-- Poems batch 160
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('58966a32-c861-4d7a-bc94-e328e96fc960','和至卿敘述三首  其三','王炎','宋','宋诗','song-poetry','','[]','襟期難與俗人論，擺落浮名莫絆身。',64,'全唐诗/poet.song.160000.json','["襟期難與俗人論，擺落浮名莫絆身。", "妙理自能中酒聖，清談不肯問錢神。", "世情一任手翻覆，此道元如肘屈伸。", "隠約形容不枯槁，祗應胸次有陽春。"]'),
('dcb96b1b-04a5-4828-94ae-cae40ef581de','和至卿述懷二首  其一','王炎','宋','宋诗','song-poetry','','[]','管城脫帽即詩成，尚挾琴書困筆耕。',64,'全唐诗/poet.song.160000.json','["管城脫帽即詩成，尚挾琴書困筆耕。", "自可追風千里去，何妨警露九臯鳴。", "心於外物無榮辱，身與虛名孰重輕。", "醉裏工爲青白眼，定應阮籍是前生。"]'),
('dac3ec64-e72b-4f50-b453-b5ac3a69322d','和至卿述懷二首  其二','王炎','宋','宋诗','song-poetry','','[]','老氣軒昂驥躡雲，丘園盤薄不求聞。',64,'全唐诗/poet.song.160000.json','["老氣軒昂驥躡雲，丘園盤薄不求聞。", "詩方平淡如摩詰，人亦清真似右軍。", "無以爲家那得爾，幸哉有子不徒云。", "鳳雛自是堯廷瑞，翰墨埸中早策勳。"]'),
('7d135221-e701-49b0-b900-efcc26a3b52d','弔禰正平','王炎','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','曹瞞忍殺楊德祖，不敢復害禰正平。',112,'全唐诗/poet.song.160000.json','["曹瞞忍殺楊德祖，不敢復害禰正平。", "區區黄祖雀鼠輩，乃以嬉笑生五兵。", "才雖可愛亦可忌，人間險過羊腸路。", "不鋤驕氣禍之媒，祖也不仁衡未智。", "黄鶴樓前江水平，鸚鵡洲邊春草青。", "憑君酹酒弔孤塚，古來賢哲非貪生。", "處士一死泰山重，文舉一死鴻毛輕。"]'),
('3e28feac-fd3a-4e99-929b-65174e1fde4b','和韓毅伯知命','王炎','宋','宋诗','song-poetry','','[]','春風盎盎杯中酒，流水潺潺膝上琴。',32,'全唐诗/poet.song.160000.json','["春風盎盎杯中酒，流水潺潺膝上琴。", "箇裏有人真得趣，槐安一夢莫關心。"]'),
('56524730-96e5-4ba0-881f-f4440569b822','和韓毅伯求鹿皮韻','王炎','宋','宋诗','song-poetry','','[]','文豹以皮豜以肉，鹿兼坐此命難贖。',32,'全唐诗/poet.song.160000.json','["文豹以皮豜以肉，鹿兼坐此命難贖。", "梅花膚革充靴材，人恰跣行畏傷足。"]'),
('ca42b813-8cb2-47cc-ae18-444fb760d878','次韻韓毅伯病瘧','王炎','宋','宋诗','song-poetry','','[]','胸襟玉氣吐長虹，扶老猶須藥物功。',64,'全唐诗/poet.song.160000.json','["胸襟玉氣吐長虹，扶老猶須藥物功。", "示病維摩非實相，戲人瘧鬼助文窮。", "筆頭排悶詩千首，甕面消愁酒一中。", "無悶無愁始安樂，此身何日不春風。"]'),
('5f3a8aaa-e444-46cc-9c43-caf60b65f0c7','次韻韓毅伯謝人惠茶','王炎','宋','宋诗','song-poetry','','[]','一線金沙泉脈來，官焙初香春未雷。',128,'全唐诗/poet.song.160000.json','["一線金沙泉脈來，官焙初香春未雷。", "雲龍小餠到天上，露芽濯濯千巖隈。", "縑緗空滿石渠閣，鴻漸經成方有託。", "喚作酪奴真薄夫，雪乳雲腴何可無。", "哦詩舌本費澆灌，畏遭水厄徒拘拘。", "豈知佩印乘軒客，醉飽犠尊羊鼎側。", "要試江山第一泉，紫鳳盤旋蒼璧圓。", "書生品味惟三九，性自嗜茶如嗜酒。"]'),
('07527b12-48fc-458f-9c53-9fdfc6ffbdbb','和韓毅伯述懷','王炎','宋','宋诗','song-poetry','','[]','洗琖從容對聖賢，笑談未了意悽然。',64,'全唐诗/poet.song.160000.json','["洗琖從容對聖賢，笑談未了意悽然。", "折腰我既慚陶令，肆志公宜學仲連。", "三沐三熏嗟已晚，一觴一詠樂餘年。", "人窮愈甚詩方好，留取珠璣向後傳。"]'),
('c6b7fd60-301c-4862-845d-bfd60f45bb7d','次韻韓毅伯趣諸先輩送茶','王炎','宋','宋诗','song-poetry','','[]','脫腕符移日旁午，魚眼浮香須一煮。',128,'全唐诗/poet.song.160000.json','["脫腕符移日旁午，魚眼浮香須一煮。", "客來捧腹共軒渠，暫時撥置官文書。", "喜客恨無鮮可擊，滿盂脫粟饑時喫。", "睡魔不待巧擠排，雪花小啜清風來。", "人生何苦浪馳逐，但得所求心自足。", "意在春風曉露邊，愛惜一旗輕萬錢。", "碾破雲龍還不飲，灧灧金荷扶玉筍。", "渠方醉魄甘沉迷，我自詩情要勾引。"]'),
('52729e51-7641-46e5-9643-8b941f46727a','再用元韻因簡縣庠諸先輩','王炎','宋','宋诗','song-poetry','','[]','書生卯飯動及午，薑糝菜絲煩自煮。',128,'全唐诗/poet.song.160000.json','["書生卯飯動及午，薑糝菜絲煩自煮。", "異時甘脆屋渠渠，出自空腸千卷書。", "竹間杵臼相敲擊，茶不療饑何苦喫。", "泉新火活費裁排，呼奴更挈銅瓶來。", "蜀客見之心逐逐，暫借紙窗休繭足。", "歸歟家在淮湖邊，草魁可買無青錢。", "不辦雲腴供粥飲，空有束詩如束筍。", "青箬小分鷹爪香，江上拏舟當遠引。"]'),
('7a76b2e0-82fa-4ffc-ab6b-b98e6670369f','和韓毅伯擬別','王炎','宋','宋诗','song-poetry','','[]','踉蹡揖客客爲誰，依舊驪珠色陸離。',64,'全唐诗/poet.song.160000.json','["踉蹡揖客客爲誰，依舊驪珠色陸離。", "不謂遠遊來此地，未能小隠待何時。", "慣看覆手仍翻手，休問開眉與皺眉。", "歸去淮山訪猿鶴，清風滿袖自披披。"]'),
('bb15e528-71d0-4edb-9406-ad77afae1584','江上爲韓毅伯訪得便舟','王炎','宋','宋诗','song-poetry','','[]','銅墨纏腰雪上頭，人生一飽亦難謀。',64,'全唐诗/poet.song.160000.json','["銅墨纏腰雪上頭，人生一飽亦難謀。", "天明忽暗釀梅雨，風暖又寒催麥秋。", "老矣不堪時節換，粲然方幸故人留。", "白雲呼去淮山住，强爲江邊問買舟。"]'),
('95ab19be-6653-4fd0-882f-fecb470184b2','再用元韻二首  其一','王炎','宋','宋诗','song-poetry','','[]','牛千蹄角橘千頭，嘆息斯人善自謀。',64,'全唐诗/poet.song.160000.json','["牛千蹄角橘千頭，嘆息斯人善自謀。", "文氣如虹徒貫日，筆耕有穀不逢秋。", "悠悠何啻十年別，得得纔爲一月留。", "女嫁男婚吾未了，夢隨鷗鷺學操舟。"]'),
('1d01df42-619c-4bc2-a888-0709b1bf3606','再用元韻二首  其二','王炎','宋','宋诗','song-poetry','','[]','倦游莫忘大刀頭，老去行藏要熟謀。',64,'全唐诗/poet.song.160000.json','["倦游莫忘大刀頭，老去行藏要熟謀。", "少病若能如萬福，上書安用學千秋。", "碧雲合處來何緩，黄鶴飛時挽不留。", "後夜月明烟水闊，更呼兒輩洗瑶舟。"]'),
('dcae01ea-a05d-4bb7-b75b-1f4c66264154','次韻韓毅伯擬別','王炎','宋','宋诗','song-poetry','','[]','江頭三老風檣急，詩叟欲行還却立。',144,'全唐诗/poet.song.160000.json','["江頭三老風檣急，詩叟欲行還却立。", "剛腸不解兒女悲，肯爲別離襟袖濕。", "翰墨場中空白眉，宦游不遂休奔馳。", "平生訥室有秘訣，持以贈君君可歸。", "靜而無譁氣方定，清而寡慾心自正。", "耳根毀譽等風波，眼界枯榮俱泡影。", "得此還家雖退藏，被褐懷玉中含光。", "踏破青鞋行萬里，猛省昨非今近是。", "但看污瀆有靈龜，莫道蹄涔無尺鯉。"]'),
('7d686dae-332d-4a3d-9410-2b0d53d235d8','次韻韓毅伯別許宣教','王炎','宋','宋诗','song-poetry','','[]','自說羈懷老更慵，淮山入夢碧叢叢。',64,'全唐诗/poet.song.160000.json','["自說羈懷老更慵，淮山入夢碧叢叢。", "一尊醽醁人將別，三疊陽關曲易終。", "此去若無鴻鴈信，相望未免馬牛風。", "耕雲釣月平生事，我亦謀歸古歙中。"]'),
('091ebad7-e195-4d19-b43a-db48df17905d','題岳陽守張仲駿浮光亭','王炎','宋','宋诗','song-poetry','','[]','三邊水墨畫遥山，下有玻璃萬頃寒。',64,'全唐诗/poet.song.160000.json','["三邊水墨畫遥山，下有玻璃萬頃寒。", "蟾兔上時留倒影，魚龍舞處動微瀾。", "舊來樓觀東西出，未覺乾坤表裏寬。", "更向上頭高著眼，湖光今作一杯看。"]'),
('46605ff7-feed-4cb1-975e-71fb550f9977','又題月臺','王炎','宋','宋诗','song-poetry','','[]','天心湖面月團圓，中著胡床坐廣寒。',64,'全唐诗/poet.song.160000.json','["天心湖面月團圓，中著胡床坐廣寒。", "玉鑑照空無盡境，冰輪碾水不生瀾。", "搗成兔藥人難老，舞徹霓裳夜未闌。", "願躡兩鳬陪鶴駕，從公飛到九霄看。"]'),
('ff52527a-83a3-4403-a3b7-7bd5beaf10bb','縣圃黄梅半墮草間','王炎','宋','宋诗','song-poetry','','[]','荷鋤芟草喚畦丁，手拾黄梅遶樹行。',64,'全唐诗/poet.song.160000.json','["荷鋤芟草喚畦丁，手拾黄梅遶樹行。", "結子青青隨雨老，開花白白本冰清。", "嘗新爭擘紅泥酒，知味誰調玉鼎羹。", "齒軟眉顰遭棄擲，誤從雪裏競欣榮。"]'),
('de1b0dea-3305-4aac-a6df-27ac3f553d02','招同官諸宣教一飯用舟字韻成拙句','王炎','宋','宋诗','song-poetry','','[]','士要飛騰及黑頭，肯來揮麈試同謀。',64,'全唐诗/poet.song.160000.json','["士要飛騰及黑頭，肯來揮麈試同謀。", "已携荷葉招歡伯，莫笑花枝欠杜秋。", "老我餘年思釣渭，諸君他日合封留。", "胸中器度須深闊，江漢方行萬斛舟。"]'),
('80053abc-0b5d-4515-bfbd-44e66ecdd681','飲闌月上不能留客再成一篇','王炎','宋','宋诗','song-poetry','','[]','綠幄陰深數樹梅，胡床相對手行杯。',64,'全唐诗/poet.song.160000.json','["綠幄陰深數樹梅，胡床相對手行杯。", "茫茫世事愁眉斂，亹亹談諧笑口開。", "欲把清風留客坐，更呼明月出雲來。", "咄嗟難辦厨中具，興盡翩然命駕回。"]'),
('600c3bf7-1b5a-4285-97e7-fc173d2d41e4','居民多疫爲散藥','王炎','宋','宋诗','song-poetry','','[]','不信翳方可活人，但隨巫語去迎神。',32,'全唐诗/poet.song.160000.json','["不信翳方可活人，但隨巫語去迎神。", "憑誰妙手如和緩，調護江臯萬戶春。"]'),
('c51c0136-21fe-43e2-b2d1-2ae8f5dd876e','聞田家插秧已畢','王炎','宋','宋诗','song-poetry','','[]','聞道田家日夜愁，黄雲白雪不全收。',32,'全唐诗/poet.song.160000.json','["聞道田家日夜愁，黄雲白雪不全收。", "稻畦插遍青如染，滿望今年倍有秋。"]'),
('a3a26643-cf5c-4460-b9ed-ed90e875a094','偶行後圃成三絕  其一','王炎','宋','宋诗','song-poetry','','[]','繁紅飛盡綠成陰，更有忘憂草色新。',32,'全唐诗/poet.song.160000.json','["繁紅飛盡綠成陰，更有忘憂草色新。", "吏隠何心來對景，化工隨意自留春。"]'),
('ad2d519e-07d4-43be-b194-ebfb8e3bc04e','偶行後圃成三絕  其二','王炎','宋','宋诗','song-poetry','','[]','琅玕十丈籜龍孫，已向梢頭散綠陰。',32,'全唐诗/poet.song.160000.json','["琅玕十丈籜龍孫，已向梢頭散綠陰。", "他日雪霜顔色好，正緣外直內虛心。"]'),
('0b95e177-b7d0-46bf-9209-6bd54963b149','偶行後圃成三絕  其三','王炎','宋','宋诗','song-poetry','','[]','園蔬入市不論錢，忍口休參玉版禪。',32,'全唐诗/poet.song.160000.json','["園蔬入市不論錢，忍口休參玉版禪。", "留得新梢過舊榦，清風六月亦蕭然。"]'),
('43d5e6dc-fd2b-4292-85c9-601dcc5e80ed','小鳬','王炎','宋','宋诗','song-poetry','','[]','母雞伏得兩鳬雛，馴食庭除不待呼。',32,'全唐诗/poet.song.160000.json','["母雞伏得兩鳬雛，馴食庭除不待呼。", "水浴泥行隨分足，不知鷗鷺有江湖。"]'),
('a7a6051c-3895-48e4-a9cc-960a935169ee','蛙聲','王炎','宋','宋诗','song-poetry','','[]','官蛙不問雨兼晴，閣閣無端聒耳鳴。',32,'全唐诗/poet.song.160000.json','["官蛙不問雨兼晴，閣閣無端聒耳鳴。", "對客自誇聞鼓吹，稚圭此語豈真情。"]'),
('3d4b4b2a-9bfc-4e3a-b352-08b595ba0e3c','勸農出郊三絕  其一','王炎','宋','宋诗','song-poetry','','[]','小煩脚力上崔嵬，意爲仙翁特地來。',32,'全唐诗/poet.song.160000.json','["小煩脚力上崔嵬，意爲仙翁特地來。", "只有白雲藏古洞，不知黄鵠幾時回。"]'),
('3124e968-47c2-49d9-a616-8454f2f69f7e','勸農出郊三絕  其二','王炎','宋','宋诗','song-poetry','','[]','桃花一笑弄春晴，布穀瀾翻亦勸耕。',32,'全唐诗/poet.song.160000.json','["桃花一笑弄春晴，布穀瀾翻亦勸耕。", "十雨五風蒙帝力，願同父老慶秋成。"]'),
('705b386d-23b0-4f0d-b033-7574f7e47e89','勸農出郊三絕  其三','王炎','宋','宋诗','song-poetry','','[]','邊頭萬馬似雲屯，準備秋風壓戰塵。',32,'全唐诗/poet.song.160000.json','["邊頭萬馬似雲屯，準備秋風壓戰塵。", "何日將軍收虎帳，道旁築屋免勤民。"]'),
('9e793265-30fa-4502-9f89-affb5c67b2ad','出郭視田訟三絕  其一','王炎','宋','宋诗','song-poetry','','[]','撥置文書小據鞍，舉頭歷歷見青山。',32,'全唐诗/poet.song.160000.json','["撥置文書小據鞍，舉頭歷歷見青山。", "老農指點黄雲好，爲駐雙鳬一解顔。"]'),
('bbfa6673-55a9-404a-99e1-4ca6256f9b8a','出郭視田訟三絕  其二','王炎','宋','宋诗','song-poetry','','[]','木末鷓鴣相應鳴，路危笑我不能行。',32,'全唐诗/poet.song.160000.json','["木末鷓鴣相應鳴，路危笑我不能行。", "湖光淺綠山容碧，頗覺心清境亦清。"]'),
('5f7998e4-0397-4ee1-a28c-f87a9bf25ba3','出郭視田訟三絕  其三','王炎','宋','宋诗','song-poetry','','[]','草生棄地沒牛深，豈是膏腴畝一金。',32,'全唐诗/poet.song.160000.json','["草生棄地沒牛深，豈是膏腴畝一金。", "野老雙蓬俱半脫，尚憑蝸角起爭心。"]'),
('3138b675-d42e-429a-b0c2-2dbe78e23320','覓李尉白犬','王炎','宋','宋诗','song-poetry','','[]','長安少年好狗馬，日日遨遊五陵下。',192,'全唐诗/poet.song.160000.json','["長安少年好狗馬，日日遨遊五陵下。", "八尺騰驤行地龍，突過無前追疾風。", "一箭穿空兩鵰墮，尚挾白羽腰騂弓。", "回鞭更踏南山路，射殺山中白額虎。", "却解重環四尺獒，快逐豐狐搜狡兔。", "獵罷歸來喚歌舞，釃酒割鮮供笑語。", "窮巷書生那有此，毛穎陶泓守環堵。", "老來無力跨蹇馿，少日青鞋只徒步。", "何况平生非獵師，何須有犬如韓盧。", "青氈舊物猶在室，吹燈未滅憂穿窬。", "似聞黄耳雲來孫，豐顱拳尾雪不如。", "從公覓取扞門戶，主人高枕偷兒避。"]'),
('6064d87c-641b-49f7-bfce-dd60a9307728','和黄先卿即事五首  其一','王炎','宋','宋诗','song-poetry','','[]','見說幽棲地，長年只杜門。',48,'全唐诗/poet.song.160000.json','["見說幽棲地，長年只杜門。", "誰知雙井後，今有此公存。", "釣月操蓮葉，批雲卧竹根。", "靜中觀物化，畫外識乾坤。"]'),
('f100342c-791d-4217-ba32-ce5f61121b21','和黄先卿即事五首  其二','王炎','宋','宋诗','song-poetry','','[]','鴻鴈南隨暖，璣衡北轉杓。',48,'全唐诗/poet.song.160000.json','["鴻鴈南隨暖，璣衡北轉杓。", "忍貧居自穩，得句興偏饒。", "藜杖難頻出，蒲輪合見招。", "惜無推轂手，寂寞老漁樵。"]'),
('599745c2-f8d3-4b5c-b06d-3d9c56a0b61f','和黄先卿即事五首  其三','王炎','宋','宋诗','song-poetry','','[]','水落洲爭出，天寒日易昏。',48,'全唐诗/poet.song.160000.json','["水落洲爭出，天寒日易昏。", "倦遊來異縣，小隠住荒村。", "鶴骨緣詩瘦，雞膚借酒溫。", "長鬚煩灑掃，吾欲叩柴門。"]'),
('a59a0a98-d867-4f24-9f78-3845fb0c6540','和黄先卿即事五首  其四','王炎','宋','宋诗','song-poetry','','[]','生理今何似，豐年亦屢空。',48,'全唐诗/poet.song.160000.json','["生理今何似，豐年亦屢空。", "有愁催髮白，無藥駐顔紅。", "歸計何時决，詩家乃爾窮。", "悲風吹宰木，吾亦夢江東。"]'),
('29127b79-22d1-455d-b7a3-53f08ec93d74','和黄先卿即事五首  其五','王炎','宋','宋诗','song-poetry','','[]','此客來湖上，驪珠照北垠。',48,'全唐诗/poet.song.160000.json','["此客來湖上，驪珠照北垠。", "山林成獨往，風月許誰分。", "寂寂無波井，悠悠不雨雲。", "莫年詩更好，何止掃千軍。"]'),
('013d7cae-1531-4717-a4cb-54b1da90dad0','題巴陵宰鄧器先北窗','王炎','宋','宋诗','song-poetry','','[]','權利炙手熱，爭道俱著鞭。',252,'全唐诗/poet.song.160000.json','["權利炙手熱，爭道俱著鞭。", "雞鳴已盥櫛，日莫未息肩。", "中宵一假寐，夢想游鈞天。", "達人袖手觀，方寸常超然。", "冰壺不受暑，凜凜含清寒。", "消摇北窗下，俯仰宇宙寬。", "千詩句有眼，一曲琴無絃。", "開尊對白墮，拂榻飽黑甜。", "功名不挂念，氣定神自閒。", "淵明亦一出，未倦飛已還。", "我常疑若人，本不欲閉關。", "漫仕今墨綬，閲世垂蒼顔。", "卷舒各有時，隠顯皆足賢。", "先正文昌丞，玉立四近班。", "風流被後昆，世以忠孝傳。", "丹扆新日月，黄圖舊山川。", "故家喬木高，義氣許國堅。", "前賢經濟心，不在軒冕間。", "才猷時所須，何得無裏言。", "高枕恐未穩，鳴珂終小騫。", "煌煌漢元侯，事業光青編。"]'),
('97c8930c-aea2-4292-bcb8-5dc20d3edd64','用元韻寄周推蕭法','王炎','宋','宋诗','song-poetry','','[]','隔岸好山羅數峰，遶簷脩竹添深叢。',272,'全唐诗/poet.song.160000.json','["隔岸好山羅數峰，遶簷脩竹添深叢。", "雲溪有此兔一窟，將雛德曜隨梁鴻。", "一饑難忍出謀食，志鬰不伸成怪松。", "彼美湓城二君子，昔未識面先聞風。", "一如龍媒氣深穩，不騖捷徑行怱怱。", "管城之外別用志，懶哦五字吳江楓。", "動中養定自有道，鬚豈不白顔甚紅。", "一如鵷雛出丹山，律呂節奏藏於胸。", "即之肅肅又盎盎，意在寥廓觀鴻濛。", "蹣跚勃窣我何者，亦許附在交游中。", "少時浪迹鹿在藪，垂老能言鸚入籠。", "心官鄙吝如膩垢，見此水鏡一洗空。", "霏霏伏雨濕楊柳，滴滴寒露凋芙蓉。", "日月逝矣足可惜，夢魂不入槐安宮。", "破觥暖浪侵浮蟻，小鼎生烟明宛虹。", "爲公更作商聲歌，朔風慘淡吹葭蓬。", "精金美玉有定價，嘆息鉅眼無坡翁。"]'),
('191bb843-a8f3-4ffa-a1c9-e8952bedbcf8','用元韻答汪廣文','王炎','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','十丈花開玉井峰，藤蘿亦附灌木叢。',272,'全唐诗/poet.song.160000.json','["十丈花開玉井峰，藤蘿亦附灌木叢。", "可憐浮食不根著，南北羈旅如燕鴻。", "倦飛欲返返未得，夢魂時遶三徑松。", "故人相見發孤笑，執熱一濯清穆風。", "小傾家釀歌驪駒，有懷未吐行怱怱。", "山寒不開北枝梅，地遠誰樹南荆楓。", "欲談此意無爲領，撥灰消盡麒麟紅。", "未免隨俗且折腰，薄以今古澆其胸。", "六經之澤溉萬世，譬如畦稻宵露濛。", "陳言有味可涵泳，環堵差勝朝市中。", "退之一賦吾未許，二禽雅意豈願籠。", "乘軒執珪何有哉，日光熠熠塵飛空。", "由來賢達多下位，高原不解生芙蓉。", "龍魚仙伯妙此理，垂雲小憇來儒宮。", "洞庭湘山入詩句，借與光彩勝赮虹。", "百聞不及一見面，獨對霜月搔飛蓬。", "清光何事亦多闕，試爲問之修月翁。"]'),
('c21616b7-67ab-495e-9978-3ddd552c9a9e','用元韻答鄧宰兼簡華容孟宰','王炎','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我行六六黄山峰，山中瑶草多芳叢。',272,'全唐诗/poet.song.160000.json','["我行六六黄山峰，山中瑶草多芳叢。", "浮丘笑我無此骨，倏然飛去如孤鴻。", "隨流逐轉水上萍，失地更屈澗底松。", "絕憐拄笏頻看山，未免舉扇一障風。", "長沙三歲坐兀兀，洞庭千里來怱怱。", "擁衾時作故鄉夢，寒鴉無數啼丹楓。", "繭絲未辦竟何補，强飯空耗桃花紅。", "巴丘健令工製錦，况有奎壁星羅胸。", "明月璀璨堆我前，老眼照開春霧濛。", "西寄華容雙鯉魚，欲挽淵明來社中。", "頗聞餘事戲毛穎，亦舞玄蛟蒙碧籠。", "心雖入俗不受塵，出岫白雲行太空。", "蒹葭四澤風露冷，有此美德如芙蓉。", "尋幽或訪墨山寺，弔古可賦章華宮。", "何時再揖兩鳬仙，共喚麴生行偃虹。", "無邊湖水似少海，一點君山疑小蓬。", "城南老樹無恙否，煩渠試爲呼回翁。"]'),
('af7c2526-880b-44d9-aa22-d2044b51be15','用元韻答徐尉','王炎','宋','宋诗','song-poetry','','[]','于越亭亭羊角峰，下有團團桂樹叢。',272,'全唐诗/poet.song.160000.json','["于越亭亭羊角峰，下有團團桂樹叢。", "何人爲賦反招隠，虞羅亦罥碣石鴻。", "學詩妙處如學仙，功成換骨參喬松。", "肯來洗我箏笛耳，檿絲古曲彈南風。", "喜君到此極亹亹，惜君去此尤怱怱。", "百年莫作千歲調，試往一看楓橋楓。", "湘山幸有數斗酒，江蟹肥大霜橘紅。", "梅仙陶令連兩璧，得酒可澆丘壑胸。", "漁蓑風月笛三弄，虬龍起舞凌空濛。", "馮夷不得閟此境，湖山收入奚囊中。", "沙寒往事有銅鏃，波穩清時無水龍。", "人生所須得樂爾，嗟我愁絕逃虛空。", "已悲朽質悴蒲柳，豈解巧笑開芙蓉。", "青燈照牖似書舍，素琴挂壁疑僧宮。", "懸知堂上一杯水，難飲不邊千丈虹。", "大用自當擁金蓮，小用亦合登少蓬。", "騰身雲路五千里，定笑白鳬成老翁。"]'),
('06f1572d-2c31-4805-a2dc-cfbf8f6975f2','和許尉小洞庭韻  其一','王炎','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','古縣周遭臨水涯，中有勝地藏幽奇。',240,'全唐诗/poet.song.160000.json','["古縣周遭臨水涯，中有勝地藏幽奇。", "向來墨綬不領略，付與漁樵輕棄遺。", "我乘蒼螭上其頂，憑高小築誅茅茨。", "未能隠去學魯山，且可尋幽如退之。", "炊烟百堵共一市，民氣稍稍春臺熙。", "至尊豈爲繭絲計，老令恨無桃李蹊。", "解衣一浣三年緇，微風碾碎青琉璃。", "魚龍悲嘯吹白浪，煙靄吐吞蒙翠微。", "湖中一點小君山，誰琢瑶琨圓中規。", "朱絃一曲舞馮夷，凌風駕我雙鳬飛。", "遠喚古仙笙鶴來，月寒共醉玉東西。", "天高可逐霞佩去，兒女牽衣吾未宜。", "一官傴僂百僚底，蒼髯欲雪將何爲。", "徘徊在此爲五斗，時亦諷誦淵明詞。", "茲亭信美非我有，夢遶故園還欲歸。"]'),
('0fed8b30-837b-40ac-a35e-431d9d11e17d','和許尉小洞庭韻  其二','王炎','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','少時耕釣爲生涯，早知臭腐空神奇。',240,'全唐诗/poet.song.160000.json','["少時耕釣爲生涯，早知臭腐空神奇。", "一丘一壑有佳處，人棄我取如拾遺。", "晚將數雛就斗食，非願厚祿多如茨。", "山林習氣今尚在，前身疑是王獻之。", "君王垂拱似虞夏，朝野多暇時雍熙。", "公庭日晡鳬鶩散，屐齒小穿山徑蹊。", "隠仙一見即首肯，百鍾索酒傾琉璃。", "湖山亦爲開畫笥，烟霏空翠俱熹微。", "幼輿風度極灑灑，計然策畫徒規規。", "蒼松奮鬣倚風嘯，候鴈張羽粘天飛。", "君山洞庭日在眼，不復引領巴丘西。", "急呼泓穎共著語，境勝頗與詩相宜。", "詩成却憶梅子真，烏用一官黄綬爲。", "江頭誰是吹笛叟，爲公度此瓊瑶詞。", "喚起羣龍出平湖，屬渠扶柂從東歸。"]'),
('014aa4da-68c8-48d4-8401-fbbb68abeaf9','和吳秀才二絕  其一','王炎','宋','宋诗','song-poetry','','[]','句法洪徐可逼真，摩挲老眼見斯人。',32,'全唐诗/poet.song.160000.json','["句法洪徐可逼真，摩挲老眼見斯人。", "憐渠袖有釣鰲手，要試虹竿欠李紳。"]'),
('3ca82a42-4843-45c2-8229-2c09a416f667','和吳秀才二絕  其二','王炎','宋','宋诗','song-poetry','','[]','世人相馬苦嫌瘦，誰識龍媒氣逸羣。',32,'全唐诗/poet.song.160000.json','["世人相馬苦嫌瘦，誰識龍媒氣逸羣。", "歸傍青燈對賢聖，漢庭射策待方聞。"]'),
('36c96019-f664-4cb7-8661-5b61f8831ef0','送相士管明甫','王炎','宋','宋诗','song-poetry','','[]','名士多相識，吾鄉亦舊游。',48,'全唐诗/poet.song.160000.json','["名士多相識，吾鄉亦舊游。", "知君倦行役，見我小淹留。", "道路雙青眼，風霜一敝裘。", "人中逢燕頷，早爲說封侯。"]'),
('850aa7bd-c773-413f-b707-39a01c633fdb','和程丞遊清水巖黄龍山韻','王炎','宋','宋诗','song-poetry','','[]','嵐光野色共扶輿，見說壺天氣象殊。',64,'全唐诗/poet.song.160000.json','["嵐光野色共扶輿，見說壺天氣象殊。", "疊巘吞雲圭角露，寒泉觸石篆文紆。", "荒凉佛屋存遺像，窈窕仙巖有別區。", "何日青鞋親扣歷，細評佳致染松腴。"]'),
('7fb028e4-4967-40ad-b27d-1d21559cce9d','和程丞遊清水巖黄龍山韻 清水巖','王炎','宋','宋诗','song-poetry','','[]','臞仙窟宅獻幽奇，付與藍田煅鍊詩。',64,'全唐诗/poet.song.160000.json','["臞仙窟宅獻幽奇，付與藍田煅鍊詩。", "佳處盡從公指出，勝遊應笑我來遲。", "品題泉石非無意，依約烟霞未有期。", "獨幸胸中丘壑在，不須目擊始心知。"]'),
('0a58f292-dd31-40bf-bcd2-fea0855fb4ac','和程丞遊清水巖黄龍山韻 黄龍山 其一','王炎','宋','宋诗','song-poetry','','[]','老南蛻骨幾何年，揖客支筇謾曲拳。',64,'全唐诗/poet.song.160000.json','["老南蛻骨幾何年，揖客支筇謾曲拳。", "本自心清無染著，豈因境靜息攀緣。", "我行不值揮犀語，公到惟堪掃榻眠。", "尚有詩魔降未得，不禁物色巧勾牽。"]'),
('d87fa232-96b2-408c-a782-ef2050cc25d3','和程丞遊清水巖黄龍山韻 黄龍山 其二','王炎','宋','宋诗','song-poetry','','[]','未聞衲子著深功，但見龍孫送好風。',64,'全唐诗/poet.song.160000.json','["未聞衲子著深功，但見龍孫送好風。", "尊宿尚留雙塔在，衆丘皆讓一山雄。", "禪關暫到何須住，法窟雖深豈用窮。", "若問如如心自在，夢魂不入大槐宮。"]'),
('b58a9da1-b034-46a2-89ed-fd7ac50d3a96','和陸簿九日二首  其一','王炎','宋','宋诗','song-poetry','','[]','西風拂面飲微酣，小摘茱萸手自簪。',64,'全唐诗/poet.song.160000.json','["西風拂面飲微酣，小摘茱萸手自簪。", "極羨酒兼詩共好，正緣人與景相參。", "杜門不復貪游賞，落帽無由際劇談。", "嘆息登高兄弟遠，目隨鴻鴈過天南。"]'),
('01658aae-ded7-4b5f-849e-5713d22ab854','和陸簿九日二首  其二','王炎','宋','宋诗','song-poetry','','[]','風露蕭蕭葉半黄，老來情薄似秋陽。',64,'全唐诗/poet.song.160000.json','["風露蕭蕭葉半黄，老來情薄似秋陽。", "一樽冷落思佳客，九日凄凉在異鄉。", "採菊何心追靖節，哦詩無語答仇香。", "危臺戲馬今安在，休惹清愁攪石腸。"]'),
('b34618ba-0d49-4cb6-9ade-8a31bd952e1d','喜晴行呈陳宰','王炎','宋','宋诗','song-poetry','','[]','秋盡黄雲漲南畝，修我囷倉築場圃。',128,'全唐诗/poet.song.160000.json','["秋盡黄雲漲南畝，修我囷倉築場圃。", "不堪雨脚如懸麻，坐見禾頭欲生耳。", "令君意與神明通，爐熏未斷來天風。", "吹開六出花數點，轉盼杲杲扶桑紅。", "日下鳥烏聲亦樂，村北村南爭刈穫。", "白酒香浮老瓦盆，樵歌緩扣烏犍角。", "有客携家來受廛，豐登未見如今年。", "老農扶杖笑相語，只恐雙鳬朝日邊。"]'),
('98b296b8-b9e3-4142-8437-510eb07a71fa','陸簿生日','王炎','宋','宋诗','song-poetry','','[]','冬令始嚴肅，淑氣回晏溫。',84,'全唐诗/poet.song.160000.json','["冬令始嚴肅，淑氣回晏溫。", "簾幃映瑞色，見此天上麟。", "蒙羽有再來，機雲定前身。", "清標入黄綬，胸次不受塵。", "洗玉酌流霞，眉間喜津津。", "飛龍御天位，喬木思世臣。", "功名固自有，難得惟青春。"]'),
('604fcd2e-441c-46a0-9bed-3ac6925ac2b0','溪上晚步二首  其一','王炎','宋','宋诗','song-poetry','','[]','山靜色不改，溪深流自遲。',48,'全唐诗/poet.song.160000.json','["山靜色不改，溪深流自遲。", "緩行聊寓目，小立却支頤。", "樵斧寒尤響，漁舟晚更移。", "老夫無伴侶，穉子獨追隨。"]'),
('a9ec1caf-5c9e-401a-b00f-7e021452b0f3','溪上晚步二首  其二','王炎','宋','宋诗','song-poetry','','[]','風定留黄葉，波清湧白沙。',48,'全唐诗/poet.song.160000.json','["風定留黄葉，波清湧白沙。", "前山惟道院，斷岸半漁家。", "老去忘時事，閒中度歲華。", "經旬如再出，便可探梅花。"]'),
('b289613d-5b40-4fa8-a1b2-f8e1abc01d7c','宋可挹挽詩','王炎','宋','宋诗','song-poetry','','[]','萬卷藏書富，千金市義多。',48,'全唐诗/poet.song.160000.json','["萬卷藏書富，千金市義多。", "斯人今止此，造物意如何。", "風月空投轄，烟波冷曬蓑。", "林間誰挂劍，清淚墮悲歌。"]'),
('2870d3f3-9109-403f-8185-c57e218a462f','用十梅韻答馮簿  其一','王炎','宋','宋诗','song-poetry','','[]','今代馮野王，聲滿東海濱。',24,'全唐诗/poet.song.160000.json','["今代馮野王，聲滿東海濱。", "可敬亦可愛，溫然氣如春。"]'),
('5c979d80-d6ae-4a84-98b2-1e7b63069049','用十梅韻答馮簿  其二','王炎','宋','宋诗','song-poetry','','[]','綠綺絃朱絲，爲我調白雪。',24,'全唐诗/poet.song.160000.json','["綠綺絃朱絲，爲我調白雪。", "此亦公緒餘，所長兼五絕。"]'),
('6e65f7f4-8a28-4489-85f3-b2f044436a61','用十梅韻答馮簿  其三','王炎','宋','宋诗','song-poetry','','[]','嘗試評公詩，崖岸極孤絕。',24,'全唐诗/poet.song.160000.json','["嘗試評公詩，崖岸極孤絕。", "同僚筆可焚，後學巾宜折。"]'),
('fe5b0bdb-5077-4ed9-aaf7-0d36202f6f1f','用十梅韻答馮簿  其四','王炎','宋','宋诗','song-poetry','','[]','清真去邊幅，明白傾底裏。',24,'全唐诗/poet.song.160000.json','["清真去邊幅，明白傾底裏。", "枳棘見鸞凰，十倍跫然喜。"]'),
('d643a0b3-b300-4368-afd2-df40a92275aa','用十梅韻答馮簿  其五','王炎','宋','宋诗','song-poetry','','[]','講道師友少，稽古編簡殘。',24,'全唐诗/poet.song.160000.json','["講道師友少，稽古編簡殘。", "何以起斯文，念之心爲寒。"]'),
('0542981c-41b9-4ab9-ae3b-8702213eae95','用十梅韻答馮簿  其六','王炎','宋','宋诗','song-poetry','','[]','銀鈎入翠珉，文字本膚淺。',24,'全唐诗/poet.song.160000.json','["銀鈎入翠珉，文字本膚淺。", "以書不以辭，恃此或行遠。"]'),
('9cc60a14-5816-4402-a50c-d58e98dad5d5','用十梅韻答馮簿  其七','王炎','宋','宋诗','song-poetry','','[]','人品如許高，不卑一官小。',24,'全唐诗/poet.song.160000.json','["人品如許高，不卑一官小。", "居之以廉勤，王事豈難了。"]'),
('40148b80-8584-45de-9998-1c001a88abb6','用十梅韻答馮簿  其八','王炎','宋','宋诗','song-poetry','','[]','霏霏玉麈談，鄙吝堪澡雪。',24,'全唐诗/poet.song.160000.json','["霏霏玉麈談，鄙吝堪澡雪。", "每見輒有聞，敢憚頻磬折。"]'),
('e147941f-69e5-463a-8322-4a5afd0ab0e3','用十梅韻答馮簿  其九','王炎','宋','宋诗','song-poetry','','[]','道本無垢凈，境自有喧寂。',24,'全唐诗/poet.song.160000.json','["道本無垢凈，境自有喧寂。", "願聞禪說中，何以得真實。"]'),
('ca8abbb7-dd8f-44ae-8823-a1e3b6482f6c','用十梅韻答馮簿  其一○','王炎','宋','宋诗','song-poetry','','[]','黄門執戟翁，晚乃薄詞賦。',24,'全唐诗/poet.song.160000.json','["黄門執戟翁，晚乃薄詞賦。", "我宜草玄文，未必知妙處。"]'),
('d7734a31-debb-4b37-a67e-9172bdab7e02','和何應辰過山谷墓韻','王炎','宋','宋诗','song-poetry','','[]','何年馬鬣埋玉樹，上有喬木清風寒。',96,'全唐诗/poet.song.160000.json','["何年馬鬣埋玉樹，上有喬木清風寒。", "琳瑯金薤落四海，萬象頓挫隨毫端。", "追攀前輩豈無意，偶來弛擔鳴珂里。", "生恨與公相後先，臨風三嘆不能已。", "論詩誰解鍼膏肓，人間今日無黄香。", "經過一酹尊中碧，明月灣頭山閴寂。"]'),
('126a0b6e-8e4d-4b1c-99e5-f936d623e391','新晴出溪上因訪王伯明詹望之','王炎','宋','宋诗','song-poetry','','[]','萍轉滯巖邑，簡出而深居。',180,'全唐诗/poet.song.160000.json','["萍轉滯巖邑，簡出而深居。", "兒輩不自量，妄意游璧池。", "日占烏鵲喜，不寄黄犬書。", "積雨蒸溽暑，客思鬰不舒。", "新晴一散策，消摇滌煩紆。", "意行入幽徑，籬落相蔽虧。", "竹萌茁鳳尾，瓜蔓纏龍鬚。", "物化日夜流，嗟我方棲遲。", "莫受憂患煎，素髮無再緇。", "扣門謁二友，清坐俱久如。", "莊語間善謔，相視一解頤。", "靜窺勢利場，疾足爭驅馳。", "自念甘斂退，非黠仍非癡。", "茗乳泛輕雪，爐熏駐游絲。", "且勿談世事，揮犀聊說詩。"]'),
('c75ac8b3-d686-4bb1-a173-bb0f5793459f','用元韻答詹望之','王炎','宋','宋诗','song-poetry','','[]','隨牒久浮食，弛擔來卜居。',180,'全唐诗/poet.song.160000.json','["隨牒久浮食，弛擔來卜居。", "鷦鷯一枝足，不羨飛天池。", "盥濯朱墨手，拂蠹理故書。", "識字非子雲，下帷慚仲舒。", "第喜宦情薄，未解歸思紆。", "對境有喧寂，即理無成虧。", "動以靜爲根，輪柅常相須。", "捷徑易傾覆，夷途固逶遲。", "巷南有廛隠，白玉不受緇。", "熟視眉睫間，容色常穆如。", "伯仲吹箎塤，北堂奉期頤。", "時亦踏街塵，意馬不外馳。", "見我床頭易，信我殊不癡。", "喜言雖溢美，老眼眩色絲。", "相期到妙處，不止奚囊詩。"]'),
('265ab4f1-761d-4272-b4e0-4f2ed5cdd16a','溪上尋梅不遇','王炎','宋','宋诗','song-poetry','','[]','玄冬用事禿千林，蓓蕾凌寒瘦不禁。',64,'全唐诗/poet.song.160000.json','["玄冬用事禿千林，蓓蕾凌寒瘦不禁。", "已喚蒼頭篘臘脚，未逢玉頰吐春心。", "客居避俗遨遊少，老境看花感慨深。", "屬付綠衣歌舞地，吹香一笑慰幽尋。"]'),
('9ee3c154-65ca-4e2f-ad20-51f3f2e213db','寓居分寧去故鄉千里不歸者二年思念松楸成長句','王炎','宋','宋诗','song-poetry','','[]','曖曖風日暖，林薄皆蕃鮮。',264,'全唐诗/poet.song.160000.json','["曖曖風日暖，林薄皆蕃鮮。", "好鳥仍嘯歌，晚花亦嫣然。", "問之此何時，春莫將禁烟。", "家家饌觴豆，拜掃墟墓間。", "飛鳴烏攫肉，叢木挂紙錢。", "而我獨不樂，慨然坐長嘆。", "開編不能讀，當饋不能餐。", "豺獺尚有祭，誰忍忘其先。", "念爲貧所驅，隨牒二十年。", "少壯不可留，覽鏡將華顛。", "空慚北山移，未表南陽阡。", "闔門有百指，負郭無一廛。", "坐此客異鄉，歸思空纏綿。", "憶昔初筮仕，吾母猶朱顔。", "三釜不及養，遽悲蓼莪篇。", "侵尋歲月久，百感難具言。", "傷心思宰木，清淚如流泉。", "狐死必首丘，古人亦重遷。", "况我雖宦游，十世家星川。", "親朋日在眼，可以相周旋。", "土風有不同，客意終未安。", "花落草凄凄，青山啼杜鵑。"]'),
('47f30fde-c56d-40e8-998a-4d20db275aaa','即事六絕  其一','王炎','宋','宋诗','song-poetry','','[]','焚香清坐對韋編，妙處懸知不可傳。',32,'全唐诗/poet.song.160000.json','["焚香清坐對韋編，妙處懸知不可傳。", "三畫分明寄玄旨，誰將脩綆汲深泉。"]'),
('0d92c982-b2bf-4653-9fb7-a5b60480e316','即事六絕  其二','王炎','宋','宋诗','song-poetry','','[]','半生飄泊將雛意，百感凄凉舐犢情。',32,'全唐诗/poet.song.160000.json','["半生飄泊將雛意，百感凄凉舐犢情。", "露電終非真實相，彭殤何者是長生。"]'),
('669787f0-f4d7-4627-81a8-3b2389cc7744','即事六絕  其三','王炎','宋','宋诗','song-poetry','','[]','布衣蔬食且隨緣，睡起時參柏子烟。',32,'全唐诗/poet.song.160000.json','["布衣蔬食且隨緣，睡起時參柏子烟。", "欲倚繩床拈白拂，何人真解意中玄。"]'),
('80fd244b-be49-4b56-9cf0-c05f9231f653','即事六絕  其四','王炎','宋','宋诗','song-poetry','','[]','了無俗駕到蝸廬，隠几閒翻貝葉書。',32,'全唐诗/poet.song.160000.json','["了無俗駕到蝸廬，隠几閒翻貝葉書。", "屬付蒼頭休洒掃，綠苔隨意上階除。"]'),
('b9b25731-bc70-4f7e-af26-9fa8b17cea78','即事六絕  其五','王炎','宋','宋诗','song-poetry','','[]','拂拭青奴供晝眠，半晴半雨釀愁天。',32,'全唐诗/poet.song.160000.json','["拂拭青奴供晝眠，半晴半雨釀愁天。", "夢回不到南柯境，風過綠陰號晚蟬。"]'),
('d4501545-52f3-4c04-ad89-67520852e080','即事六絕  其六','王炎','宋','宋诗','song-poetry','','[]','孫竹新添綠玉枝，穉禽學習遶簷飛。',32,'全唐诗/poet.song.160000.json','["孫竹新添綠玉枝，穉禽學習遶簷飛。", "動中會取歸根意，雨過白雲橫翠微。"]'),
('5595501c-5e3d-4f58-b80e-0ab948d4bb13','遊南山寺題澹軒','王炎','宋','宋诗','song-poetry','','[]','雲根露奇怪，上有青蓮宮。',84,'全唐诗/poet.song.160000.json','["雲根露奇怪，上有青蓮宮。", "軒窗極凈麗，疑入懸壺中。", "凭檻俯寒流，披襟納清風。", "跏趺坐少定，滯念冰雪融。", "人生蟻旋磨，世故鳥印空。", "道眼一回光，味與嚼蠟同。", "此意誰爲領，白雲橫遠峰。"]'),
('3d1f81cb-58bb-4a15-9ee7-1c0703c79a53','用元韻答麟老  其一','王炎','宋','宋诗','song-poetry','','[]','登臨倚木末，下瞰魚龍宮。',84,'全唐诗/poet.song.160000.json','["登臨倚木末，下瞰魚龍宮。", "我方解墨綬，著身丘壑中。", "翩然一清游，飛舄可御風。", "前瞻鳳山尾，老衲如懶融。", "見處詣實際，非色仍非空。", "笑我蠟屐行，亦與玩物同。", "燕坐不出門，心游妙高峰。"]'),
('ffbfca8e-3bb4-4e1e-9f29-afbc6622d5e8','用元韻答麟老  其二','王炎','宋','宋诗','song-poetry','','[]','七閩名家子，祝髮隠梵宮。',84,'全唐诗/poet.song.160000.json','["七閩名家子，祝髮隠梵宮。", "碧海掉尾鯨，不墮世網中。", "熏爐起香霧，棕拂生清風。", "寂寂枯木巖，中有春意融。", "杖屨厭山水，習氣一洗空。", "違俗非崖異，入俗非雷同。", "乃知行市廛，宛如坐孤峰。"]'),
('500ce4c6-e3ae-4bc2-8084-db6165fec7e9','述懷三首  其一','王炎','宋','宋诗','song-poetry','','[]','久客二年半，故鄉千里餘。',48,'全唐诗/poet.song.160000.json','["久客二年半，故鄉千里餘。", "兒曹穿草屨，老子挂柴車。", "世事杯中物，生涯篋裏書。", "一廛何日辦，衰晚憶吾廬。"]'),
('fdaabf95-2c60-4d2d-9079-54641172a84d','述懷三首  其二','王炎','宋','宋诗','song-poetry','','[]','宦薄因謀拙，心安任數奇。',48,'全唐诗/poet.song.160000.json','["宦薄因謀拙，心安任數奇。", "功名半幅紙，權利一鈎絲。", "已作絡頭驥，殊慚曳尾龜。", "暫時深袖手，風月話襟期。"]'),
('ea58b0ca-8901-4eb7-a511-76c1f8d9ea90','述懷三首  其三','王炎','宋','宋诗','song-poetry','','[]','百指久轉食，一身今倦遊。',48,'全唐诗/poet.song.160000.json','["百指久轉食，一身今倦遊。", "事無非墮甑，心本是虛舟。", "儻不嘗艱阻，渠能寡悔尤。", "管城雖解語，懶賦畔牢愁。"]'),
('81f4cd08-4a59-4097-8161-3ec1b3f361f2','次韻答熊朝英  其一','王炎','宋','宋诗','song-poetry','','[]','杜門燕坐閲黄庭，道在靈臺莫與京。',64,'全唐诗/poet.song.160000.json','["杜門燕坐閲黄庭，道在靈臺莫與京。", "少日忍貧吾志得，莫年爲吏此身輕。", "始知軒冕有塵累，不似山林無俗情。", "絳帳先生應撫掌，南箕北斗只虛名。"]'),
('1ad144bb-ed52-48e3-8886-57755c796ad7','次韻答熊朝英  其二','王炎','宋','宋诗','song-poetry','','[]','秋風相挽出門庭，東望雲邊白玉京。',64,'全唐诗/poet.song.160000.json','["秋風相挽出門庭，東望雲邊白玉京。", "婚嫁自嗟何日了，利名誰信本來輕。", "揮毫爲我光行色，傾蓋知公不世情。", "文字清新有如此，底緣淡墨未題名。"]'),
('4305f620-3bcf-468d-92c7-e8875c8908b0','勝賞亭','王炎','宋','宋诗','song-poetry','','[]','路入三家市，牆圍十畝園。',24,'全唐诗/poet.song.160000.json','["路入三家市，牆圍十畝園。", "雲山如畫出，人住小桃源。"]'),
('a7d31402-71b0-4dd8-a223-f8dfdc42c075','贈郭相士','王炎','宋','宋诗','song-poetry','','[]','兩眼明如月，江湖度十春。',24,'全唐诗/poet.song.160000.json','["兩眼明如月，江湖度十春。", "問誰當鼎貴，笑說未逢人。"]'),
('c2e45bf6-8ffa-490c-9eb4-33c0c78dd5ae','和祝聖予送行韻','王炎','宋','宋诗','song-poetry','','[]','少年困裋褐，妄意取圭組。',192,'全唐诗/poet.song.160000.json','["少年困裋褐，妄意取圭組。", "徒爲出岫雲，不作潤物雨。", "三年葭葦叢，鳬舄墮江滸。", "憂患鬢先凋，驚呼髀空撫。", "過期釋重負，揆日趨在所。", "投簪誠未能，束擔亦良苦。", "漢庭士冀北，不可一二數。", "顧我最平凡，辱君誤推許。", "皇明照百工，天高日亭午。", "海嶽雖兼受，涓埃諒無補。", "汲汲爲身謀，人生幾寒暑。", "軒冕既儻來，金璧又難貯。", "試看轅下駒，何如黄鵠舉。", "莫待婚嫁了，徑爲松菊主。", "大隠在城市，高人戀衡宇。", "相期數過從，脩綆同汲古。"]'),
('77fd2039-84fd-443e-8732-6ede39384ee4','次韻孫居易送行','王炎','宋','宋诗','song-poetry','','[]','著鞭欲爲功名起，椎鈍不堪加礪砥。',96,'全唐诗/poet.song.160000.json','["著鞭欲爲功名起，椎鈍不堪加礪砥。", "感君雅意重金玉，餞我新詩粲桃李。", "我於吏事非清通，向來妄意圖民功。", "本無仁心致三異，豈有遺愛留一同。", "鬢毛斑白眼昏黑，身外榮枯從造物。", "恥携奏牘到公車，千慮懸知無一得。"]'),
('599dcda1-439a-4dfb-a941-ae3dac66acfd','陳宰生日','王炎','宋','宋诗','song-poetry','','[]','花枝點綴深淺紅，溪山二月春融融。',176,'全唐诗/poet.song.160000.json','["花枝點綴深淺紅，溪山二月春融融。", "琴堂清曉氣葱鬰，躡鳬此日來仙翁。", "姓名已久書絳闕，骨相元自居紗籠。", "君王厚下爲保障，郎宿垂光臨一同。", "兩行吏立薄冰上，四境人行明鏡中。", "三年妙手巧製錦，藉甚治聲聞九重。", "桃李陰邊共歌舞，勸君飲盡玻璃鍾。", "著鞭由此登要路，推轂豈必由諸公。", "未教曳履侍文石，亦合峩豸乘花驄。", "中堂朱紱映綵服，瑶池無日無春風。", "摩挲銅狄閲人世，何止他年方兩瞳。"]'),
('31a0cc4f-fe27-425d-8afb-481cc6f2db45','和王宗禮送行韻','王炎','宋','宋诗','song-poetry','','[]','羊腸官路困躋攀，爲米低頭亦厚顔。',64,'全唐诗/poet.song.160000.json','["羊腸官路困躋攀，爲米低頭亦厚顔。", "尚欲束裝趨帝闕，未能盡室返家山。", "青雲新貴爭先進，空谷幽人去不還。", "我獨行藏兩無取，狐疑丘壑市朝間。"]'),
('097885f9-f9e7-4726-b75d-1dd4be8ce61b','和陸簿韻','王炎','宋','宋诗','song-poetry','','[]','士龍才氣極超然，奕奕家聲見象賢。',64,'全唐诗/poet.song.160000.json','["士龍才氣極超然，奕奕家聲見象賢。", "慣學詩翁歌白雪，懶從舉子選青錢。", "三年小試淹巖邑，千里來歸近日邊。", "流落倦遊吾老矣，看公騰踏上凌烟。"]'),
('2629d875-8a9b-48f4-a4b2-b4ba7563a339','和黄子山韻二首  其一','王炎','宋','宋诗','song-poetry','','[]','三年凋縣積憂虞，幸脫拘囚氣始蘇。',64,'全唐诗/poet.song.160000.json','["三年凋縣積憂虞，幸脫拘囚氣始蘇。", "已愧淵明辭五斗，尚睎聱叟住三吾。", "潜心道義須加進，垂世功名莫浪圖。", "前日趨榮今斂退，看人高步上天衢。"]'),
('a5376f2e-916b-4a17-8d54-3e3d85ee4f60','和黄子山韻二首  其二','王炎','宋','宋诗','song-poetry','','[]','閉門聖域妙鈎深，霧豹文成照士林。',64,'全唐诗/poet.song.160000.json','["閉門聖域妙鈎深，霧豹文成照士林。", "顧我一生求勝己，與公數面可論心。", "曬蓑溪上今陳迹，嘯白堂中久絕吟。", "雙井獨爲風月主，欣聞綠綺奏遺音。"]'),
('147bdcb2-5913-455d-92fd-3461879645ea','用元韻答徐幼文  其一','王炎','宋','宋诗','song-poetry','','[]','身行宦路固多虞，夢到清都厭積蘇。',64,'全唐诗/poet.song.160000.json','["身行宦路固多虞，夢到清都厭積蘇。", "欲返初心觀易老，懶開辯口學巖吾。", "有懷擬作西征賦，無策堪陳北伐圖。", "才具如公宜穎脫，不應空谷老唐衢。"]'),
('00a9e4c1-b74d-4ba5-b8e5-af7be9b448a4','用元韻答徐幼文  其二','王炎','宋','宋诗','song-poetry','','[]','學道工夫要汲深，塵生麈尾坐書林。',64,'全唐诗/poet.song.160000.json','["學道工夫要汲深，塵生麈尾坐書林。", "何妨緩步時過我，試共玄談一洗心。", "翠岫遶溪雙鷺下，綠陰覆屋亂蟬吟。", "是中別有無聲句，莫笑遲遲不嗣音。"]'),
('2491433e-ad49-42f6-910d-5ee2c5598d2d','謝黄子山賀得孫','王炎','宋','宋诗','song-poetry','','[]','侵尋及頹齡，憂患催霜鬚。',168,'全唐诗/poet.song.160000.json','["侵尋及頹齡，憂患催霜鬚。", "是身如老木，枯枿生孫枝。", "自念非逸少，屈指無七之。", "日願穀豐下，今見鳳有兒。", "安得壽喬松，及渠成立時。", "追念十年事，欣戚更乘除。", "瓜葛自延蔓，葭莩相因依。", "頼此一雛生，兩家釋猜疑。", "飛鵲遶屋鳴，織翠來華裾。", "相視一粲然，英詞出瓊琚。", "醴甘不醉人，湯餠浮銀絲。", "只欠解語花，遏雲歌此詞。", "知公本惜飲，嘗試覆一巵。", "因之酹梅塘，騎鵠何時歸。"]'),
('19769fe9-d59e-4f77-a6b1-d0d562ba4309','和麟老韻五絕  其一','王炎','宋','宋诗','song-poetry','','[]','詩清雖爲竹庵編，禪妙元從佛眼傳。',32,'全唐诗/poet.song.160000.json','["詩清雖爲竹庵編，禪妙元從佛眼傳。", "用處縱橫能殺活，匣藏不肯試龍泉。"]'),
('f061a2cf-0957-454f-a354-9660cbb040c1','和麟老韻五絕  其二','王炎','宋','宋诗','song-poetry','','[]','清如野鶴有仙骨，閒似片雲無俗情。',32,'全唐诗/poet.song.160000.json','["清如野鶴有仙骨，閒似片雲無俗情。", "試問老人那得病，定應金粟是前生。"]'),
('4f09950d-20e5-4962-abd3-51ec25966feb','和麟老韻五絕  其三','王炎','宋','宋诗','song-poetry','','[]','客塵悟了息攀援，萬事虛浮一聚烟。',32,'全唐诗/poet.song.160000.json','["客塵悟了息攀援，萬事虛浮一聚烟。", "挂佛壁間趺坐穩，遶簷翠柏解談玄。"]'),
('0e7ab684-a159-4850-8438-9b6d80aea023','和麟老韻五絕  其四','王炎','宋','宋诗','song-poetry','','[]','白雪蒙頭卧佛廬，筆端亦解世間書。',32,'全唐诗/poet.song.160000.json','["白雪蒙頭卧佛廬，筆端亦解世間書。", "無情安用詩陶寫，有病何須藥破除。"]'),
('eebbbb45-0316-4791-b900-49b4ce01c22e','和麟老韻五絕  其五','王炎','宋','宋诗','song-poetry','','[]','居似鷦鷯巢一枝，意如倦翼怯高飛。',32,'全唐诗/poet.song.160000.json','["居似鷦鷯巢一枝，意如倦翼怯高飛。", "尚憐身是他鄉客，夢遶松楸賦式微。"]'),
('b5575d16-2bac-4648-b4af-3750da9c5736','王倅成老挽詩二首  其一','王炎','宋','宋诗','song-poetry','','[]','末俗輕浮甚，斯人有古風。',48,'全唐诗/poet.song.160000.json','["末俗輕浮甚，斯人有古風。", "持身無表襮，爲吏極清通。", "學似武平一，仕如張長公。", "龜趺宜篆刻，潜德照無窮。"]'),
('3a3b4240-d249-4308-90a2-12cdf5428eeb','王倅成老挽詩二首  其二','王炎','宋','宋诗','song-poetry','','[]','珠玉山淵潤，仁人久里居。',48,'全唐诗/poet.song.160000.json','["珠玉山淵潤，仁人久里居。", "低徊嘗結綬，强健即垂車。", "長厚皆堪法，循良亦可書。", "惜哉懷遠業，小試只題輿。"]'),
('69f18d3f-0443-42a6-8dbb-3ada4d43eca5','和陳丞彥能韻','王炎','宋','宋诗','song-poetry','','[]','東山林壑自盤旋，健步翩翩似壯年。',64,'全唐诗/poet.song.160000.json','["東山林壑自盤旋，健步翩翩似壯年。", "退不求名如避世，清而寡欲可成仙。", "懸知身外渾無事，不羨壺中別有天。", "珍重與君頻問信，二松遺愛滿脩川。"]'),
('6a211e46-64a6-4ede-9e85-d9202e7bc0e3','方漕躬明挽詩三首  其一','王炎','宋','宋诗','song-poetry','','[]','行蹕留吳會，神州久陸沉。',48,'全唐诗/poet.song.160000.json','["行蹕留吳會，神州久陸沉。", "君王經遠志，臣子復讐心。", "慷慨披丹悃，褒嘉拜玉音。", "騎箕何太速，有識共沾襟。"]'),
('e48900b5-e8cd-47e2-b3fc-0ca271503b5b','方漕躬明挽詩三首  其二','王炎','宋','宋诗','song-poetry','','[]','吳蜀蜂腰勢，荆襄控上游。',48,'全唐诗/poet.song.160000.json','["吳蜀蜂腰勢，荆襄控上游。", "羣公無遠慮，天子有深憂。", "此事須成算，何人更熟籌。", "黄圖三輔近，北望不禁愁。"]'),
('99c37eb2-d8cf-4a3d-a02c-7779c1395ff6','方漕躬明挽詩三首  其三','王炎','宋','宋诗','song-poetry','','[]','一節方將指，千兵競力耕。',48,'全唐诗/poet.song.160000.json','["一節方將指，千兵競力耕。", "江淮如富實，河洛可經營。", "許國忠誠切，謀身寵辱輕。", "空遺今日恨，公論付臺評。"]'),
('126f3c5f-173f-42a7-aae8-8d9e5bab87c4','謝江潭諸公','王炎','宋','宋诗','song-poetry','','[]','相逢一解頤，款曲吐肺腑。',180,'全唐诗/poet.song.160000.json','["相逢一解頤，款曲吐肺腑。", "主人愛敬客，童孺亦呼舞。", "擊鮮倒家釀，花枝照樽俎。", "善謔時絕倒，惜飲亦徑醉。", "十年一會面，此身幾寒暑。", "不見即相念，臨分無可語。", "翰墨要陶練，飲食謹調護。", "行役今何時，天寒歲將莫。", "故鄉松梓荒，他鄉寓兒女。", "豈不念之深，祇覺丹心苦。", "天機馬出塞，人事狙賦芧。", "都門桂玉地，久客憚羈旅。", "東風染春紅，歸程涉溪滸。", "經過不厭數，弛擔更少住。", "禮簡情乃真，惟宜具雞黍。"]'),
('c1735ab8-a195-42ef-8ad9-52b532ddaf98','題童壽卿博雅堂','王炎','宋','宋诗','song-poetry','','[]','會道莫如約，要識胸中真。',204,'全唐诗/poet.song.160000.json','["會道莫如約，要識胸中真。", "講學亦貴博，不廢紙上陳。", "王充與李邕，世豈無若人。", "中秘未許見，市肆何所聞。", "童君家多書，乃爲我輩慮。", "安用蓬萊山，萬卷皆聚此。", "又復附益之，秦碑及周鼓。", "剡溪來楮生，歙穴會石友。", "持此分雅俗，清渭映濁涇。", "不賄屋自潤，無爵身亦榮。", "好事時相過，不憚倒屣迎。", "揮麈言有味，寂如無市聲。", "孰如漢中郎，孰似楚左史。", "孰能誦亡書，孰解作奇字。", "是中猶淵海，隨取即隨有。", "或問賈幾何，還可商度否。", "掀髯笑謝客，吾非鬻書叟。"]'),
('36c5dd5a-492d-44f5-aa4a-b5dcb0fbf58c','題秋山圖','王炎','宋','宋诗','song-poetry','','[]','我本山中人，築室依澗岡。',72,'全唐诗/poet.song.160000.json','["我本山中人，築室依澗岡。", "世故驅我來，緇塵滿衣裳。", "見此山中景，我思更深長。", "老樹何離離，瘦石何蒼蒼。", "借問此何時，天寒鴈南翔。", "西風有摇落，蘭桂含幽芳。"]'),
('f378d03e-9fd4-41be-91a5-630d19e7ee7b','題遠山平林圖','王炎','宋','宋诗','song-poetry','','[]','山色微茫疑有無，木葉半脫殊蕭疎。',80,'全唐诗/poet.song.160000.json','["山色微茫疑有無，木葉半脫殊蕭疎。", "雲根更著數椽屋，此屋當有幽人居。", "墨妙逼真乃如此，畢竟非真惟近似。", "何如屐齒飽經行，是處溪山皆畫笥。", "還君圖畫吾且歸，家在江南依翠微。"]'),
('b59fdfe7-83b2-4bb6-a1e0-db8d119a1645','題潮山海門圖','王炎','宋','宋诗','song-poetry','','[]','潮來濺雪欲浮天，潮去奔雷又寂然。',32,'全唐诗/poet.song.160000.json','["潮來濺雪欲浮天，潮去奔雷又寂然。", "海上兩山元不動，更添此意畫中傳。"]'),
('53ac1eef-1106-4f31-90f8-540b7884d212','送許士龍秘校','王炎','宋','宋诗','song-poetry','','[]','南山霧豹隠，北海風鵬飛。',180,'全唐诗/poet.song.160000.json','["南山霧豹隠，北海風鵬飛。", "顯晦不在人，屈伸各有時。", "之子後來秀，躡屩飄長裾。", "俗眼變青白，論士相目皮。", "父執謝艮齋，片言借吹噓。", "聞君方遠游，行李將何如。", "食梅不免酸，彈鋏不免悲。", "易盡床頭金，難浣衣上緇。", "白髮倚門望，豈宜去庭闈。", "林烏能反哺，人亦稱其慈。", "勿徒走踆踆，而更歸遲遲。", "志定學始進，身臞道方肥。", "譬如汲深井，脩綆斯得之。", "持此爲親榮，玉潤山含輝。", "苦言當贈策，申以南陔詩。"]'),
('51a9f7c9-4070-4250-9411-aac7184cf390','題韋同年聚遠閤','王炎','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','塵蒙萬家市，中有壺公天。',216,'全唐诗/poet.song.160000.json','["塵蒙萬家市，中有壺公天。", "翬飛倚空翠，吞納無中邊。", "江遠益淵回，山遠益清妍。", "雲霞之斂散，竹樹之芊綿。", "羽鱗之翔泳，舟車之往還。", "物色四面來，輸入簷楹間。", "境遠心亦遠，意將隘人寰。", "我嘗觀洞庭，水與天相連。", "流光浮玉鏡，萬象皆包涵。", "又嘗登天柱，衆丘如髻鬟。", "孤鴻滅沒處，寓目行中原。", "蓬轉墮江城，此身縛微官。", "今代韋表微，懶著進取鞭。", "尚記千佛名，亦許時扣關。", "自疑脫凡骨，揖此樓居仙。", "江山開畫笥，使我思悠然。", "是中有真趣，可得不可傳。", "客至勿揮麈，但與浮觥船。"]'),
('affa69cc-6a12-41b4-b44f-6f184fb8bfc5','送房陵倅韋同年二首  其一','王炎','宋','宋诗','song-poetry','','[]','白玉難求市，青雲緩作程。',48,'全唐诗/poet.song.160000.json','["白玉難求市，青雲緩作程。", "小煩乘別駕，遠去護邊城。", "斥堠烽烟冷，譙門鼓角清。", "採桑遺戒在，約束要堅明。"]'),
('1e08c968-afc4-4359-96f4-f250d9d6229a','送房陵倅韋同年二首  其二','王炎','宋','宋诗','song-poetry','','[]','德齒皆兄我，曾聯淡墨名。',48,'全唐诗/poet.song.160000.json','["德齒皆兄我，曾聯淡墨名。", "揮犀方晤語，浮鷁又催行。", "今日惟櫜矢，何人更請纓。", "戰塵猶未息，北望若爲情。"]'),
('ffd8768e-d146-4dc0-9a6a-d7c84c23833f','贈輪上座','王炎','宋','宋诗','song-poetry','','[]','念舊今歸楚，尋師久入吳。',48,'全唐诗/poet.song.160000.json','["念舊今歸楚，尋師久入吳。", "有緣依梵釋，何事走江湖。", "休問傳心印，當先覓髻珠。", "直須言語斷，方不墮凡夫。"]'),
('8e9f13af-8905-4fd0-8e47-ae8bbedcb022','寄蔣主簿','王炎','宋','宋诗','song-poetry','','[]','過我怱怱去，難淹長者車。',48,'全唐诗/poet.song.160000.json','["過我怱怱去，難淹長者車。", "歲華今又晚，官况近何如。", "不是無才具，渠憂少薦書。", "因君問公幹，久不寄雙魚。"]'),
('4af1f0ab-63f5-4a62-967d-e3f752e74421','用元韻答劉判官','王炎','宋','宋诗','song-poetry','','[]','解后章江上，知從五馬車。',48,'全唐诗/poet.song.160000.json','["解后章江上，知從五馬車。", "君才猶未用，吾老更焉如。", "間闊思眉宇，殷勤得手書。", "喜聞衣綵樂，入饌有江魚。"]'),
('61be2c0c-4e64-47f9-abe1-a3adc3f96025','用元韻答戴簿','王炎','宋','宋诗','song-poetry','','[]','綠衣隨宦牒，綵服侍安車。',48,'全唐诗/poet.song.160000.json','["綠衣隨宦牒，綵服侍安車。", "問齒君方壯，論才我不如。", "清新哦五字，博洽貫羣書。", "尚肯求龍尾，容交華子魚。"]'),
('9942066d-b9b4-4195-942b-70eb9e54a983','用元韻答蔣簿','王炎','宋','宋诗','song-poetry','','[]','北去方休駕，西行又出車。',48,'全唐诗/poet.song.160000.json','["北去方休駕，西行又出車。", "身勞雖僕僕，心靜自如如。", "儻得重揮麈，全勝數寄書。", "詩來驚老眼，筆力掣鯨魚。"]'),
('7f8addec-3fe3-41c0-9658-b0fb521d74a6','蕭參政挽詩二首  其一','王炎','宋','宋诗','song-poetry','','[]','正學無阿世，危言不顧身。',48,'全唐诗/poet.song.160000.json','["正學無阿世，危言不顧身。", "旁觀多側目，獨立屢攖鱗。", "八葉鈞衡後，三朝柱石臣。", "晚方陪國論，終不盡經綸。"]'),
('a779e491-1086-4abc-8ad1-78586a78e69f','蕭參政挽詩二首  其二','王炎','宋','宋诗','song-poetry','','[]','東府纔登用，南園即退藏。',48,'全唐诗/poet.song.160000.json','["東府纔登用，南園即退藏。", "不欺身自正，無欲氣能剛。", "士共悲梁壞，朝應惜鑑亡。", "臧孫宜有後，世出甲科郎。"]'),
('7622892d-5ad9-4e33-962e-1ba87df99257','送施宣教','王炎','宋','宋诗','song-poetry','','[]','翩翩貴公子，和氣如春溫。',96,'全唐诗/poet.song.160000.json','["翩翩貴公子，和氣如春溫。", "傾蓋一晤語，肯吐胸中真。", "江頭雨新霽，浮鷁波鱗鱗。", "騎鳳吹玉簫，歸歟覲慈親。", "我老無所營，君方富青春。", "後會未有期，人來時嗣音。", "毛穎二十輩，深衷致殷勤。", "助君賦子虛，高飛到青雲。"]'),
('cf8a72da-b0e0-4ea0-90c1-6821d418e56d','和吳夢授韻','王炎','宋','宋诗','song-poetry','','[]','卷舒有道在隨時，隠約何須感慨爲。',64,'全唐诗/poet.song.160000.json','["卷舒有道在隨時，隠約何須感慨爲。", "末路老夫甘退縮，華途吾友尚驅馳。", "準繩行義當趨正，淘練文章自出奇。", "舉世豈無人具眼，未應終不貴和隨。"]'),
('439ba0c4-b7db-46ea-a6d8-b8c05f86fdc9','題徐秘校達軒','王炎','宋','宋诗','song-poetry','','[]','洙泗之學心爲宗，以心會理俱圓融。',128,'全唐诗/poet.song.160000.json','["洙泗之學心爲宗，以心會理俱圓融。", "皎如日月猶有蝕，豈可講習無深功。", "仲祥家自有師友，箇中嘗指入門否。", "磨礲浸灌更覃思，道不外求皆我有。", "靈臺四闢如八窗，面面高明悉通透。", "此道周流無定名，此心微妙無定形。", "知隨物誘心失位，思而不達空營營。", "爲君再下一轉語，敬以攝心思乃精。"]'),
('390f5e52-19db-4f85-92da-a06517b805a6','壬子春羅端長贈別','王炎','宋','宋诗','song-poetry','','[]','憶昔始相識，公歸自中都。',288,'全唐诗/poet.song.160000.json','["憶昔始相識，公歸自中都。", "時方擢上第，綠髮青衫紆。", "論交兄弟間，意氣和笙竽。", "瓌文得要攬，快語相爲娛。", "一別間何闊，流年走暘烏。", "高情自浩浩，風骨乃仙癯。", "顧我蒲柳姿，雪霜凝鬢鬚。", "回思鴻鴈行，淚落衣袖濡。", "相逢慰棲遲，此道評精粗。", "稔聞充素藴，諸老推通儒。", "又知治劇縣，民瘼刪繁須。", "清才爲世用，洗目亨天衢。", "監州尚小試，稱屈非超踰。", "敂門喜重來，新詩遺明珠。", "傾倒念有陳，草具陪觴壺。", "自愧學不講，議論無根株。", "殷勤謝雅貺，披索中腸枯。", "壯志已愴悢，俗情厭崎嶇。", "正須心所欣，日與鎸迂愚。", "奈何復作遠，攬袂還躊躇。", "公猶寄異邦，同是江南區。", "但慮懷與安，久客非良圖。", "終當念墳墓，速歸三徑蕪。", "昨言亦云然，歲寒勿盟渝。"]'),
('cb94a3e5-4457-46df-944e-6b097445ed4e','和王文州咏雪韻  其一','王炎','宋','宋诗','song-poetry','','[]','老盡青青江上山，漁蓑如畫過前灣。',64,'全唐诗/poet.song.160000.json','["老盡青青江上山，漁蓑如畫過前灣。", "玲瓏冰玉光相射，點綴寒花意自閒。", "甕面春風消寂寞，爐中宿火護尪孱。", "請君試跨白霓去，鶴氅凌空我願攀。"]'),
('ac65de68-8ba0-4063-94d3-4db77a2647d0','和王文州咏雪韻  其二','王炎','宋','宋诗','song-poetry','','[]','一穗香雲擁博山，毛錐吸盡墨池灣。',64,'全唐诗/poet.song.160000.json','["一穗香雲擁博山，毛錐吸盡墨池灣。", "詩如驪頷生明月，人似龍媒出帝閑。", "洒落高情忘固陋，崢嶸健論起衰孱。", "蒼髯半雪吾休矣，却怕飛騰不可攀。"]'),
('aee66a03-d812-48bf-bc64-d3bd25e4c7b4','冬雪行','王炎','宋','宋诗','song-poetry','','[]','擁衾展轉夜不眠，細數更籌知苦寒。',208,'全唐诗/poet.song.160000.json','["擁衾展轉夜不眠，細數更籌知苦寒。", "角聲未動紙窗白，兒曹報我雪滿簷。", "玉妃剪水出天巧，飛花萬點爭清妍。", "朱門貴人對之笑，初見一白來豐年。", "金甖玉爵雜蔬笋，飲罷敲冰煮新茗。", "繡幃中有紅麒麟，輕暖勝春尚嫌冷。", "窮巷小家真可憐，典衣糴米無炊烟。", "江頭津吏日來報，往往上流無米船。", "縣官要糴十萬斛，天上符移星火速。", "去年秋旱糶陳腐，今年秋熟米如玉。", "且願扶桑枝上紅，日轂東來却滕六。", "今年冬雪民已臞，明年春雪民更饑。", "九關有路虎豹守，欲語不敢空長吁。"]'),
('0eb77e90-7c63-4464-85e5-88be69b57e20','次韻答簡簿','王炎','宋','宋诗','song-poetry','','[]','少日牛衣嘗熟眠，老來駝褐不護寒。',208,'全唐诗/poet.song.160000.json','["少日牛衣嘗熟眠，老來駝褐不護寒。", "欲呵龜手拈禿筆，怯看冰柱懸疎簷。", "東風不解著梅柳，翻作六出欺春妍。", "春回臘盡亦何好，但爲浮生添一年。", "負郭有人如石笋，雪裏哦詩自烹茗。", "胸中盎盎有天和，戶外蕭蕭尚冰冷。", "日炊脫粟不自憐，却念野廬無爨烟。", "此憂未知可解否，準擬爲君浮酒船。", "酒酣傾瀉珠百斛，定覺揮毫轉神速。", "聞道諸公雙眼青，豈終遺此豐年玉。", "倦游別駕老更貧，自謀慚似龜藏六。", "詩來謂我清而臞，我方忍慾將忍饑。", "短蓑歸釣寒江雪，紛紛世事休嗟吁。"]'),
('504aa2a4-76fc-45d8-8c8f-1cd0cc50e915','題楊秀才園三亭 綉春','王炎','宋','宋诗','song-poetry','','[]','幽圃春風蕩漾時，阿誰綉出百花枝。',32,'全唐诗/poet.song.160000.json','["幽圃春風蕩漾時，阿誰綉出百花枝。", "春工不與人爭巧，玉笋羞拈五色絲。"]'),
('4fa3a73d-b328-4671-829a-0494ba883e15','題楊秀才園三亭 見山','王炎','宋','宋诗','song-poetry','','[]','窗間酒榼與詩編，窗外山光翠入簾。',32,'全唐诗/poet.song.160000.json','["窗間酒榼與詩編，窗外山光翠入簾。", "山好要人能領略，直須胸次似陶潜。"]'),
('b0c1a7a2-08ce-4e3d-ba8b-aaec30f6b5a7','題楊秀才園三亭 移春','王炎','宋','宋诗','song-poetry','','[]','花邊春色可移來，遶屋株株手自栽。',32,'全唐诗/poet.song.160000.json','["花邊春色可移來，遶屋株株手自栽。", "若要四時春不去，更添秋菊與寒梅。"]'),
('d4035385-974a-4a2d-af26-0dfddaf25957','和王文州梅花韻','王炎','宋','宋诗','song-poetry','','[]','何處東風發春早，先傍梅花試天巧。',192,'全唐诗/poet.song.160000.json','["何處東風發春早，先傍梅花試天巧。", "新陽一點破雪霜，春意將回可前料。", "天公乞我人日晴，新年屈指將浹旬。", "老懷不似少時好，對花默默仍循循。", "坐看流年如許急，嘆息浮生駒過隙。", "與花相見忍相負，洗杯一醉樽中碧。", "起來索笑巡疎簷，愛渠清絕無中邊。", "君侯肯爲花吐句，麝媒洒落生雲烟。", "花開花謝莫深問，物有榮枯付天命。", "聞道隴頭天正寒，驛使不來無遠信。", "可憐桃李品格低，誰似玉肌蒙縞衣。", "爲花著語只如此，更請健筆無停飛。"]'),
('2003e22a-8301-4789-ad3d-c6ef8fc123ab','題清江常宰道院','王炎','宋','宋诗','song-poetry','','[]','古人牧民如赤子，今人臨民用笞箠。',112,'全唐诗/poet.song.160000.json','["古人牧民如赤子，今人臨民用笞箠。", "孰知官府本無事，獨恨庸人擾之耳。", "臨邛有客腰銅章，三年爲吏先慈祥。", "老農共說長官好，桑柘陰中民小康。", "公庭閒暇鴈鶩散，燕坐胡床清晝長。", "撥煩何自文書省，治道由來貴清靜。", "不須柱下五千言，洙泗六經無猛政。"]'),
('f5c8009b-695f-4f05-b96c-66d24d32f811','和周南吉二絕  其一','王炎','宋','宋诗','song-poetry','','[]','才諝諸公爭汲引，文高後學共儀刑。',32,'全唐诗/poet.song.160000.json','["才諝諸公爭汲引，文高後學共儀刑。", "相逢未覺功名晚，鏡裏依然兩鬢青。"]'),
('38d8b63e-2b5b-4250-ae43-98367d129ff0','和周南吉二絕  其二','王炎','宋','宋诗','song-poetry','','[]','舊遊追記岳陽城，莫惜經過憩旆旌。',32,'全唐诗/poet.song.160000.json','["舊遊追記岳陽城，莫惜經過憩旆旌。", "容易別離難會合，爲君重酌聖人清。"]'),
('95a04a9f-278d-440d-988a-165622ea20ac','題徐參議畫軸三首 墨梅','王炎','宋','宋诗','song-poetry','','["\u897f\u6e56"]','酷似西湖處士詩，雖無半樹有橫枝。',32,'全唐诗/poet.song.160000.json','["酷似西湖處士詩，雖無半樹有橫枝。", "天寒地冷清癯甚，故著緇衣護玉肌。"]'),
('aca358de-7383-4b78-b30d-65dbbeca7200','題徐參議畫軸三首 赤壁圖','王炎','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','烏林赤壁事已陳，黄州赤壁天下聞。',96,'全唐诗/poet.song.160000.json','["烏林赤壁事已陳，黄州赤壁天下聞。", "東坡居士妙言語，賦到此翁無古人。", "江流浩浩日東注，老石輪囷飽烟雨。", "雪堂尚在人不來，黄鵠而今定何許。", "此賦可歌仍可絃，此畫可與俱流傳。", "沙埋折戟洞庭岸，訪古壯懷空黯然。"]'),
('326fb145-327d-4847-bc0d-c9f95c0e08ea','題徐參議畫軸三首 歲寒三友','王炎','宋','宋诗','song-poetry','','[]','玉色高人之潔，虬髭烈士之剛。',28,'全唐诗/poet.song.160000.json','["玉色高人之潔，虬髭烈士之剛。", "可與此君鼎立，偃然傲睨冰霜。"]'),
('e2bf94b4-4f15-4e60-b201-46de786cf649','題徐參議所藏唐人浴兒圖','王炎','宋','宋诗','song-poetry','','[]','右相嘗慚呼畫師，技癢仍復拈毛錐。',224,'全唐诗/poet.song.160000.json','["右相嘗慚呼畫師，技癢仍復拈毛錐。", "逼真誰作此贋本，亦有妙意生妍姿。", "中庭燕坐必主婦，綠雲高髻香羅衣。", "嫣然嬪妾左右侍，前浴能言丹鳳雛。", "娉婷及筓女公子，素腕擁項相携扶。", "兩兩爲朋四髫齔，乳盧隨逐相諧嬉。", "掌中看珠二少艾，捧顋却立鴉鬟奴。", "屏間擁膝袖玉笋，疑是夢闌顰翠眉。", "側身背面按箏者，冰肌綽約不自持。", "床前跪起各姝麗，爲兒理髮抆涕洟。", "有犬斕斑受摩撫，與人習熟無猜疑。", "梳粧淡薄服製古，如見永徽貞觀時。", "若非侯家及主第，人物無此美且都。", "荆釵布襦小家婦，生子不如山下麑。"]'),
('199ae13f-1286-4140-9b83-be3e4138905a','和潘判官送酒韻','王炎','宋','宋诗','song-poetry','','[]','由來高士憐麴糵，爲有和氣如三春。',96,'全唐诗/poet.song.160000.json','["由來高士憐麴糵，爲有和氣如三春。", "一朝驟見四從事，使我頌德思伯倫。", "官醅亦自有妙理，風味不如家釀醇。", "掀髯抆拭玉荷葉，消憂破悶還天真。", "此公胸次有醖藉，酒馨且旨如其人。", "平生誤學獨醒客，醉鄉有地堪藏身。"]'),
('84a5bb4c-3d5b-4664-89ef-fe0d003baae9','和王宮教送酒韻','王炎','宋','宋诗','song-poetry','','[]','不肯獨醒如屈平，要於酒國立詩城。',32,'全唐诗/poet.song.160000.json','["不肯獨醒如屈平，要於酒國立詩城。", "蒼頭滿挹鸕鷀杓，中有春風習習生。"]'),
('0206445f-15a3-428b-9462-2557c97f32f4','和王宮教韻','王炎','宋','宋诗','song-poetry','','[]','六籍橫陳日醉心，忍貧不肯問錢神。',32,'全唐诗/poet.song.160000.json','["六籍橫陳日醉心，忍貧不肯問錢神。", "旁人但見門冰冷，豈識胸中暖似春。"]'),
('46fa0d2e-cc9c-464e-9005-bf2c91e81545','送簡簿  其一','王炎','宋','宋诗','song-poetry','','[]','催科撫字意何如，吏莫難於縣大夫。',32,'全唐诗/poet.song.160000.json','["催科撫字意何如，吏莫難於縣大夫。", "游刃有餘須小試，若逢盤錯少躊躇。"]'),
('3db8c9b4-be3e-49e3-bece-410074be8d56','送簡簿  其二','王炎','宋','宋诗','song-poetry','','[]','路入天南庾嶺根，梅花落盡已春深。',32,'全唐诗/poet.song.160000.json','["路入天南庾嶺根，梅花落盡已春深。", "中年氣體須調護，莫受蠻烟瘴雨侵。"]'),
('bcd628a5-a43f-444f-92de-180355f783e9','送簡簿  其三','王炎','宋','宋诗','song-poetry','','[]','向來倦客寓中都，解后嘗瞻五馬車。',32,'全唐诗/poet.song.160000.json','["向來倦客寓中都，解后嘗瞻五馬車。", "未敢匆匆致雙鯉，煩君先爲問興居。"]'),
('b7d50a67-b625-4615-8dab-2cae7378a3f8','遊閤皂','王炎','宋','宋诗','song-poetry','','[]','竈臼依然在翠微，重重臺殿鎖雙扉。',64,'全唐诗/poet.song.160000.json','["竈臼依然在翠微，重重臺殿鎖雙扉。", "可憐千載碧杉老，不見兩翁黄鶴歸。", "小倚脩篁飛玉子，更升虛室奏金徽。", "渺茫且置神仙事，輸却清閒屬羽衣。"]'),
('08982e3d-168c-4c6f-a316-20274ce2feb7','陳張甘三道士和篇繼至用元韻併謝之','王炎','宋','宋诗','song-poetry','','[]','疑有幽人是少微，支筇特地叩岩扉。',64,'全唐诗/poet.song.160000.json','["疑有幽人是少微，支筇特地叩岩扉。", "清風度竹邀人住，暗水浮花送客歸。", "鶴在青田違畢弋，琴號白雪遶絃徽。", "明朝回首雲山隔，撲撲紅塵又滿衣。"]'),
('8609b094-84d5-4805-a969-5644a7b505ad','題蒼玉軒','王炎','宋','宋诗','song-poetry','','[]','羽客家何在，翠微有仙躅。',136,'全唐诗/poet.song.160000.json','["羽客家何在，翠微有仙躅。", "誰謂絳闕遠，功行要純熟。", "小築開壺天，燕坐媚幽獨。", "室中閲丹經，簷外養脩竹。", "竹清不受塵，人清不受俗。", "意甚珍惜之，命名以蒼玉。", "此玉可種不可餐，檀欒秀色青於藍。", "琅玕碧樹未足貴，直節虛心同歲寒。", "風前歷歷戛球磬，雪裏珊珊鳴珮環。", "他年化作蒼龍去，紫霄直上追鸞驂。"]'),
('db725d32-9cd1-43b3-a03d-8dcd10e2b9e6','題李道士揖雲軒','王炎','宋','宋诗','song-poetry','','[]','獨酌樽中綠醑，自橫膝上瑶琴。',28,'全唐诗/poet.song.160000.json','["獨酌樽中綠醑，自橫膝上瑶琴。", "笑揖白雲爲伴，愛渠舒卷無心。"]'),
('67358b42-c6b6-43cd-9095-ce74fb725d17','題熊道士遐觀閣','王炎','宋','宋诗','song-poetry','','[]','伐翳旋開清曠，樓居便覺超然。',28,'全唐诗/poet.song.160000.json','["伐翳旋開清曠，樓居便覺超然。", "注目青山有盡，游心碧落無邊。"]'),
('8cf9b966-dbbe-449c-911e-497bd09b6005','題劉知宮愚圃三首  其一','王炎','宋','宋诗','song-poetry','','[]','蝸角橫戈不解，羊腸覆轍相尋。',28,'全唐诗/poet.song.160000.json','["蝸角橫戈不解，羊腸覆轍相尋。", "爭似藏明納智，淡然高卧山林。"]'),
('09292bb0-6e62-4247-931e-4078b841deb6','題劉知宮愚圃三首  其二','王炎','宋','宋诗','song-poetry','','[]','不羨蘇秦六印，不貪范蠡千金。',28,'全唐诗/poet.song.160000.json','["不羨蘇秦六印，不貪范蠡千金。", "身住神仙窟宅，當無一點機心。"]'),
('d8ccf320-8ff0-4259-945a-e97141069aa2','題劉知宮愚圃三首  其三','王炎','宋','宋诗','song-poetry','','[]','養性欲虛而一，攝生欲靜而閒。',28,'全唐诗/poet.song.160000.json','["養性欲虛而一，攝生欲靜而閒。", "須信道如牆壁，絕嫌心有機關。"]'),
('ee454acc-fb8b-4789-a994-6433b1db4fd9','題乘槎','王炎','宋','宋诗','song-poetry','','[]','石溜涓涓遶屋流，山居疑是小瀛洲。',32,'全唐诗/poet.song.160000.json','["石溜涓涓遶屋流，山居疑是小瀛洲。", "星槎不渡銀潢去，織女機邊客倦游。"]'),
('617387e1-c7c9-4e65-a023-555ed9b9ff48','和壁間謝艮齋留題','王炎','宋','宋诗','song-poetry','','[]','寥寥鶴駕人安在，灑灑驪珠迹已陳。',32,'全唐诗/poet.song.160000.json','["寥寥鶴駕人安在，灑灑驪珠迹已陳。", "見說仙家能拔宅，何妨乘此上天津。"]'),
('267ac8b5-5704-4b8a-a4bf-7b757e00bba5','酬白雲張道士惠詩','王炎','宋','宋诗','song-poetry','','[]','不但學仙仍學詩，年來古錦富珠璣。',32,'全唐诗/poet.song.160000.json','["不但學仙仍學詩，年來古錦富珠璣。", "却疑汗漫騎鯨李，誤向天台訪子微。"]'),
('9192cc0d-b137-4f30-8b2c-a9147378770a','題楊解元壽萱堂二首  其一','王炎','宋','宋诗','song-poetry','','[]','濟濟斑衣子，怡怡白髮親。',24,'全唐诗/poet.song.160000.json','["濟濟斑衣子，怡怡白髮親。", "紫萱偏得地，玉樹解留春。"]'),
('5d3e5b31-c80e-476a-af64-825155c0b196','題楊解元壽萱堂二首  其二','王炎','宋','宋诗','song-poetry','','[]','冬夏勤溫凊，晨昏潔膳羞。',24,'全唐诗/poet.song.160000.json','["冬夏勤溫凊，晨昏潔膳羞。", "堂中人不老，庭下草忘憂。"]'),
('90bbad55-03b0-4b14-955b-58da4f65594e','除日出江上迓趙憲','王炎','宋','宋诗','song-poetry','','[]','江風獵獵吹客衣，水生鱗甲舟行遲。',224,'全唐诗/poet.song.160000.json','["江風獵獵吹客衣，水生鱗甲舟行遲。", "今年江上春信早，剩有梅花開北枝。", "問之今日是何日，三百六旬當歲除。", "翩翩鷗鷺定笑我，欲得一飽甘奔馳。", "二星移次照鶉尾，繡衣持斧生光輝。", "摐金伐鼓聲震動，鷁首破浪開黄旗。", "三宮萬壽帝出震，周家磐石先諸姬。", "外分符節用肺腑，丞相與國同安危。", "書生白頭不解事，佐一小壘將何爲。", "少年側目望雲漢，欲與鸞鳳俱翻飛。", "草黄驥病絡頭老，自笑意行身不隨。", "人生虎鼠在用舍，未用以此相瑕疵。", "兒曹婚嫁雖未了，此心久與青山期。", "天無老眼不可問，哦詩莫作商聲悲。"]'),
('e0efff26-1451-42f6-a832-9c81ae172ddc','張德夫園亭八咏 梅隠','王炎','宋','宋诗','song-poetry','','[]','聞君家有十畝園，竹踰萬箇花亦繁。',128,'全唐诗/poet.song.160000.json','["聞君家有十畝園，竹踰萬箇花亦繁。", "門楣大字扁梅隠，要與梅兄同歲寒。", "問君小隠亦何好，脚踏風波身易老。", "花雖不語解笑人，似隠又非何草草。", "破雪暗香先得春，青州從事如春溫。", "女奴洗玉歌一曲，對花舉酒成三人。", "飲酣拔劍氣方怒，汴洛神臯難北顧。", "手提萬騎屬櫜鞬，未可爲梅空隠去。"]'),
('5c498d4e-9ce2-4721-8507-0e2e3620512a','張德夫園亭八咏 山堂','王炎','宋','宋诗','song-poetry','','[]','四顧盡臯壤，此山何可無。',48,'全唐诗/poet.song.160000.json','["四顧盡臯壤，此山何可無。", "翠嵐侵戶牖，瘦石出江湖。", "靈運謾著屐，宗文空畫圖。", "釣鰲真有力，移得一蓬壺。"]'),
('77f52c1f-3dbb-4c74-bd3a-0c86c7f766ff','張德夫園亭八咏 玉椽','王炎','宋','宋诗','song-poetry','','[]','萬箇龍孫長，梢梢上半天。',48,'全唐诗/poet.song.160000.json','["萬箇龍孫長，梢梢上半天。", "清風長滿屋，蒼玉總如椽。", "秀色到今日，深根凡幾年。", "宜封管城子，濡首落雲烟。"]'),
('d9c19df0-2581-4357-98d8-0350e12dd61c','張德夫園亭八咏 漁村','王炎','宋','宋诗','song-poetry','','[]','聞道江村好，人家罨畫中。',48,'全唐诗/poet.song.160000.json','["聞道江村好，人家罨畫中。", "持杯聽欵乃，支策望空濛。", "日落收疎網，潮生繫短蓬。", "君嘗詢訪否，恐有陸龜蒙。"]'),
('654e7132-13ec-4143-bc7f-e7d866a55cae','張德夫園亭八咏 兼遠','王炎','宋','宋诗','song-poetry','','[]','若人胸次中，自有萬人敵。',132,'全唐诗/poet.song.160000.json','["若人胸次中，自有萬人敵。", "胡不籌前箸，時清偃金革。", "婆娑林壑間，亦自適其適。", "憑高著胡床，千里獻物色。", "稻疇碁局方，指數皆歷歷。", "海山疑有無，雲樹半明沒。", "高懷安在哉，流目送鴻翼。", "冷笑蟻垤卑，偪仄復偪仄。", "淋漓呼酒徒，揮洒延墨客。", "不記訾家洲，休賦雲夢澤。", "何當從公游，汗漫揮八極。"]'),
('da07bbb1-cb5d-4eb8-9d2e-f57adc55fc71','張德夫園亭八咏 橘渚','王炎','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','小插藩籬護洲渚，當年手自種嘉樹。',96,'全唐诗/poet.song.160000.json','["小插藩籬護洲渚，當年手自種嘉樹。", "春風吹出玉瓏璁，水面霏微噴香霧。", "蕭疎木落候鴈翔，漙漙白露朝爲霜。", "木奴欲獻主人壽，一夜纍纍千顆黄。", "紫蟹螯肥鱸膾好，釀就洞庭春色老。", "蒼頭急走喚客來，翠勺金壺同醉倒。"]'),
('d072a05b-b609-4a51-a5f9-00094a2b0873','張德夫園亭八咏 山椒','王炎','宋','宋诗','song-poetry','','[]','百尺雲根老，斑斑長綠苔。',48,'全唐诗/poet.song.160000.json','["百尺雲根老，斑斑長綠苔。", "幽尋穿䆗窱，遠眺步崔嵬。", "地脈元無此，人心亦巧哉。", "千年湖底石，幻作小飛來。"]'),
('62b2a2b5-5ad0-4985-8245-6cdaff6e0256','張德夫園亭八咏 可瑩','王炎','宋','宋诗','song-poetry','','[]','小鑿蒼苔破，潴爲玉鑑平。',48,'全唐诗/poet.song.160000.json','["小鑿蒼苔破，潴爲玉鑑平。", "最宜孤月浴，亦有白雲行。", "須髮盡堪燭，肺肝元自清。", "微風莫吹皺，虛靜即生明。"]'),
('b9bceafe-0da7-41ef-944e-f177dbd370bc','題謝艮齋畫笥四首  其一','王炎','宋','宋诗','song-poetry','','[]','團蒲曲几自支頤，領略江山入座隅。',32,'全唐诗/poet.song.160000.json','["團蒲曲几自支頤，領略江山入座隅。", "若使右丞知此畫，定當閣筆輞川圖。"]'),
('d8294659-e251-41d1-b670-777b170a7cba','題謝艮齋畫笥四首  其二','王炎','宋','宋诗','song-poetry','','[]','萬點青山一曲溪，門闌疑是辟塵犀。',32,'全唐诗/poet.song.160000.json','["萬點青山一曲溪，門闌疑是辟塵犀。", "筆端更有詩中畫，細細冥搜爲品題。"]'),
('cc299038-21f3-49fe-9566-c1d9f050c471','題謝艮齋畫笥四首  其三','王炎','宋','宋诗','song-poetry','','[]','熟視天機日日新，無邊物色盡橫陳。',32,'全唐诗/poet.song.160000.json','["熟視天機日日新，無邊物色盡橫陳。", "從教巧手工摹寫，粉墨何能便逼真。"]'),
('4de1a444-164e-4270-b2b8-993d77755f63','題謝艮齋畫笥四首  其四','王炎','宋','宋诗','song-poetry','','[]','玉軸錦囊無此景，何年天巧出丹青。',32,'全唐诗/poet.song.160000.json','["玉軸錦囊無此景，何年天巧出丹青。", "艮齋收得供詩眼，勝看鸞臺十二屏。"]'),
('ab75afdd-5141-4acc-af11-6bc1d1f39fbf','送謝庭玉二首  其一','王炎','宋','宋诗','song-poetry','','[]','舊事十年久，故人千里疎。',48,'全唐诗/poet.song.160000.json','["舊事十年久，故人千里疎。", "喜逢青眼語，勝寄錦鱗書。", "草草銜杯酒，怱怱返笋輿。", "桂山今健否，煩爲問興居。"]'),
('6628f915-68e2-48df-a339-4536c232872a','送謝庭玉二首  其二','王炎','宋','宋诗','song-poetry','','[]','話舊情非淺，遄歸意謂何。',48,'全唐诗/poet.song.160000.json','["話舊情非淺，遄歸意謂何。", "杜門元簡出，命駕特相過。", "黄鵠仙翁逝，青衿子姓多。", "屬渠勤肄業，歲月易蹉跎。"]'),
('02c835d1-d787-4ea9-9cee-548924c43a1f','送劉都幹','王炎','宋','宋诗','song-poetry','','[]','本歎儒冠誤，因思學六韜。',48,'全唐诗/poet.song.160000.json','["本歎儒冠誤，因思學六韜。", "侵尋身尚困，凌厲氣當豪。", "生理舊良薄，親年今已高。", "匣中雄劍在，早去樹旗旄。"]'),
('99f90011-cf1d-43d7-93da-946c18542b45','清江勸駕送舉人二首  其一','王炎','宋','宋诗','song-poetry','','[]','藏山有良玉，潛淵有明珠。',96,'全唐诗/poet.song.160000.json','["藏山有良玉，潛淵有明珠。", "寶氣露光彩，見者詎肯遺。", "賢士抱良貴，又與珠玉殊。", "方其未達時，眇然一布韋。", "時來取通顯，乘軒而執珪。", "鶴書出閶闔，嗣聖清明初。", "彈冠今彙征，駸駸上天衢。", "顯親與事君，忠孝當無虧。"]'),
('c306f070-0792-4438-9913-b50c4b72f906','清江勸駕送舉人二首  其二','王炎','宋','宋诗','song-poetry','','[]','黄堂暫虛位，勸駕屬守丞。',108,'全唐诗/poet.song.160000.json','["黄堂暫虛位，勸駕屬守丞。", "金石方遏密，不敢歌鹿鳴。", "吉蠲置觴豆，少洽賓主情。", "西風吹桂枝，馬首將東行。", "春官奏高第，天子開延英。", "親策降清問，健論攄丹誠。", "解褐躋膴仕，何止爲身榮。", "二劉與三孔，至今流芳馨。", "願言踵前脩，勉矣垂令名。"]'),
('a4a17568-ad18-45b0-b75b-ec1b315cf4d1','次韻分寧胡宰贈行','王炎','宋','宋诗','song-poetry','','[]','別駕無才堪展驥，解印來歸私自喜。',176,'全唐诗/poet.song.160000.json','["別駕無才堪展驥，解印來歸私自喜。", "意欲息肩猶未能，政坐文窮巧爲祟。", "鳬仙傾蓋如舊知，冰玉清言心可洗。", "況逢父老誇長官，撫字有恩淪骨髓。", "俶裝暫去桃李陰，遽勤飲餞枉車騎。", "自憐孤冷仍數奇，諸公薦口頗難啟。", "溪上只今梅未花，歸時春燕定成壘。", "妙語吹噓恐過情，甚慚綠綺奏山水。", "君才過我蓋十倍，乃容蹇足陪驪駬。", "異鄉爲客更別離，寒日纁黄催短晷。", "平生惜飲亦徑醉，放歌不記南山鯉。"]'),
('c8b5a254-4279-407f-8350-2200c3471889','次韻巴陵羅簿送行二首  其一','王炎','宋','宋诗','song-poetry','','[]','旌陽峰下水成淵，可約鳬鷗共一川。',64,'全唐诗/poet.song.160000.json','["旌陽峰下水成淵，可約鳬鷗共一川。", "種秫漸營浮蟻甕，結茅重理蠹魚編。", "敢期晤語方傾蓋，遽有新詩當贈鞭。", "仰望青雲多鼎貴，無由換骨學飛仙。"]'),
('cbbcb2f5-4d20-4586-8d47-0a5161cc9b47','次韻巴陵羅簿送行二首  其二','王炎','宋','宋诗','song-poetry','','[]','削去浮夸意味真，襟期殊不似今人。',64,'全唐诗/poet.song.160000.json','["削去浮夸意味真，襟期殊不似今人。", "慶傳於後珠成樹，德潤其身玉有筠。", "在昔雁行嘗並進，只今鶴髮獨相親。", "仕雖不達俱强健，剝復何須問大鈞。"]'),
('04067583-26aa-4f6c-a0fc-3fe6a46937f0','次韻分寧羅簿贈行二首  其一','王炎','宋','宋诗','song-poetry','','[]','剛腸厭徇俗，老眼飽閲世。',120,'全唐诗/poet.song.160000.json','["剛腸厭徇俗，老眼飽閲世。", "讀書學經綸，亦頗識一二。", "妄意糟粕中，啜嚌得馨旨。", "終然不可用，落落多左計。", "慨念古人遠，莫救吾道弊。", "脩溪有短簿，今代習鑿齒。", "貽我瓊瑶章，有美而無刺。", "內視才具短，不能尺有咫。", "贈言雖甚寵，借玉恐未是。", "公等必飛揚，我老惟退避。"]'),
('63084167-f78f-4e77-8a5c-cb2999f694fa','次韻分寧羅簿贈行二首  其二','王炎','宋','宋诗','song-poetry','','[]','已丑太常第，君家登兩翁。',120,'全唐诗/poet.song.160000.json','["已丑太常第，君家登兩翁。", "黄鵠久仙去，不亡有流風。", "小阮最逸羣，未幾魚化龍。", "江城始解后，岩邑仍過從。", "謂予偕二父，聯名千佛中。", "一見辭色莊，再款肺腑通。", "議論到易象，或借聽於聾。", "我行踏京塵，君棲簿書叢。", "情親不厭久，語別殊怱怱。", "回首川陸隔，天寒悲塞鴻。"]'),
('bbc9cd7e-ca5b-4a51-aed6-627d7934234a','郊祀慶成詩','王炎','宋','宋诗','song-poetry','','[]','燕翼傳丕緒，龍飛襲慶基。',288,'全唐诗/poet.song.160000.json','["燕翼傳丕緒，龍飛襲慶基。", "萬年新景命，三歲始親祠。", "脩己崇仁儉，承顔洽孝慈。", "和平調玉燭，靜謐偃鋒旗。", "九廟歆禋享，三宮集壽祺。", "馨香端可薦，降鑒本無私。", "寶律迎長至，觚壇蕆上儀。", "貢金來牧伯，執玉列丞疑。", "祼鬯清宮後，燔蕭太室時。", "青城收宿靄，黄道煥晴曦。", "六驥鑾輿穩，千牛彩仗移。", "聲文蒐舊典，誓戒儆前期。", "陟配尊皇祖，靈承合大示。", "陶匏浮泛齊，繭栗用騂犧。", "皦繹圜鍾奏，忱恂祝冊辭。", "夜分風籟靜，天近斗杓垂。", "聖意彌寅畏，臣心盡肅祗。", "欽柴靈下墮，拜胙福來綏。", "樂與民同慶，寧顓已受釐。", "榮光浮翠輦，歡抃擁彤墀。", "日騎屯方罷，雲韶樂共隨。", "一聲傳入蹕，萬目望華芝。", "丹鳳端門聳，金雞渙號施。", "厖恩沾動植，協氣暢華夷。"]'),
('a9086d3d-98d3-40d4-9d38-a9993a15f176','送吳司令知金州','王炎','宋','宋诗','song-poetry','','[]','曩時異姓新安王，中興功烈書旗常。',160,'全唐诗/poet.song.160000.json','["曩時異姓新安王，中興功烈書旗常。", "邊兵不敢窺蜀塞，至今恃此爲金湯。", "我生久恨在王後，幸識王孫人物秀。", "立朝日淺即西還，自詭一州宜試守。", "媯墟北望臨咸陽，往事令人多感傷。", "清時乘障姑緩带，試問澆瓜兼採桑。", "湖上花光濃似酒，紫微惜別同携手。", "一杯爲壽謝不能，千里關山漫回首。", "春秋鼎盛握虎符，此行善保千金軀。", "籌邊熟慮得全策，歸來却獻平戎書。"]'),
('a7e48361-dfd1-4aaa-87d1-75f2a30d1cb2','和李提幹携詩相訪','王炎','宋','宋诗','song-poetry','','[]','古來論人物，西蜀名士多。',120,'全唐诗/poet.song.160000.json','["古來論人物，西蜀名士多。", "李侯有醖藉，自愛如隨和。", "不肯扣朱門，漫刺獨我過。", "筆端金石鳴，音節如九歌。", "小拂榻上塵，揮麈傾懸河。", "歲月易晼晚，功名忌蹉跎。", "西風向摇落，如此羈旅何。", "倦游且西還，萬里行江沱。", "士誠有所挾，光彩終不磨。", "翰墨更著鞭，淵雲可同科。"]'),
('915548e3-492b-4e74-b1b1-2768cbc17186','用前韻答李提幹','王炎','宋','宋诗','song-poetry','','[]','交游不厭廣，益友未必多。',120,'全唐诗/poet.song.160000.json','["交游不厭廣，益友未必多。", "晚乃識斯人，心肅而氣和。", "薄言臭味同，屢枉高軒過。", "手携綠綺琴，絃以白雪歌。", "別易會合難，預愁隔關河。", "老我無所營，豈復憂蹉跎。", "才高位猶下，君意將如何。", "有玉不願獻，誰能涕滂沱。", "自可薦藻藉，政須工琢磨。", "何以贈君行，聖門睎四科。"]'),
('423de6af-1a3f-4ae8-82ca-0b2e26a0e1ea','九日登寶叔塔同游者楊大著李校書馮正字曾著作易校書','王炎','宋','宋诗','song-poetry','','[]','湖邊老石立巨鰲，背負浮圖千尺高。',144,'全唐诗/poet.song.160000.json','["湖邊老石立巨鰲，背負浮圖千尺高。", "升高望遠天界闊，海山江樹皆秋毫。", "蓬萊藏室極清靜，雖有暇日無遊遨。", "不應令節亦虛度，特爲萸菊觴新醪。", "樽前一笑豈易得，身涉百憂今二毛。", "茲游回首便陳迹，事如逝水流滔滔。", "明年九日定何許，未用感慨增煩勞。", "半生隨牒落州縣，莫年結綬來神臯。", "去留聚散偶然耳，且覆一杯持蟹螯。"]'),
('76b0b3ec-77b2-4e04-8b50-80f02ddb1017','用元韻答楊大著李校書','王炎','宋','宋诗','song-poetry','','[]','蓬萊雲氣依海鰲，中有詩仙流品高。',144,'全唐诗/poet.song.160000.json','["蓬萊雲氣依海鰲，中有詩仙流品高。", "子雲抄書自點勘，方瞳炯炯分纖毫。", "仲元公退便燕坐，日涉藝圃當遊遨。", "烏衣裔孫不解此，但摘青蕊斟官醪。", "壯年落筆無好語，況復衰颯垂霜毛。", "二豪拔足立塵表，下視流俗徒滔滔。", "詞鋒健鬭取一快，往復險韻不憚勞。", "旁觀微之敵白傅，自分司馬優枚臯。", "倡而不和當受罰，丐公酌酒羞二螯。"]'),
('083ea800-1aec-4986-b49d-72a61ef7bfad','送王巽澤侍郎  其一','王炎','宋','宋诗','song-poetry','','[]','今代王文度，聲名滿日邊。',48,'全唐诗/poet.song.160000.json','["今代王文度，聲名滿日邊。", "中年登近侍，早歲悟深禪。", "要路頻回首，名藩小息肩。", "卷舒無不可，胸次本超然。"]'),
('c15b6309-425f-4489-9713-d2e55d435c92','送王巽澤侍郎  其二','王炎','宋','宋诗','song-poetry','','[]','屈指桃溪上，差池二十年。',48,'全唐诗/poet.song.160000.json','["屈指桃溪上，差池二十年。", "知心寧易得，識面豈無緣。", "離別何須恨，平安可數傳。", "異時如索我，小隠翠微邊。"]'),
('1509cb2c-18ba-4e79-8ce4-8587a23efc5e','張尚書挽詩  其一','王炎','宋','宋诗','song-poetry','','[]','魏國扶天力，荆州貫日忠。',48,'全唐诗/poet.song.160000.json','["魏國扶天力，荆州貫日忠。", "堂堂惟此老，凜凜尚英風。", "地寄陪京重，名加秘殿隆。", "望徒高四海，身不到三公。"]'),
('65f0accb-71b3-400d-b9ab-6d69377d7243','張尚書挽詩  其二','王炎','宋','宋诗','song-poetry','','[]','細數青雲士，如公有幾人。',48,'全唐诗/poet.song.160000.json','["細數青雲士，如公有幾人。", "登龍心不遂，烹鯉字猶新。", "後進思高誼，中朝念信臣。", "百年喬木折，有識共酸辛。"]'),
('0bb087a3-fbe4-4b9d-9a40-076e32a8d864','李少保挽詩  其一','王炎','宋','宋诗','song-poetry','','[]','潔己惟清德，攖鱗有格言。',48,'全唐诗/poet.song.160000.json','["潔己惟清德，攖鱗有格言。", "位雖居鼎鼐，心已在丘園。", "身退名增重，年高道愈尊。", "哀榮無可憾，餘慶子孫蕃。"]'),
('1eef4847-f9fa-4656-a224-658957e0c4a3','李少保挽詩  其二','王炎','宋','宋诗','song-poetry','','[]','昭代多諸老，惟公有典刑。',48,'全唐诗/poet.song.160000.json','["昭代多諸老，惟公有典刑。", "上方思舊弼，天亦畀脩齡。", "竟委元成笏，俄傳有道銘。", "只期麟閣上，遺像拜丹青。"]'),
('3c7b2eef-1dab-43c5-bf09-4039db043db3','太皇太后挽詩  其一','王炎','宋','宋诗','song-poetry','','[]','弧矢能天授，詩書德日新。',48,'全唐诗/poet.song.160000.json','["弧矢能天授，詩書德日新。", "中興扶漢祚，內禪贊堯仁。", "鏤玉三朝慶，塗椒四世親。", "乘雲今不返，垂白泣遺民。"]'),
('183577ed-e17a-44cd-b8e9-9063c2c85680','太皇太后挽詩  其二','王炎','宋','宋诗','song-poetry','','[]','離日升黄道，簾中出玉音。',48,'全唐诗/poet.song.160000.json','["離日升黄道，簾中出玉音。", "位高踰薄竇，德盛掩姜任。", "七紀哀榮備，三宮愛慕深。", "補天生萬物，何以答仁心。"]'),
('e4cb5218-2515-4428-b61c-73de8b1acaa4','從范秘監過城南陳亦顔讀書樓  其一','王炎','宋','宋诗','song-poetry','','[]','客來揮麈對觥船，客去焚香閲簡編。',32,'全唐诗/poet.song.160000.json','["客來揮麈對觥船，客去焚香閲簡編。", "車馬軟紅塵裏走，不知委巷有壺天。"]'),
('762e06f7-dd95-4a91-9a99-de4765753742','從范秘監過城南陳亦顔讀書樓  其二','王炎','宋','宋诗','song-poetry','','[]','軒冕浮夸不繫情，山林清奧可逃名。',32,'全唐诗/poet.song.160000.json','["軒冕浮夸不繫情，山林清奧可逃名。", "如何結屋依廬阜，又却移家近玉京。"]'),
('e8c71837-3763-4764-a075-5a3bc4afae6e','次韻楊秘監館中即事','王炎','宋','宋诗','song-poetry','','[]','簾箔風清乳燕飛，綠陰遶殿覆銅池。',64,'全唐诗/poet.song.160000.json','["簾箔風清乳燕飛，綠陰遶殿覆銅池。", "九衢達宦爭馳轂，羣玉詩翁獨下帷。", "鳳餠正當分賜後，牙籤又近曝書時。", "管城寫出琳琅句，付與神靈爲護持。"]'),
('9f0ee209-219a-420d-b534-c45f06cf086c','次韻午睡不知雨作','王炎','宋','宋诗','song-poetry','','[]','曲肱幽夢午風凉，銷盡熏爐一穗香。',64,'全唐诗/poet.song.160000.json','["曲肱幽夢午風凉，銷盡熏爐一穗香。", "急雨蕭蕭猶未覺，浮塵熠熠更相忘。", "自非靜處心神定，誰識閒中氣味長。", "隠几豈容無一事，願將奇字問偏旁。"]'),
('a5f6e32a-f5d6-4dfc-a6ed-0f8c23fec266','次韻楊秘監館中留題  其一','王炎','宋','宋诗','song-poetry','','[]','把杯方喜挹流霞，照眼驪珠重拜嘉。',64,'全唐诗/poet.song.160000.json','["把杯方喜挹流霞，照眼驪珠重拜嘉。", "庭下滿生書带草，胸中宜吐筆頭花。", "敢言策足攀賢躅，獨幸游心泳聖涯。", "誰謂蓬萊雲氣遠，此中清閟即仙家。"]'),
('cfb32837-244b-4ddb-826d-c06e001fe169','次韻楊秘監館中留題  其二','王炎','宋','宋诗','song-poetry','','[]','紅塵飛不到壺天，風月幽懷屬老仙。',32,'全唐诗/poet.song.160000.json','["紅塵飛不到壺天，風月幽懷屬老仙。", "自笑枯腸無好語，且呼黄嬭曲肱眠。"]'),
('e1c4ea01-795a-4d45-a1f4-3726329f37d4','九日陪楊秘監游真珠園屬炎賦詩','王炎','宋','宋诗','song-poetry','','[]','珍重蓬萊老，携壺領客來。',48,'全唐诗/poet.song.160000.json','["珍重蓬萊老，携壺領客來。", "湖山羅畫笥，風物獻詩材。", "素髮難重染，黄花有再開。", "莫憂身外事，且覆掌中杯。"]'),
('b93381ab-44c3-416c-b8f1-7b3e70b24193','送黄尚書帥蜀','王炎','宋','宋诗','song-poetry','','[]','六蜚駐蹕臨東吳，益州遠在西南隅。',224,'全唐诗/poet.song.160000.json','["六蜚駐蹕臨東吳，益州遠在西南隅。", "君王右顧入念慮，選用名德分麟符。", "文章政事俱第一，袖手未肯持鈞樞。", "清獻之清過於水，忠定之信孚豚魚。", "二賢寂寂未有繼，蜀人惟恐公來遲。", "泝江萬里飛鷁首，祝公善保千金軀。", "髮須未見一絲白，歸來便可居丞疑。", "清時緩带鎮方面，問民疾苦勤褰帷。", "頗聞今蜀與昔異，昔日民肥今已臞。", "願言細意護根本，要令可與同安危。", "更須推轂拔人物，勿念折箠笞羌夷。", "想見明年初下車，錦官城裏花正都。", "四郊按堵但耕鑿，春風蕩漾隨旄麾。", "遨頭一笑父老賀，九重不用憂坤維。"]'),
('7bd17c1f-7c4e-45e8-84ea-4d8bd86fcd73','題徐商叟參議儒榮閣','王炎','宋','宋诗','song-poetry','','[]','神臯北望幾傷情，海上何人議北盟。',64,'全唐诗/poet.song.160000.json','["神臯北望幾傷情，海上何人議北盟。", "青簡成編裨史事，紫泥封璽奬儒榮。", "書藏金匱人爭問，身到蓬山志亦亨。", "佩印纍纍真漫耳，婆娑林下有香名。"]'),
('06320ead-94be-4cbe-8be2-487c55e37830','銛老許相過不至炎約堯章訪之又以事奪銛寄二詩次其韻  其一','王炎','宋','宋诗','song-poetry','','[]','聞道幽棲好，天香坐上飄。',48,'全唐诗/poet.song.160000.json','["聞道幽棲好，天香坐上飄。", "熟知甘淡泊，甚欲識孤高。", "縱有門關隔，元非道路遥。", "恐公真簡出，不過虎溪橋。"]'),
('ea87cadc-3257-4a4b-abd8-616f5c125338','銛老許相過不至炎約堯章訪之又以事奪銛寄二詩次其韻  其二','王炎','宋','宋诗','song-poetry','','[]','南山藏霧豹，幾欲訪幽深。',48,'全唐诗/poet.song.160000.json','["南山藏霧豹，幾欲訪幽深。", "詩到如相挽，盟寒尚可尋。", "惠初從柳子，支遁會山陰。", "此事今寥落，期公慰我心。"]'),
('f14271e0-2a33-4b0a-b99a-e1d2104817ad','游劉寺次林子長郎中韻','王炎','宋','宋诗','song-poetry','','[]','琳瑯觸目聚潛郎，假日相携入酒鄉。',64,'全唐诗/poet.song.160000.json','["琳瑯觸目聚潛郎，假日相携入酒鄉。", "小憑笋輿穿野徑，却尋蕭寺涉脩廊。", "意行塵外襟懷爽，身坐梅邊笑語香。", "頭白倦游休嘆息，喜迎一線日華長。"]'),
('bd2f8531-b2d5-4b46-997b-2247d196fe61','炎十世先隴在婺源不歸拜掃者九年清明有感遂成小詩','王炎','宋','宋诗','song-poetry','','[]','九陌黄塵裏，不知桃李開。',48,'全唐诗/poet.song.160000.json','["九陌黄塵裏，不知桃李開。", "怱怱春又過，逐逐老相催。", "浮脆身如露，紛華念已灰。", "松楸無恙否，久客盍歸來。"]'),
('67df358e-8d1e-44a7-877c-6faed4147dd6','同李魯二郎中游三茅觀  其一','王炎','宋','宋诗','song-poetry','','[]','羽衣邀我坐團蒲，一穗香雲遶竹爐。',32,'全唐诗/poet.song.160000.json','["羽衣邀我坐團蒲，一穗香雲遶竹爐。", "九陌紅塵飛不到，疑從木末入懸壺。"]'),
('70738ec0-3390-4376-b85d-25cfb8f53083','同李魯二郎中游三茅觀  其二','王炎','宋','宋诗','song-poetry','','[]','愁邊無處寄幽懷，擬傍梅花把一杯。',32,'全唐诗/poet.song.160000.json','["愁邊無處寄幽懷，擬傍梅花把一杯。", "玉靨含香渾未吐，嘗携歡伯爲重來。"]'),
('fcc5269d-2744-4fc9-9356-fcc6f7dcb933','同李魯二郎中游三茅觀  其三','王炎','宋','宋诗','song-poetry','','[]','路入疎梅密竹間，俯看水墨畫湖山。',32,'全唐诗/poet.song.160000.json','["路入疎梅密竹間，俯看水墨畫湖山。", "玉妃妬我清游好，剪水飛花作苦寒。"]'),
('b173d2b1-2a36-4917-9b4f-af27751543fd','用元韻答李郎中  其一','王炎','宋','宋诗','song-poetry','','[]','未問仙家九節蒲，且持茗碗對熏爐。',32,'全唐诗/poet.song.160000.json','["未問仙家九節蒲，且持茗碗對熏爐。", "黄冠也肯迎留客，咀嚼梅花費一壺。"]'),
('313c95fc-40a2-4e40-91ba-f06a0edc268e','用元韻答李郎中  其二','王炎','宋','宋诗','song-poetry','','[]','冰玉談清洗老懷，興濃亦覆手中杯。',32,'全唐诗/poet.song.160000.json','["冰玉談清洗老懷，興濃亦覆手中杯。", "平生蠟屐登山慣，豈必因花特地來。"]'),
('086aa68d-d7be-407e-af17-f7ee9b3b6778','用元韻答李郎中  其三','王炎','宋','宋诗','song-poetry','','[]','地近觚稜雲氣間，蕊珠宮殿壓青山。',32,'全唐诗/poet.song.160000.json','["地近觚稜雲氣間，蕊珠宮殿壓青山。", "雲根盡處天風急，疑是人間有廣寒。"]'),
('f737a7bc-ce24-4d08-a9de-a387be606dbc','用元韻答銛老  其一','王炎','宋','宋诗','song-poetry','','[]','人間得喪等樗蒲，何似繙經擁地爐。',32,'全唐诗/poet.song.160000.json','["人間得喪等樗蒲，何似繙經擁地爐。", "尚學湯休頻覓句，儻逢元亮一傾壺。"]'),
('5aa88b10-9382-42b3-b75f-822f0ac74a95','用元韻答銛老  其二','王炎','宋','宋诗','song-poetry','','[]','舐犢酸辛入客懷，何堪婪尾更傳杯。',32,'全唐诗/poet.song.160000.json','["舐犢酸辛入客懷，何堪婪尾更傳杯。", "却思拈拂談名理，肯憚携筇數往來。"]'),
('f2205fc7-4707-4b9b-b955-8f5cfec31cf4','用元韻答銛老  其三','王炎','宋','宋诗','song-poetry','','[]','墮在黄塵九陌間，羨君小隠住南山。',32,'全唐诗/poet.song.160000.json','["墮在黄塵九陌間，羨君小隠住南山。", "梅花香裏尋支徑，屢有盟言不可寒。"]'),
('03c972ef-deb8-48bd-b9b5-b98339114b93','臘中得雪快晴成古風呈堯章銛老','王炎','宋','宋诗','song-poetry','','[]','蒼頭熟睡喚不應，光射紙窗疑月明。',128,'全唐诗/poet.song.160000.json','["蒼頭熟睡喚不應，光射紙窗疑月明。", "更籌可數夜方半，杙上一雞先誤鳴。", "曉起飛花堆戶外，幻出人間無色界。", "九街車馬不知寒，蹴蹋銀杯翻縞带。", "杲杲日升東海東，須臾光彩蒸霞紅。", "不憂桂玉頓增價，人在沖融和氣中。", "貝闕珠宮五雲際，遥知天上龍顔喜。", "麥畦白白覆青青，農事來年定豐美。"]'),
('58fdc537-63ae-4749-82e5-705121103be8','用元韻答李郎中','王炎','宋','宋诗','song-poetry','','[]','何人喚得滕六應，遺我通宵銀海明。',128,'全唐诗/poet.song.160000.json','["何人喚得滕六應，遺我通宵銀海明。", "起來無以助清興，銅瓶煮茗松風鳴。", "恍疑拔脚塵寰外，玉田萬頃無疆界。", "蒼官青士亦改容，高下瑶林相映带。", "騎鯨人在日華東，曉踏天街無軟紅。", "雪車冰柱堪著語，何止爭雄郊島中。", "翩翩鶴氅凌風際，得句摇毫心自喜。", "從渠春笋捧金荷，醉倒氍毹貪睡美。"]'),
('64659018-fdd9-4f3c-b8f6-02c3e332dbb7','游水樂洞','王炎','宋','宋诗','song-poetry','','[]','路向峰腰轉，泉從洞口來。',48,'全唐诗/poet.song.160000.json','["路向峰腰轉，泉從洞口來。", "決渠飛瀑布，伐石作崔嵬。", "勝境難頻到，幽懷只暫開。", "登臨興不盡，日昃故須回。"]'),
('48a0f030-8b4f-443e-91f0-8f792177e17b','出城','王炎','宋','宋诗','song-poetry','','[]','郊原雨過草萋萋，桑柘陰濃麥穗低。',32,'全唐诗/poet.song.160000.json','["郊原雨過草萋萋，桑柘陰濃麥穗低。", "春色難留人易老，落花風裏杜鵑啼。"]'),
('37b995b0-ae13-47a8-a4ba-2de939c2b8bf','即事四首  其一','王炎','宋','宋诗','song-poetry','','[]','游宦初心改，殷憂素髮稀。',48,'全唐诗/poet.song.160000.json','["游宦初心改，殷憂素髮稀。", "稍閒甘晝寢，已暖怯春衣。", "遮眼惟黄卷，關心在翠微。", "去留俱有恨，不見二雛飛。"]'),
('4a2851f4-b9e5-474d-8825-e7e5633bb98f','即事四首  其二','王炎','宋','宋诗','song-poetry','','[]','髮禿憐毛穎，纔供米帛謀。',48,'全唐诗/poet.song.160000.json','["髮禿憐毛穎，纔供米帛謀。", "才疎無可用，身老更何求。", "燕語催春事，花飛惱客愁。", "行藏猶首鼠，歸夢遶滄洲。"]'),
('ec2b724f-c420-4d84-b224-9a097be388e8','即事四首  其三','王炎','宋','宋诗','song-poetry','','[]','半日肩輿走，歸來已薾然。',48,'全唐诗/poet.song.160000.json','["半日肩輿走，歸來已薾然。", "倦談懸麈尾，清坐炷龍涎。", "有累緣糊口，何時可息肩。", "靈襟要淘洗，盥手閲韋編。"]'),
('a2897070-eda1-47e3-843f-46e2b12f5530','即事四首  其四','王炎','宋','宋诗','song-poetry','','[]','京國三年夢，家山二子喪。',48,'全唐诗/poet.song.160000.json','["京國三年夢，家山二子喪。", "淚乾昏老眼，痛極斷中腸。", "數盡誰無死，情鍾自不忘。", "餘生寧有幾，回首意茫茫。"]'),
('92164384-9305-4635-be01-4116a1faf58b','汪秘校携詩併雪月二賦相訪次其韻','王炎','宋','宋诗','song-poetry','','[]','自從就食寄他州，不到鄉關近十秋。',64,'全唐诗/poet.song.160000.json','["自從就食寄他州，不到鄉關近十秋。", "文采誰能如象齒，交游今乃見龍頭。", "携詩過我情何厚，落筆驚人語不休。", "雪月賦成凌二謝，高懷肯述畔牢愁。"]'),
('fb011724-7f35-439b-8cd3-d0618248f2d9','送朱大卿歸龍舒','王炎','宋','宋诗','song-poetry','','[]','觚稜挂曉日，浮鷁違都城。',240,'全唐诗/poet.song.160000.json','["觚稜挂曉日，浮鷁違都城。", "今代朱伯厚，勇去投簪纓。", "津津眉睫間，不見離別情。", "問之何能爾，內重外物輕。", "聲利誘一世，漏盡猶夜行。", "豈不厭逐逐，無由息營營。", "若人著眼高，不受世網攖。", "奮身許國久，艱險亦飽更。", "乘傳上蠶叢，擁旄到龍廷。", "中朝豹尾班，詎可欠老成。", "一旦念丘園，拂衣即遐征。", "君相雖貪賢，欲留終不能。", "班以內閣奧，秩之閒館清。", "皖山插天翠，淮水到海平。", "婆娑山水間，可築半隠亭。", "雞豚入新社，鷗鷺尋舊盟。", "收身謝危機，至此全脩名。", "嗟我爲糊口，偃蹇侵頹齡。", "仰羨冥鴻高，俯慙曉猿驚。", "青山不負約，行矣謀歸耕。"]'),
('2588d1bb-87c2-418d-898f-f41ed14d13eb','題徐商叟所藏李伯時四天王圖','王炎','宋','宋诗','song-poetry','','[]','龍眠有巧手，幻出汗血駒。',144,'全唐诗/poet.song.160000.json','["龍眠有巧手，幻出汗血駒。", "老衲或戒之，回向心地初。", "遂畫白衣仙，蘄與梵釋俱。", "北方四天王，亦附瞿曇居。", "雜以馬龍像，宿習終未除。", "四王名字異，且復形狀殊。", "信者謂其有，疑者意其無。", "蕩蕩天門高，誰能凌空虛。", "何以信不疑，取諸貝葉書。", "子不語怪神，從釋恐畔儒。", "語之且不可，筆之其可乎。", "因畫議及此，於公意何如。"]'),
('3e96c589-6a41-4dfe-803d-581e5287599d','次韻胡連翁携詩見訪','王炎','宋','宋诗','song-poetry','','[]','蘄春別駕寡交游，獨肯對君青兩眸。',64,'全唐诗/poet.song.160000.json','["蘄春別駕寡交游，獨肯對君青兩眸。", "我亦杜門嫌俗子，今方下榻得詩流。", "環溪陳迹幾如掃，鄂渚遺文散不收。", "訪舊九京無起日，臨風三嘆不能休。"]'),
('dd4958d6-5a61-4f60-afac-061af9595188','太上皇后挽詩  其一','王炎','宋','宋诗','song-poetry','','[]','紫殿尊嚴地，黄圖揖遜辰。',48,'全唐诗/poet.song.160000.json','["紫殿尊嚴地，黄圖揖遜辰。", "一言裨大策，萬物頼深仁。", "配極乾坤大，重輪日月新。", "遽違天下養，氛祲揜鈎陳。"]'),
('85fcf5c8-b799-4a80-9d78-1d29e208c5d7','太上皇后挽詩  其二','王炎','宋','宋诗','song-poetry','','[]','大帝資陰德，吾皇仰母慈。',48,'全唐诗/poet.song.160000.json','["大帝資陰德，吾皇仰母慈。", "盛儀猶澣服，新樂在含飴。", "玉冊將增慶，椒庭遽共悲。", "憂勤終損壽，天道果難知。"]'),
('5e11c6e8-950f-4d95-9f87-b0fcb4f7c914','太上皇帝挽詩  其一','王炎','宋','宋诗','song-poetry','','[]','揖遜承虞治，謳歌與啟賢。',48,'全唐诗/poet.song.160000.json','["揖遜承虞治，謳歌與啟賢。", "御圖纔五載，垂統可千年。", "明有重離繼，高居太極先。", "四朝三內禪，盛美古無傳。"]'),
('088a8c74-4f23-4795-9799-51e0ed69cce1','太上皇帝挽詩  其二','王炎','宋','宋诗','song-poetry','','[]','億兆方同慶，三宮洽孝慈。',48,'全唐诗/poet.song.160000.json','["億兆方同慶，三宮洽孝慈。", "坤輿俄㢮衛，天極遂纏悲。", "共憾遺丹鼎，無由奉玉巵。", "光輝終不熄，徽號日星垂。"]'),
('580d8e12-ba76-42b7-9cea-7cdf7bb060fc','題姜堯章舊游詩卷','王炎','宋','宋诗','song-poetry','','[]','出郭栽花涉小園，歸調琴譜輯詩編。',32,'全唐诗/poet.song.160000.json','["出郭栽花涉小園，歸調琴譜輯詩編。", "少年豪健今揫斂，休羨騎鯨李謫仙。"]'),
('5f627f63-8d4f-4d0e-a3a9-add2457b72c3','和九日堯章送菊  其一','王炎','宋','宋诗','song-poetry','','[]','對花懶舉玉東西，孤負金錢滿綠枝。',32,'全唐诗/poet.song.160000.json','["對花懶舉玉東西，孤負金錢滿綠枝。", "短髮不堪重落帽，枯腸何可强搜詩。"]'),
('eb88bc95-f4d2-44ec-91c6-87e786dde436','和九日堯章送菊  其二','王炎','宋','宋诗','song-poetry','','[]','花品若將人品較，此花風味似吾儒。',32,'全唐诗/poet.song.160000.json','["花品若將人品較，此花風味似吾儒。", "秋英餐罷含清思，曾有離騷續筆無。"]'),
('c41ffdf3-5420-4ab0-9fb8-46d1b767a2d1','送陳華文出守當塗同僚餞別分韻得立字','王炎','宋','宋诗','song-poetry','','[]','今代陳仲弓，人門兩難及。',120,'全唐诗/poet.song.160000.json','["今代陳仲弓，人門兩難及。", "長離五色羽，覽輝早翔集。", "功名雖鼎來，未肯心汲汲。", "自請牧一州，小民要安輯。", "維時春將半，桃李露華濕。", "慈顔御輕軒，綵服隨坐立。", "行行即下車，嘯諾解苛急。", "凝香宴賓從，仁氣散臯隰。", "政恐席未暖，追鋒已催入。", "塗轍可通行，青雲如陟級。"]'),
('02237bf7-baed-4c8b-9068-7e690281565d','即事','王炎','宋','宋诗','song-poetry','','[]','久輟囊中句，時看肘後方。',48,'全唐诗/poet.song.160000.json','["久輟囊中句，時看肘後方。", "有家如旅舍，無事似僧房。", "梅白牆頭笑，榴紅甕面香。", "杖藜如可出，溪上探春光。"]'),
('a0c575dc-b471-46bf-b8ce-8b4cc8a2bf5a','庚申元日','王炎','宋','宋诗','song-poetry','','[]','九陌歡聲合，三宮瑞氣開。',48,'全唐诗/poet.song.160000.json','["九陌歡聲合，三宮瑞氣開。", "陰雲催歲換，霽日迓春回。", "鬰壘還當戶，屠蘇强舉杯。", "二雛無返日，羸老不勝哀。"]'),
('3af293ee-71b3-4e70-9930-36e8ecb11385','和楊郎中北廊梅花','王炎','宋','宋诗','song-poetry','','[]','不臨水曲與山隈，却在天臺獨自開。',64,'全唐诗/poet.song.160000.json','["不臨水曲與山隈，却在天臺獨自開。", "幽韻可居蘭友上，孤標惟許竹君陪。", "廣寒仙子雲中下，姑射神人海上來。", "冰玉皎然清徹骨，南廊亦欲斸根栽。"]'),
('abe25f2b-f015-4c5e-aad7-afe0912381d4','和陳右司春雪','王炎','宋','宋诗','song-poetry','','[]','換却人間色界塵，千林別作一家春。',64,'全唐诗/poet.song.160000.json','["換却人間色界塵，千林別作一家春。", "風姨寒重吹飛絮，月姊光凝映爛銀。", "曳履獨游無此士，閉門高卧有何人。", "試從羣玉山頭看，似與瑶臺貝闕鄰。"]'),
('271a43fe-976c-4739-ba4b-e989a2534142','送楊明夫郎中持節閩中','王炎','宋','宋诗','song-poetry','','[]','稍覺飛騰疾，方知選擇公。',48,'全唐诗/poet.song.160000.json','["稍覺飛騰疾，方知選擇公。", "雲霄移列宿，泉嶺度春風。", "問俗窮閻底，搜材薦墨中。", "褰帷先辦此，續續寄詩筒。"]'),
('6d338120-8f4a-4e79-99aa-87cfcc2489d6','壬戌立春日','王炎','宋','宋诗','song-poetry','','[]','晼晚流年度，凄涼短景催。',48,'全唐诗/poet.song.160000.json','["晼晚流年度，凄涼短景催。", "月圓疑臘半，歲閏已春回。", "一箸青絲菜，三杯白玉醅。", "主人無喜事，蠟炬誤花開。"]'),
('7e6c69be-5c60-41f0-8583-9188814b2a52','賀吳興郡王生日','王炎','宋','宋诗','song-poetry','','[]','花萼樓臺畔，年年瑞氣新。',48,'全唐诗/poet.song.160000.json','["花萼樓臺畔，年年瑞氣新。", "慈闈歡愛洽，帝殿寵光頻。", "清靜心如水，和平氣似春。", "自然眉壽永，何必羨松椿。"]'),
('83e3445c-1923-4dd3-858b-db6a872b09aa','登四望亭','王炎','宋','宋诗','song-poetry','','[]','春老飛花盡，園林遍綠陰。',48,'全唐诗/poet.song.160000.json','["春老飛花盡，園林遍綠陰。", "憑高聊寓目，念遠更傷心。", "劇郡才難稱，衰年病易侵。", "不如休歇去，吾意決投簪。"]'),
('003ca0fd-1fd2-4621-91bc-d02c8875d02d','閒居即事  其一','王炎','宋','宋诗','song-poetry','','[]','稍稍開三徑，徐徐辦一廛。',48,'全唐诗/poet.song.160000.json','["稍稍開三徑，徐徐辦一廛。", "歸來非失計，老去只隨緣。", "旋蠟登山屐，時操泛月船。", "生涯且如此，蕭散樂餘年。"]'),
('a2e78d2e-8e70-4eb5-9f65-c7bef4703561','閒居即事  其二','王炎','宋','宋诗','song-poetry','','[]','壯年多旅寓，晚歲遽鰥居。',48,'全唐诗/poet.song.160000.json','["壯年多旅寓，晚歲遽鰥居。", "傷往遂成賦，解嘲休著書。", "經營惟種蒔，來往但樵漁。", "百念今灰冷，雖貧自晏如。"]'),
('33e949a3-1bee-4abc-9e11-17341f786367','閒居即事  其三','王炎','宋','宋诗','song-poetry','','[]','四面青山合，中藏小隠家。',48,'全唐诗/poet.song.160000.json','["四面青山合，中藏小隠家。", "謀栽陶令秫，學種邵侯瓜。", "笋長多添竹，荷高漸有花。", "林泉宜寂靜，鼓吹厭鳴蛙。"]'),
('f033ff68-1d6f-4d36-b7a7-d4b86e626b54','喜晴','王炎','宋','宋诗','song-poetry','','[]','欲了老妻窀穸事，屈指前期日無幾。',96,'全唐诗/poet.song.160000.json','["欲了老妻窀穸事，屈指前期日無幾。", "羊腸路險不容車，水澀石高灘齒齒。", "天公憫我憂惱深，一雨驟添三尺水。", "黄流又恐舟難行，落盡雪花天宇清。", "六龍扶轂日杲杲，更乞天公旬日晴。", "襄事歸來閉門坐，但擁竹爐多熾火。"]'),
('a7c2368c-fce2-4a2b-8b2d-b29c66d5e724','用元韻答秀叔  其一','王炎','宋','宋诗','song-poetry','','[]','休將世事關身事，自數頹齡尚餘幾。',96,'全唐诗/poet.song.160000.json','["休將世事關身事，自數頹齡尚餘幾。", "那堪老賦悼亡詩，不見蛾眉瓠犀齒。", "熏染可無知見香，澡雪正須功德水。", "風波跌足今憚行，林下獨居心迹清。", "冷看世態有翻覆，蚌則欲雨鷸欲晴。", "何似消摇常燕坐，雪白蓮花生烈火。"]'),
('4910d46f-7891-4c5b-915d-2256a7656b0d','用元韻答秀叔  其二','王炎','宋','宋诗','song-poetry','','[]','人生昏宦只二事，憂喜相纏不知幾。',96,'全唐诗/poet.song.160000.json','["人生昏宦只二事，憂喜相纏不知幾。", "我今豈可老更癡，頰有霜髭口無齒。", "舉案齊眉安在哉，獨自飯蔬而飲水。", "半生同住不同行，稍感傷悲心亦清。", "雉鳴雌應春日暖，鳩喚婦歸天雨晴。", "斷除此念如尸坐，調護坎離交水火。"]'),
('2a42ba67-398d-4938-8ca2-8d8fa85acca7','用元韻答秀叔  其三','王炎','宋','宋诗','song-poetry','','[]','老身强健幸無事，舊日交游存者幾。',96,'全唐诗/poet.song.160000.json','["老身强健幸無事，舊日交游存者幾。", "後來阿秀詩句新，露滴金莖寒著齒。", "笑我胸中千斛塵，解纓未濯滄浪水。", "翠微嘗約載酒行，洗耳潺湲泉石清。", "天寒短策未可出，更約東郊春日晴。", "且來伴我窗間坐，黄嬭在旁同附火。"]'),
('098dc6a2-0c68-49cc-81e2-701823de8f22','秀叔和章自言及再娶之事用元韻戲答之','王炎','宋','宋诗','song-poetry','','[]','寤寐閒思疇昔事，來往于懷日凡幾。',96,'全唐诗/poet.song.160000.json','["寤寐閒思疇昔事，來往于懷日凡幾。", "伯鸞不可無孟光，豈爲青眉并玉齒。", "阿咸今與我不同，蛩蛩得草魚得水。", "流蘇帳暖雙杯行，春近梅粧香更清。", "試唱劉郎竹枝曲，道是無晴還有晴。", "長夜老夫方獨坐，手把楞伽對燈火。"]'),
('75b7e158-8581-4573-9d1f-8de450bc04f1','池邊梅花一株盛開  其一','王炎','宋','宋诗','song-poetry','','[]','天外青鸞不復歸，蕭蕭短髮日成絲。',32,'全唐诗/poet.song.160000.json','["天外青鸞不復歸，蕭蕭短髮日成絲。", "寒梅不管人憔悴，故著新花滿舊枝。"]'),
('52aed088-2716-48c1-b700-a9b0bebaf80c','池邊梅花一株盛開  其二','王炎','宋','宋诗','song-poetry','','[]','老來裘褐怯風吹，難傍花邊把一巵。',32,'全唐诗/poet.song.160000.json','["老來裘褐怯風吹，難傍花邊把一巵。", "嚼蕊嗅香清興在，尚呵凍筆欲題詩。"]'),
('556da5e0-bf74-4a62-8c55-0d5a50f355b1','戲江子大','王炎','宋','宋诗','song-poetry','','[]','莫年尚戀蛾眉斧，平日空談蠟脚禪。',32,'全唐诗/poet.song.160000.json','["莫年尚戀蛾眉斧，平日空談蠟脚禪。", "應笑老夫甘寂寞，只將黄嬭替嬋娟。"]'),
('49a560c1-8952-413d-8e69-bc01f266a3d3','用元韻答子大','王炎','宋','宋诗','song-poetry','','[]','桃花映面方留咏，藤刺纏身始悟禪。',32,'全唐诗/poet.song.160000.json','["桃花映面方留咏，藤刺纏身始悟禪。", "短髮鏡中霜薄薄，脩眉窗下月娟娟。"]'),
('b911b203-d1cb-4d8e-adf7-61d46d17e07e','追悼親哥','王炎','宋','宋诗','song-poetry','','[]','昔在清華日，明珠掌上新。',48,'全唐诗/poet.song.160000.json','["昔在清華日，明珠掌上新。", "豈期吾薄福，不見汝成人。", "荒塚魂長夜，空山草自春。", "淒涼無限恨，獨坐一沾巾。"]'),
('e226efe0-df29-47b3-b2e0-1a13b6dffb08','送石宰','王炎','宋','宋诗','song-poetry','','[]','溪頭雪後梅花發，飛鳬東去朝雙闕。',128,'全唐诗/poet.song.160000.json','["溪頭雪後梅花發，飛鳬東去朝雙闕。", "涉溪父老肩相摩，再拜路旁皆惜別。", "問侯何以能得民，胸中仁氣如陽春。", "攀轅徒切侯不住，金馬石渠須若人。", "雲溪野叟久閉戶，時枉高軒肯相顧。", "何不臨分把一杯，天寒懶出無他故。", "別離羞作兒女悲，此行穩上青雲衢。", "相思要得知健否，寄我平安雙鯉魚。"]'),
('6fb625f7-e580-4bef-a8a0-6174fec2b1ea','念舊  其一','王炎','宋','宋诗','song-poetry','','[]','香銷篋裏舊裳衣，回首人間萬事非。',32,'全唐诗/poet.song.160000.json','["香銷篋裏舊裳衣，回首人間萬事非。", "天闊海寬魂杳杳，雲軿何日復來歸。"]'),
('858f778b-f694-43be-a012-0f00674c02d9','念舊  其二','王炎','宋','宋诗','song-poetry','','[]','老懷易感淚汍瀾，塵世分明一夢間。',32,'全唐诗/poet.song.160000.json','["老懷易感淚汍瀾，塵世分明一夢間。", "精爽乘鸞雲外去，空留玉骨葬青山。"]'),
('afe1b4fd-cec3-4b9d-b38e-07b6269830d5','久雨無聊成兩詩呈秀叔并簡繼韓  其一','王炎','宋','宋诗','song-poetry','','[]','花落雨不止，鶑啼春又徂。',48,'全唐诗/poet.song.160000.json','["花落雨不止，鶑啼春又徂。", "曲肱眠短榻，擁膝坐團蒲。", "梅子今堪摘，松醪不待酤。", "兩君能坐隠，泥濘肯來無。"]'),
('094d563d-1794-4dbe-96da-6a87e1519b53','久雨無聊成兩詩呈秀叔并簡繼韓  其二','王炎','宋','宋诗','song-poetry','','[]','避濕屋多漏，怯寒窗不開。',48,'全唐诗/poet.song.160000.json','["避濕屋多漏，怯寒窗不開。", "龍涎時吐霧，麈尾任生埃。", "獨與韋編對，誰能蠟屐來。", "天知蠶麥病，願喚雨師回。"]'),
('e7e29780-e189-42cc-9334-5fbdaac79dc7','賀吳興郡王生日四絕  其一','王炎','宋','宋诗','song-poetry','','[]','德聲不減漢東平，玉鑑冰壺表裏清。',32,'全唐诗/poet.song.160000.json','["德聲不減漢東平，玉鑑冰壺表裏清。", "休問南山山色翠，淡然無慾自長生。"]'),
('20f344bb-f280-4717-878d-e6206cdd9c55','賀吳興郡王生日四絕  其二','王炎','宋','宋诗','song-poetry','','[]','黄門宣賜出丹墀，花萼樓邊禁漏遲。',32,'全唐诗/poet.song.160000.json','["黄門宣賜出丹墀，花萼樓邊禁漏遲。", "天上龍顔生喜色，鶺鴒飛在萬年枝。"]'),
('6ab0772b-4684-43df-b048-6cdf5a3fd78a','賀吳興郡王生日四絕  其三','王炎','宋','宋诗','song-poetry','','[]','長樂觚稜接未央，至尊友愛獨賢王。',32,'全唐诗/poet.song.160000.json','["長樂觚稜接未央，至尊友愛獨賢王。", "宮中共用家人禮，日近清光侍太皇。"]'),
('2c152da6-7695-4515-a619-cbe512ee1def','賀吳興郡王生日四絕  其四','王炎','宋','宋诗','song-poetry','','[]','斑衣盭綬兩光輝，和氣融融洽孝慈。',32,'全唐诗/poet.song.160000.json','["斑衣盭綬兩光輝，和氣融融洽孝慈。", "千載蟠桃今日熟，喜同王母宴瑶池。"]'),
('2cff19d9-626f-42e6-b4f6-cdf283656494','念往  其一','王炎','宋','宋诗','song-poetry','','[]','生別有見日，死別無返時。',60,'全唐诗/poet.song.160000.json','["生別有見日，死別無返時。", "綢繆結髮初，百歲以爲期。", "豈意中道間，棄我忽如遺。", "玉骨空委蛻，青山未同歸。", "晤語永已矣，衰懷寧不悲。"]'),
('dc63d8a0-e62d-468f-97c4-d5081787d423','念往  其二','王炎','宋','宋诗','song-poetry','','[]','疇昔鱅溪翁，重爲子相攸。',60,'全唐诗/poet.song.160000.json','["疇昔鱅溪翁，重爲子相攸。", "謂我稍可教，許以相匹儔。", "此德未及報，黄髮歸山邱。", "今又捨我去，垂老增百憂。", "深念不能置，泫然清淚流。"]'),
('74f4c4e8-38bf-40d3-857a-8d6023f14864','念往  其三','王炎','宋','宋诗','song-poetry','','[]','半生共飄泊，所至無定居。',60,'全唐诗/poet.song.160000.json','["半生共飄泊，所至無定居。", "晚有一區宅，乃以喪來歸。", "樂少辛苦多，嗚呼止於斯。", "臨沒尚了了，儆戒皆可書。", "子言不可忘，我意當何如。"]'),
('65b2d912-8a35-48c5-b161-9cbfde4cddde','念往  其四','王炎','宋','宋诗','song-poetry','','[]','有姑共饘粥，有子自抱乳。',60,'全唐诗/poet.song.160000.json','["有姑共饘粥，有子自抱乳。", "人亦有困窮，子獨最艱苦。", "晚歲未即安，此身先逝矣。", "逝者不可作，在者誰與處。", "欲以理奪情，悵然還念起。"]'),
('f3e247b6-a237-463a-bb59-20797e3ce39c','子大有游東山之約以詩相趣因次其韻  其一','王炎','宋','宋诗','song-poetry','','[]','家如錦里先生甫，詩似錢塘處士逋。',32,'全唐诗/poet.song.160000.json','["家如錦里先生甫，詩似錢塘處士逋。", "若解山中安穩住，定勝軟飽卧流蘇。"]'),
('34627ab8-f0d1-4206-9e3d-635ae7b97f49','子大有游東山之約以詩相趣因次其韻  其二','王炎','宋','宋诗','song-poetry','','[]','今昔東山約略同，但無紅袖肯相從。',32,'全唐诗/poet.song.160000.json','["今昔東山約略同，但無紅袖肯相從。", "不妨小試游山屐，因訪騤騤陸士龍。"]'),
('acf5ed7d-a402-4647-9aee-d555d268405a','子大有游東山之約以詩相趣因次其韻  其三','王炎','宋','宋诗','song-poetry','','[]','萬杉深處一軒開，秀色參天費壅培。',32,'全唐诗/poet.song.160000.json','["萬杉深處一軒開，秀色參天費壅培。", "我爲不知林壑趣，黄粱夢覺却歸來。"]'),
('13042394-e0eb-4ce8-9bfc-a15c8c1d41f8','子大有游東山之約以詩相趣因次其韻  其四','王炎','宋','宋诗','song-poetry','','[]','猛省香山及輞川，句中摹寫共流傳。',32,'全唐诗/poet.song.160000.json','["猛省香山及輞川，句中摹寫共流傳。", "煩公檢點遺編看，二老元曾賦幾篇。"]'),
('be730588-a1ca-429b-8446-7f7a317c0029','紙被行','王炎','宋','宋诗','song-poetry','','[]','瑶姬不觸麒麟紅，金壺瀲灧琥珀濃。',272,'全唐诗/poet.song.160000.json','["瑶姬不觸麒麟紅，金壺瀲灧琥珀濃。", "狐裘公子喜夜永，杯行暖玉煩春葱。", "簷頭雪花大如掌，洞房但覺春融融。", "豈知有客方貪睡，漏盡更闌不能寐。", "花紅玉白不相隨，頼有楮生爲伴侶。", "生家住處近麻姑，亦能幻出冰肌膚。", "絕嫌墨客蠅頭污，懶入官黄藏蠹魚。", "寧隨人意任舒卷，雖則軟美非脂韋。", "風姨霜女皆退舍，稍覺和氣生氍毹。", "梅花破雪催寒去，春回人向花前醉。", "女郎霧縠試輕衫，至此失時因坐廢。", "綠槐影底夏日長，人間只要一味涼。", "青奴元自不嫵媚，居然負恃能專房。", "秋風一夜來消息，又却見渠先棄擲。", "冬來復挽楮生歸，屬付蒼頭輕拂拭。", "用則鋪張舍則藏，喜慍未嘗形玉色。", "世事乘除無不然，安用動心三嘆息。"]'),
('37d30dfe-4990-42cc-b6f1-eb30866102f8','京丞相挽詩  其一','王炎','宋','宋诗','song-poetry','','[]','嗣聖登皇極，真儒秉大鈞。',48,'全唐诗/poet.song.160000.json','["嗣聖登皇極，真儒秉大鈞。", "三宮方愷樂，萬宇浸熙淳。", "碧落龍髯去，青山馬鬣新。", "衣冠同墮淚，桃李失陽春。"]'),
('b0e3583b-c471-4c63-a389-e303c28db04b','京丞相挽詩  其二','王炎','宋','宋诗','song-poetry','','[]','山立羣公表，朝廷勢自尊。',48,'全唐诗/poet.song.160000.json','["山立羣公表，朝廷勢自尊。", "遠謀安廟社，厚德鎮乾坤。", "帝念經綸廣，人思色笑溫。", "騎箕今不返，麟閣畫空存。"]'),
('a1bc429b-2822-495d-9f3a-13eaa6db9d20','京丞相挽詩  其三','王炎','宋','宋诗','song-poetry','','[]','鬰鬰松坡上，潭潭甲第成。',48,'全唐诗/poet.song.160000.json','["鬰鬰松坡上，潭潭甲第成。", "家方藏寶墨，地已獻佳城。", "拱極三階動，扶天一柱傾。", "祇應餘慶遠，遺德在蒼生。"]'),
('0215dec9-465d-4164-a7b4-732593a6ecc6','游東山 田舍','王炎','宋','宋诗','song-poetry','','[]','結廬稍近樵牧，豈亦甘心陸沈。',28,'全唐诗/poet.song.160000.json','["結廬稍近樵牧，豈亦甘心陸沈。", "自古明時難遇，未宜長往山林。"]'),
('cda97095-e450-4e29-b7fd-9dfaf962b371','游東山 松風','王炎','宋','宋诗','song-poetry','','[]','松公奮鬣如嘯，終日清風颯然。',28,'全唐诗/poet.song.160000.json','["松公奮鬣如嘯，終日清風颯然。", "佳處元非宮徵，誰能寫入朱絃。"]'),
('4076d693-f0ef-4a17-a570-19de2f5b6d29','游東山 爛柯','王炎','宋','宋诗','song-poetry','','[]','手談一局未了，葉落花紅幾回。',28,'全唐诗/poet.song.160000.json','["手談一局未了，葉落花紅幾回。", "只恐雲迷歸路，不容樵客重來。"]'),
('2e136185-289f-4ef0-b452-f0d78445ab00','游東山 舒嘯','王炎','宋','宋诗','song-poetry','','[]','幽人獨坐空谷，最愛夜深月明。',28,'全唐诗/poet.song.160000.json','["幽人獨坐空谷，最愛夜深月明。", "雲外一聲長嘯，四山木偃風生。"]'),
('f5275db6-bf34-4d1a-8b67-7424246f95b6','游東山 待月','王炎','宋','宋诗','song-poetry','','[]','只有麴生爲侶，夜涼同迓冰輪。',28,'全唐诗/poet.song.160000.json','["只有麴生爲侶，夜涼同迓冰輪。", "未審素娥知否，惟予與影三人。"]'),
('c58aef61-3db9-4e93-8918-347f8df4d8d8','游東山 棧徑','王炎','宋','宋诗','song-poetry','','[]','詰曲羊腸中斷，小安略彴通行。',28,'全唐诗/poet.song.160000.json','["詰曲羊腸中斷，小安略彴通行。", "緩臂不携藜杖，翩翩自喜身輕。"]'),
('d6e49d5b-4fc0-4824-995d-afbe19faecb9','游東山 入翠','王炎','宋','宋诗','song-poetry','','[]','路入半山深處，穿雲竟日忘歸。',28,'全唐诗/poet.song.160000.json','["路入半山深處，穿雲竟日忘歸。", "若扣山中何有，濛濛空翠沾衣。"]'),
('197ba352-d45b-45b2-a638-bff4a451fc14','游東山 磐吉','王炎','宋','宋诗','song-poetry','','[]','客來捧腹一笑，抹月批雲療饑。',28,'全唐诗/poet.song.160000.json','["客來捧腹一笑，抹月批雲療饑。", "只此如何獲吉，爲無富貴危機。"]'),
('27932d90-3257-4680-990b-417142a108d6','游東山 披雲','王炎','宋','宋诗','song-poetry','','[]','上到蒼螭絕頂，四邊無數青山。',28,'全唐诗/poet.song.160000.json','["上到蒼螭絕頂，四邊無數青山。", "下視樓臺一簇，超然身在雲間。"]'),
('301b4bd1-fbdd-4504-b520-eb03b839a011','胡清卿來訪留一日亟求去云欲謁鄭宰因以小詩佐其行','王炎','宋','宋诗','song-poetry','','[]','跋涉山川歲一歸，奚奴古錦慣相隨。',64,'全唐诗/poet.song.160000.json','["跋涉山川歲一歸，奚奴古錦慣相隨。", "自憐機杼無遺巧，却怪珠璣不療饑。", "酌酒挽君澆舌本，解驂許我話心期。", "空囊羞澀將焉往，笑說鳬仙舊見知。"]'),
('79a55ab4-6642-4c02-8022-89f89ba84b94','用元韻答清卿并簡蔡尉','王炎','宋','宋诗','song-poetry','','[]','貂裘半敝復來歸，正坐剛腸不詭隨。',64,'全唐诗/poet.song.160000.json','["貂裘半敝復來歸，正坐剛腸不詭隨。", "見說史君嘗餽贐，似聞內子亦啼饑。", "經年一別方相遇，他日重來未有期。", "試問此行誰借重，梅仙青眼是新知。"]'),
('97e9fd08-0e50-4bd1-a15f-57cd26ffe1f6','次韻謝胡清卿','王炎','宋','宋诗','song-poetry','','[]','殷勤訪我到山中，一笑依然尚諱窮。',64,'全唐诗/poet.song.160000.json','["殷勤訪我到山中，一笑依然尚諱窮。", "氣老絕非年少銳，詩新殊勝舊時工。", "劇談不惜麈尾落，歸路難淹馬首東。", "若遇故人相借問，爲言衰朽學農功。"]'),
('d0283585-a63e-4f49-a94f-263755884876','汪直卿相招以病爽約因成拙句併呈子大','王炎','宋','宋诗','song-poetry','','[]','一聲鶗鴂落紅稀，試問春餘幾許時。',64,'全唐诗/poet.song.160000.json','["一聲鶗鴂落紅稀，試問春餘幾許時。", "多謝佳招頻卜日，自慙衰朽却愆期。", "但能有酒肯留客，莫恨無花空折枝。", "邑下老禪無恙否，可同談笑一開眉。"]'),
('179e6558-6e91-4736-a974-38bb74b1481f','汪直卿相招子大先至有詩炎後至子大再至因次其韻','王炎','宋','宋诗','song-poetry','','[]','笋輿嘔軋度何許，水滿東臯新過雨。',96,'全唐诗/poet.song.160000.json','["笋輿嘔軋度何許，水滿東臯新過雨。", "主人倒屣出門迎，喜氣津津貫眉宇。", "別易會難宜少留，清談絕倒殊不休。", "青衿誦詩勸客飲，客亦歡然爭旅酬。", "向來青鬢今白首，自古交情難耐久。", "從今乘興時一來，請屬細君多釀酒。"]'),
('0ce9c0d8-c7cf-49e6-a446-49e5cc3cbd34','穀雨後一日子大再有詩次其韻','王炎','宋','宋诗','song-poetry','','[]','花氣濃於百和香，郊行緩臂聊翺翔。',96,'全唐诗/poet.song.160000.json','["花氣濃於百和香，郊行緩臂聊翺翔。", "壺中春色自不老，小白淺紅蒙短牆。", "平疇翠浪麥秋近，老農之意方揚揚。", "吾儕飽飯幸無事，日繙芸簡尋遺芳。", "閒中更覺春晝長，酒酣耳熱如清狂。", "自憐藿食徒過計，袖手看人能蹶張。"]'),
('dfa9b7a1-bf07-4356-be42-649bbc154df2','鱅溪行','王炎','宋','宋诗','song-poetry','','[]','小溪一曲山四合，溪邊楊柳藏門闌。',376,'全唐诗/poet.song.160000.json','["小溪一曲山四合，溪邊楊柳藏門闌。", "當時玉人在花下，對花窈窕矜紅顔。", "一雙白璧不可聘，許我結佩乘青鸞。", "我時年少氣方銳，自負落筆翻波瀾。", "謂趁春風上霄漢，可以終老同清歡。", "不知辛苦得一第，始見崎嶇行路難。", "有如萍草無根蒂，二紀流落江湖間。", "莫年通籍入金馬，虎豹嗔人窺九關。", "天邊失脚身墮地，春風破浪扁舟還。", "雲軿未幾舍我去，空委玉骨埋青山。", "重來溪上事皆變，惆悵齊眉難再見。", "王母麻姑安在哉，過眼百年皆露電。", "老身長子恩義深，不爲向來花映面。", "花枝一謝明年開，玉人一去何時回。", "人今不見花亦盡，至此終日空徘徊。", "百川寧有西流水，萬古滔滔同一軌。", "不堪回首細繹思，臨沒之言猶在耳。", "蜀鄉有鳳空求凰，秦樹無烏共將子。", "年來年去春復冬，此生有盡情無窮。", "一泓清淚灑不斷，四山蕭颯來悲風。", "惟有老人老更健，年過九十如霜松。", "尊則吾母舅，親又吾婦翁。", "收淚相勞問，停車少從容。", "悲思無益不自禁，暫時借酒澆心胸。"]'),
('06d79fb3-d151-4f1b-8b34-be0a6c559619','次韻子大四絕  其一','王炎','宋','宋诗','song-poetry','','[]','世路羊腸久憚行，歸來自喜一身輕。',32,'全唐诗/poet.song.160000.json','["世路羊腸久憚行，歸來自喜一身輕。", "故人零落今無幾，獨幸相逢底裏傾。"]'),
('321e0068-95ca-47d5-adbf-10566afb8f9e','次韻子大四絕  其二','王炎','宋','宋诗','song-poetry','','[]','一榻塵埃書滿前，愧無絲竹宴彭宣。',32,'全唐诗/poet.song.160000.json','["一榻塵埃書滿前，愧無絲竹宴彭宣。", "而今又斷功名念，只擬躬耕郭外田。"]'),
('86caeb2e-27f0-4dfe-8808-c588125af451','次韻子大四絕  其三','王炎','宋','宋诗','song-poetry','','[]','抽身幸免坐氈針，鏡裏休憐白髮新。',32,'全唐诗/poet.song.160000.json','["抽身幸免坐氈針，鏡裏休憐白髮新。", "杖屨消摇共來往，更添林下一閒人。"]'),
('0021b390-9175-410a-922f-49eb86e36a22','次韻子大四絕  其四','王炎','宋','宋诗','song-poetry','','[]','主人速客重尋盟，不但郊居氣象清。',32,'全唐诗/poet.song.160000.json','["主人速客重尋盟，不但郊居氣象清。", "家釀滿壺留醉倒，驪駒未可度歌聲。"]'),
('1ee4bc59-02e3-44df-a216-0154a3d423bf','送僧惠日歸蟠龍山','王炎','宋','宋诗','song-poetry','','[]','宴坐團蒲穩，何緣有此行。',48,'全唐诗/poet.song.160000.json','["宴坐團蒲穩，何緣有此行。", "理元無作止，事亦要經營。", "鶴錫尋歸路，龍宮出化城。", "更於文字外，會取法無生。"]'),
('9496275d-1358-465d-b049-693bf3baabbb','秋旱得雨子大詩言祈禱所致炎謂不可貪天之功次韻以見區區','王炎','宋','宋诗','song-poetry','','[]','宦游碌碌本無奇，失脚歸來莫皺眉。',64,'全唐诗/poet.song.160000.json','["宦游碌碌本無奇，失脚歸來莫皺眉。", "只合一廛修穡事，豈堪千騎把州麾。", "旱乾偶得崇朝雨，秋熟應無卒歲饑。", "耕鑿熙熙皆帝力，豐年請爲續周詩。"]'),
('94ff2f27-23be-49ff-974d-7c888661cd40','金夫人挽詩','王炎','宋','宋诗','song-poetry','','[]','兩大家聲著，三從婦德全。',48,'全唐诗/poet.song.160000.json','["兩大家聲著，三從婦德全。", "金珠捐玩飾，蘋藻薦恭虔。", "眉壽無遺恨，心空悟秘詮。", "生芻來奠客，千兩擁新阡。"]'),
('c254cfe8-53ae-4812-af30-3aeacdedaf1e','萬宣教挽詩','王炎','宋','宋诗','song-poetry','','[]','家有青箱學，文名早擅場。',48,'全唐诗/poet.song.160000.json','["家有青箱學，文名早擅場。", "諸公爭汲引，萬里可騰驤。", "豈料才如此，空嗟命不長。", "雲山埋玉樹，松柏倍凄涼。"]'),
('367f03d1-3660-4cda-a45c-6525f81aacc4','汪貴之挽詩','王炎','宋','宋诗','song-poetry','','[]','洗滌膏粱習，熟熏班馬香。',48,'全唐诗/poet.song.160000.json','["洗滌膏粱習，熟熏班馬香。", "吹竽多炫鬻，韞玉獨深藏。", "不作山中相，應爲地下郎。", "一夔家有子，雖沒未云亡。"]'),
('3a3129b1-dd7d-4c0a-9137-6f554c5a0cea','周仁甫挽詩','王炎','宋','宋诗','song-poetry','','[]','人物今難得，如君孰比肩。',48,'全唐诗/poet.song.160000.json','["人物今難得，如君孰比肩。", "干將鋒立斷，神駿氣無前。", "官不過爲縣，天胡嗇與年。", "空聞精爽在，廟食桂江邊。"]'),
('9baf6580-b862-4cab-8bed-e9c5f27c0b11','盧夫人挽詩','王炎','宋','宋诗','song-poetry','','[]','在室從名父，宜家配大賢。',48,'全唐诗/poet.song.160000.json','["在室從名父，宜家配大賢。", "上公調玉鉉，中道失雲軿。", "一品夫人貴，千秋列女傳。", "貂蟬今合窆，恰值白雞年。"]'),
('a05e4ef8-ef2c-4daa-949f-858d7e7338fe','奏事入都出西湖上成四絕  其一','王炎','宋','宋诗','song-poetry','','["\u897f\u6e56"]','呼舟特地度西湖，欲訪山中幽子居。',32,'全唐诗/poet.song.160000.json','["呼舟特地度西湖，欲訪山中幽子居。", "山色湖光渾似舊，人間萬事有乘除。"]'),
('d57371d5-46fa-4344-ad52-b92d6ff161fd','奏事入都出西湖上成四絕  其二','王炎','宋','宋诗','song-poetry','','["\u897f\u6e56"]','羽衣引我度松關，借得湖山一眼看。',32,'全唐诗/poet.song.160000.json','["羽衣引我度松關，借得湖山一眼看。", "去棹來橈皆物役，箇中惟有白鷗閒。"]'),
('9df5839e-3101-4e26-ab51-926c3e4a974f','奏事入都出西湖上成四絕  其三','王炎','宋','宋诗','song-poetry','','["\u897f\u6e56"]','花驄油壁隠輕雷，消却冰山不復來。',32,'全唐诗/poet.song.160000.json','["花驄油壁隠輕雷，消却冰山不復來。", "墳土未乾爲餒鬼，園花雖好爲誰開。"]'),
('4dc42c26-ec16-4eec-a5c7-44018772fbb0','奏事入都出西湖上成四絕  其四','王炎','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鼎新堂殿鬰嵯峩，中有方袍千指多。',32,'全唐诗/poet.song.160000.json','["鼎新堂殿鬰嵯峩，中有方袍千指多。", "未審雪山黄面老，樹邊一宿意如何。"]'),
('4bbcdc35-ed1f-47b0-bda7-a10566d2c201','招諸宰飯六客堂以小詩代折簡','王炎','宋','宋诗','song-poetry','','[]','雙袖日沾朱墨塵，風流那復似前人。',32,'全唐诗/poet.song.160000.json','["雙袖日沾朱墨塵，風流那復似前人。", "梅花香裏傾杯酒，略與鳬仙一探春。"]'),
('6642f6b1-052a-4a8e-8663-c221938385fd','通守趙侯改倅會稽以詩餞行','王炎','宋','宋诗','song-poetry','','[]','我來席未溫，君去袂難摻。',108,'全唐诗/poet.song.160000.json','["我來席未溫，君去袂難摻。", "所喜相知新，所恨相見晚。", "吏能極縝密，風度乃蕭散。", "同僚有斯人，可近不可遠。", "漕渠新漲生，輦路春風滿。", "置之緹屏中，驥足終未展。", "夫豈無裏言，相與共推輓。", "語別一杯酒，何時對青眼。", "願保千金軀，努力加餐飯。"]'),
('a14f29ec-0654-4cb1-b365-c517e78de23a','勸農道場山','王炎','宋','宋诗','song-poetry','','[]','練日遵詔條，行春勸耕事。',120,'全唐诗/poet.song.160000.json','["練日遵詔條，行春勸耕事。", "擁旆有傳呼，據鞍小馳騖。", "兒童競聚觀，父老歡來詣。", "松徑度坡陀，蓮宮得清閟。", "此行非遨遊，所職在撫字。", "示之淺易語，諭以丁寧意。", "扶杖既言歸，解衣聊少憇。", "山中無俗情，物外有幽趣。", "僧閒衆所羨，農困吾甚愧。", "不敢飽登臨，肩輿下山去。"]'),
('f9fd677e-ddfa-4c63-9a10-b8903c51fced','招魏倅項教授小飲','王炎','宋','宋诗','song-poetry','','[]','菖葉青青初出水，布穀聲中耕事起。',128,'全唐诗/poet.song.160000.json','["菖葉青青初出水，布穀聲中耕事起。", "去年蝗旱傷農收，今年日望歲豐美。", "聞道郊原麥浪平，但慮飛蝗遺孽耳。", "甚欲往來阡陌間，稍與田家共憂喜。", "老大心情畏忌多，攬轡未行還自止。", "假日公庭吏牘稀，祇可清談共揮麈。", "小園春色亦自都，醉日杏桃嬌欲語。", "舉杯相屬謝東風，莫待枝頭落紅雨。"]'),
('237d10f0-3d73-4ee4-b637-567e4d342403','用前韻酬魏倅','王炎','宋','宋诗','song-poetry','','[]','手把一麾來霅水，身似痿人方暫起。',128,'全唐诗/poet.song.160000.json','["手把一麾來霅水，身似痿人方暫起。", "此行本爲貧所驅，非戀吳中風土美。", "浩蕩煙波隔白鷗，間關道路勞黄耳。", "幸而別駕有詩流，相逢眉睫津津喜。", "我今白首君黑頭，莫訝鐘鳴不知止。", "每因揖客愁下榻，豈暇談玄頻捉麈。", "忙裏偷閒花下飲，更約廣文同笑語。", "把酒消憂憂更來，見說東臯今渴雨。"]'),
('f8aa5bae-ae82-4730-91a2-af8906ec8f50','夜半聞雨再用前韻','王炎','宋','宋诗','song-poetry','','[]','轆轤百尺汲無水，映日四山雲不起。',128,'全唐诗/poet.song.160000.json','["轆轤百尺汲無水，映日四山雲不起。", "朱轓浪說勸農桑，衣食何從可甘美。", "禱而得雨不苦旱，竊疑此殆偶然爾。", "夜半潺潺簷溜鳴，孤枕夢回心失喜。", "兒童挽犢婦餉饁，襏襫耕夫亦勤止。", "鼠跡印我榻上書，蛛絲罥我壁間麈。", "抖擻胸中三斗塵，强欲吟哦無好語。", "請公酌酒更揮毫，快寫珠璣歌喜雨。"]'),
('ab14ce52-9c7f-4d63-b7bf-06707f74ebfc','魏倅同杜仲高游黄龍洞次韻','王炎','宋','宋诗','song-poetry','','[]','風流別駕臨苕溪，行厨携客尋幽奇。',80,'全唐诗/poet.song.160000.json','["風流別駕臨苕溪，行厨携客尋幽奇。", "五湖浩蕩三江永，綠浄不知凡幾頃。", "憑高縱望心目開，便可一傾三百杯。", "疑與塵寰不同宇，彈壓風光須妙語。", "只恐揮毫驚蟄龍，金相玉質音玲瓏。"]'),
('f23908d3-3410-4c5f-862a-38b7be244ff2','郡中游觀之地清風樓爲第一前此諸公有詩似覺摹寫未盡輒成唐律一篇約魏倅同賦不拘和韻可也','王炎','宋','宋诗','song-poetry','','[]','山屏四面碧相重，苕霅無聲瀉玉虹。',64,'全唐诗/poet.song.160000.json','["山屏四面碧相重，苕霅無聲瀉玉虹。", "萬戶連甍皆在下，一樓飛棟獨當中。", "不容半點浮塵到，但覺無邊爽氣通。", "安得翛然辭物役，披襟終日挹清風。"]'),
('50fa9287-c856-43e8-b2e8-8dc5505c23c8','和項廣文喜雨','王炎','宋','宋诗','song-poetry','','[]','雨師雲將莫論功，天意元因聖德通。',64,'全唐诗/poet.song.160000.json','["雨師雲將莫論功，天意元因聖德通。", "不但水生苗厭厭，也應土潤黍芃芃。", "田間老稚交相語，秋後倉箱定不空。", "絳帳先生妙言語，請歌嘉定比元豐。"]'),
('35a60b61-5457-4bd9-a6ef-e58e935d680c','與魏倅葛書記同謝雨于黄龍洞回憩小玲瓏晚飯魏倅有詩次其韻','王炎','宋','宋诗','song-poetry','','[]','政術平生欠講明，頼公關决可蒙成。',64,'全唐诗/poet.song.160000.json','["政術平生欠講明，頼公關决可蒙成。", "食新雖有豐登望，闔郡寧無嘆息聲。", "因爲賽神携一榼，暫能擇勝駐雙旌。", "歸來依舊塵勞在，不盡逍遥物外情。"]'),
('67612b42-14dc-4f38-bc77-a8682ab42e4d','苦脾泄在告因飲白酒一杯小愈魏倅有詩已而病復作因次韻見意','王炎','宋','宋诗','song-poetry','','[]','羸老畏風濕，河魚將奈何。',72,'全唐诗/poet.song.160000.json','["羸老畏風濕，河魚將奈何。", "玉友豈不佳，終難護天和。", "數息謾吐納，鍊形空按摩。", "自笑來日短，殘漏鳴銅荷。", "吏事如衣垢，濯之費挼挲。", "養痾諒非宜，山林歸興多。"]'),
('26219f32-ccfc-484a-8df6-d17a856a5fbf','賀皇太子生辰  其一','王炎','宋','宋诗','song-poetry','','[]','鳳姿日表極高明，講習詩書若性成。',64,'全唐诗/poet.song.160000.json','["鳳姿日表極高明，講習詩書若性成。", "參決萬機裨獨斷，力行三善答輿情。", "綺園何必來爲助，啟誦安能更擅名。", "日侍兩宮慈孝洽，萬年主鬯共安榮。"]'),
('b6291a74-c857-49a9-80c6-7531799dbb16','賀皇太子生辰  其二','王炎','宋','宋诗','song-poetry','','[]','鬰葱佳氣擁天庭，申命無疆啟震亨。',64,'全唐诗/poet.song.160000.json','["鬰葱佳氣擁天庭，申命無疆啟震亨。", "少海永重瀛海潤，前星長拱極星明。", "螭旗色轉秋風爽，雞戟光凝曉月清。", "遥想宮僚斟玉斝，進趨無地倍馳情。"]'),
('5cf384c5-f09d-4ecc-ab1e-acf5170ea77e','題歸鴈亭','王炎','宋','宋诗','song-poetry','','[]','江湖冰泮草生時，鴻鴈南來又北歸。',32,'全唐诗/poet.song.160000.json','["江湖冰泮草生時，鴻鴈南來又北歸。", "莫謾說歸歸不早，青雲高處有危機。"]'),
('b18499ba-28ef-48c9-9573-ad8fcbbae5ba','題白蘋亭','王炎','宋','宋诗','song-poetry','','[]','得句柳刺史，築亭顔魯公。',48,'全唐诗/poet.song.160000.json','["得句柳刺史，築亭顔魯公。", "二賢雖異代，千古有遺風。", "苕水永不盡，蘋洲今半空。", "老懷多感慨，訪古意無窮。"]'),
('5bc1aade-f294-4594-8ed7-7180cd696660','題碧瀾亭','王炎','宋','宋诗','song-poetry','','[]','一色挼藍染碧流，翬飛恰對白蘋洲。',64,'全唐诗/poet.song.160000.json','["一色挼藍染碧流，翬飛恰對白蘋洲。", "風清六月非朱夏，氣爽三時似素秋。", "自笑品題無翰墨，也知領略欠觥籌。", "鳬鷗定怪霜髯叟，難洗胸中萬古愁。"]'),
('2354f222-d0cb-4d26-ac99-8593884b2ef1','六客堂','王炎','宋','宋诗','song-poetry','','[]','一樽相屬更何人，六客當年事已陳。',64,'全唐诗/poet.song.160000.json','["一樽相屬更何人，六客當年事已陳。", "扁榜特書名尚在，篇章深刻字猶新。", "關心吏事方窮日，企踵前賢分絕塵。", "涉筆符移憂百謫，偷閒來此一嚬呻。"]'),
('e2a3fe89-dff4-42c5-94b4-c656c3daf24a','生日魏倅惠三詩  其一','王炎','宋','宋诗','song-poetry','','[]','四海眼獨高，江湖走蹣跚。',48,'全唐诗/poet.song.160000.json','["四海眼獨高，江湖走蹣跚。", "帝念風霜飽，命之官仙班。", "刺天紛羣飛，政爾衮衮難。", "鹿挾朱輪去，勇哉支狂瀾。"]'),
('70631e85-ac18-401b-b4eb-6c011d0917e7','生日魏倅惠三詩  其二','王炎','宋','宋诗','song-poetry','','[]','作州豈無人，孰別涇與渭。',48,'全唐诗/poet.song.160000.json','["作州豈無人，孰別涇與渭。", "仰止雲溪老，靜處酌古味。", "庭戶令無譁，晝閒棠蔽芾。", "吳儂了不知，但說物吐氣。"]'),
('0f35f002-c112-4e7f-bd42-93a695ae7990','生日魏倅惠三詩  其三','王炎','宋','宋诗','song-poetry','','[]','門左何煙霧，挾將小春還。',48,'全唐诗/poet.song.160000.json','["門左何煙霧，挾將小春還。", "千鍾酒拍浮，一笑衣斕斑。", "醉上樓百尺，可仰不可攀。", "定應切星辰，天風吹酡顔。"]'),
('e4ce87f2-5c30-43ea-8278-4f42b863511b','酬俞子清侍郎惠畫韻  其一','王炎','宋','宋诗','song-poetry','','[]','筆端元有畫中詩，寫出三浯一段奇。',32,'全唐诗/poet.song.160000.json','["筆端元有畫中詩，寫出三浯一段奇。", "追憶舊游如昨日，艤舟細看中興碑。"]'),
('7c742b64-e990-4c5b-991c-ac779a0f568e','酬俞子清侍郎惠畫韻  其二','王炎','宋','宋诗','song-poetry','','[]','一去星沙二十年，夢魂時到橘洲邊。',32,'全唐诗/poet.song.160000.json','["一去星沙二十年，夢魂時到橘洲邊。", "從今不起南征念，移得湘山在目前。"]'),
('568cb0c1-62b1-4cf5-9687-e88d59ebe338','送蓬庵梵老  其一','王炎','宋','宋诗','song-poetry','','[]','緩行聊復倩人扶，炯炯精神兩碧矑。',32,'全唐诗/poet.song.160000.json','["緩行聊復倩人扶，炯炯精神兩碧矑。", "落筆語言清透骨，恐公胸次有冰壺。"]'),
('c0287363-1920-4428-874a-d342bfede9c0','送蓬庵梵老  其二','王炎','宋','宋诗','song-poetry','','[]','爲我衝寒特地來，扁舟興盡又須回。',32,'全唐诗/poet.song.160000.json','["爲我衝寒特地來，扁舟興盡又須回。", "相思若要問消息，早寄一枝牆角梅。"]'),
('c2d02577-3db4-42fe-8af6-2b79b4bb040b','梵老以小詩爲壽和韻答之','王炎','宋','宋诗','song-poetry','','[]','不問鸞驂鶴駕仙，且游無色界中天。',32,'全唐诗/poet.song.160000.json','["不問鸞驂鶴駕仙，且游無色界中天。", "更煩辦取詩千首，一歲從公索一聯。"]'),
('bba17616-9eb9-4ee1-9879-024415029d1b','呈游大冶','王炎','宋','宋诗','song-poetry','','[]','昔在桃溪少壯時，而今衰颯鬢成絲。',32,'全唐诗/poet.song.160000.json','["昔在桃溪少壯時，而今衰颯鬢成絲。", "悲歡三十年中事，付與寒窗酒一鴟。"]'),
('be892e54-c3bd-4f77-ace8-b215a322ec26','送游大冶歸建陽','王炎','宋','宋诗','song-poetry','','[]','震澤黄柑熟，苕溪紫蟹肥。',48,'全唐诗/poet.song.160000.json','["震澤黄柑熟，苕溪紫蟹肥。", "天寒留客舍，歲晚念親闈。", "抱負須時用，行藏與志違。", "臨分話情愫，衰謝亦謀歸。"]'),
('c85f3eff-423c-4208-8cda-0986ae3ae16f','魏倅和銛老一詩因次其韻','王炎','宋','宋诗','song-poetry','','[]','俯爲生靈與虜和，君王何忍憤揮戈。',64,'全唐诗/poet.song.160000.json','["俯爲生靈與虜和，君王何忍憤揮戈。", "信行塞外還交聘，人在軍中可雅歌。", "金帛莫嫌今重費，丁黄將見歲加多。", "漢淮千里惟青草，乘此屯田可就麽。"]'),
('b7fcbeab-bc07-41ec-ac4c-6699a35131d1','趙處州挽詩  其一','王炎','宋','宋诗','song-poetry','','[]','秀邸多英俊，惟公最有聲。',48,'全唐诗/poet.song.160000.json','["秀邸多英俊，惟公最有聲。", "君陳兼孝友，子政極忠精。", "白璧千金價，青雲萬里程。", "皇天無老眼，名位止專城。"]'),
('4216151b-96c7-4434-8de6-c11e6ebd6c43','趙處州挽詩  其二','王炎','宋','宋诗','song-poetry','','[]','白首來苕霅，深知有故人。',48,'全唐诗/poet.song.160000.json','["白首來苕霅，深知有故人。", "登門雖不數，傾蓋本相親。", "浮鷁行方遠，烹魚墨尚新。", "青山埋玉樹，老淚漫沾巾。"]'),
('421c6d54-7678-4227-8dd8-04d960c701f0','題墨妙亭','王炎','宋','宋诗','song-poetry','','[]','晉唐行草可同科，樂石雕鎸便不磨。',64,'全唐诗/poet.song.160000.json','["晉唐行草可同科，樂石雕鎸便不磨。", "幾載雨淋兼日炙，一朝雲集又星羅。", "要知訪古搜求盡，應爲凝香暇逸多。", "瀟灑高懷堪健羨，簿書堆案意如何。"]'),
('c97c1c31-8ae4-4c29-a265-d5a9f3ba8ee4','送魏倅','王炎','宋','宋诗','song-poetry','','[]','俗士不聞道，利欲熏其心。',228,'全唐诗/poet.song.160000.json','["俗士不聞道，利欲熏其心。", "陽浮外酬酢，中有機穽深。", "宛陵有君子，殊不同今人。", "矯矯鵷鷺姿，入俗不受塵。", "挹之淡於水，即之暖如春。", "筆端奏金石，妙處無新陳。", "念我久頓挫，晚歲乘朱輪。", "烹鮮易以擾，御黠難使馴。", "頼有賢貳車，一心同撫循。", "遂於吏事外，拂拭綠綺琴。", "爲我肯屬耳，領會山水音。", "持此定交契，愈久情愈親。", "東風二月初，梅花照溪津。", "語別一杯酒，莫辭十分斟。", "聚散亦常事，豈必含酸辛。", "重念髮種種，不禁憂患侵。", "君今入觀闕，我亦返山林。", "行藏異塗轍，何日再盍簪。", "所藴勿卷懷，朝廷須世臣。"]'),
('ab54a41e-df1f-4f79-b1f8-b2ee49efd339','二月望日留越上偶成','王炎','宋','宋诗','song-poetry','','[]','擺脫軒裳累，此身今自由。',48,'全唐诗/poet.song.160000.json','["擺脫軒裳累，此身今自由。", "餘生能有幾，外物已無求。", "婺水自堪隠，稽山姑少留。", "千岩并萬壑，春暖一遨遊。"]'),
('797157a0-af25-4b27-98b9-ca783d51bacf','謁告成廟','王炎','宋','宋诗','song-poetry','','[]','玉帛何年會，衣冠此地藏。',48,'全唐诗/poet.song.160000.json','["玉帛何年會，衣冠此地藏。", "物存惟窆石，神變失梅梁。", "並海山川盡，踰河道路長。", "六臣陪廟食，千古共烝嘗。"]'),
('0273a2d3-e052-489c-b24e-41cf77e46140','游稽山','王炎','宋','宋诗','song-poetry','','[]','失脚來苕霅，春風一棹還。',48,'全唐诗/poet.song.160000.json','["失脚來苕霅，春風一棹還。", "尋幽探禹穴，問訊到稽山。", "意在煙霞外，身居井邑間。", "桃花應冷笑，頭白不能閒。"]'),
('753df3c5-4e69-48eb-960b-52c678ad0505','題大禹廟','王炎','宋','宋诗','song-poetry','','[]','夏后南巡地，登臨一慨然。',48,'全唐诗/poet.song.160000.json','["夏后南巡地，登臨一慨然。", "卑宮今造寺，菲飲孰名泉。", "古道知難復，人情信誤傳。", "不隨時俗改，惟有舊山川。"]'),
('4cb98ce6-b3cb-4535-8e53-3f94f2f7e087','鑑湖','王炎','宋','宋诗','song-poetry','','[]','粼粼萬頃碧玻璃，今日耕鋤半稻畦。',32,'全唐诗/poet.song.160000.json','["粼粼萬頃碧玻璃，今日耕鋤半稻畦。", "菡萏開時還自好，買舟一醉玉東西。"]'),
('3afdc718-b2a6-48e8-a17f-5dcca6e357e8','二月中休日黄帥領客登望海亭有詩因次其韻','王炎','宋','宋诗','song-poetry','','[]','翬飛棟宇壓危峰，面面風光入座中。',64,'全唐诗/poet.song.160000.json','["翬飛棟宇壓危峰，面面風光入座中。", "潮汐近通天闕下，蓬瀛疑在海門東。", "巡行誰說秦皇事，疏鑿今餘夏后功。", "空闊無邊惟此地，君侯心與境相同。"]'),
('6e25ea65-e908-4870-966c-a9b69c454db6','追悼昭叔弟','王炎','宋','宋诗','song-poetry','','[]','老去無他念，追懷手足親。',48,'全唐诗/poet.song.160000.json','["老去無他念，追懷手足親。", "學成雖漫仕，客處只長貧。", "在昔爲三友，如今少一人。", "青山未歸窆，回首獨傷神。"]'),
('da226fe7-a5fb-4acb-9d94-3e6db4093b27','贈岩電道人','王炎','宋','宋诗','song-poetry','','[]','胸次有藻鑑，聲行朝野間。',48,'全唐诗/poet.song.160000.json','["胸次有藻鑑，聲行朝野間。", "我來勾踐國，君住少微山。", "青眼肯相顧，白頭今得閒。", "窮通無可問，歸去掩雲關。"]'),
('7550195f-734a-4a4e-968f-cdf62279ba17','賀監宅','王炎','宋','宋诗','song-poetry','','[]','輕解金龜呼酒徒，却問君王求鑑湖。',64,'全唐诗/poet.song.160000.json','["輕解金龜呼酒徒，却問君王求鑑湖。", "歸來蹁躚著鶴氅，自辦米帛供妻孥。", "鸞驂一去杳無跡，數畝荒園生草棘。", "惟有青青秦望山，曾識湖邊老狂客。"]'),
('bd668e5b-66a8-49ad-b693-3aaac3446d7f','游景德','王炎','宋','宋诗','song-poetry','','[]','老怯鶑花笑，春殘一出游。',48,'全唐诗/poet.song.160000.json','["老怯鶑花笑，春殘一出游。", "城隅尋古寺，柳下繫扁舟。", "身健聊乘興，心閒不著愁。", "支郎能款語，清坐小遲留。"]'),
('e62c7596-64f6-43fa-a63c-cee15b79af3e','即事','王炎','宋','宋诗','song-poetry','','[]','故里只十舍，滯留猶未歸。',48,'全唐诗/poet.song.160000.json','["故里只十舍，滯留猶未歸。", "湖山無此好，父子且相依。", "白璧難磨玷，黄間暗發機。", "平生丘壑在，一笑釋前非。"]'),
('ecb34346-78bd-4bdc-ad07-13bf789cebf0','麝香萱草','王炎','宋','宋诗','song-poetry','','[]','穠綠叢中出嫩黄，折來時吐麝臍香。',32,'全唐诗/poet.song.160000.json','["穠綠叢中出嫩黄，折來時吐麝臍香。", "朝開夕謝休惆悵，我已無憂不待忘。"]'),
('2d4a1f62-b4c6-481d-b0cd-c3924ede0a73','寄潘維節','王炎','宋','宋诗','song-poetry','','[]','黑貂裘敝君窮甚，黄犬書來我慨然。',32,'全唐诗/poet.song.160000.json','["黑貂裘敝君窮甚，黄犬書來我慨然。", "肯到越中同住否，秋深即上歙溪船。"]'),
('89b3603d-2a21-43d1-abf3-8a05fd40c9e4','兩鶴','王炎','宋','宋诗','song-poetry','','[]','仙家墮下兩麒麟，寄食庭除未易馴。',64,'全唐诗/poet.song.160000.json','["仙家墮下兩麒麟，寄食庭除未易馴。", "正爲白頭違世路，要須丹頂伴閒身。", "高飛橫絕心雖在，短舞婆娑意亦真。", "同返故山依蕙帳，莫思三島十洲春。"]'),
('b3dafd0f-a508-4bc1-8b62-88ff40886742','食楞梅','王炎','宋','宋诗','song-poetry','','[]','是處楊家果，求如此種難。',48,'全唐诗/poet.song.160000.json','["是處楊家果，求如此種難。", "色深渾是紫，味美更無酸。", "磊磊堆盤潤，津津遶齒寒。", "品高何以辨，但把一楞看。"]'),
('681dca7f-128d-46cd-9f09-295b08ba8bd1','會稽六月初五日新米入市價減舊以升計之几十二三聞海商米船方集亦損其直','王炎','宋','宋诗','song-poetry','','[]','大侵難宿飽，小熟有晨炊。',48,'全唐诗/poet.song.160000.json','["大侵難宿飽，小熟有晨炊。", "歲事早如此，人情喜可知。", "田家甘糶賤，海賈恨來遲。", "粒粒皆珠玉，無忘餓殍時。"]'),
('bb2e31b7-bdff-4cef-9b76-45ece7be2255','七月二十二日遣懷','王炎','宋','宋诗','song-poetry','','[]','寥落求凰鳳，凄涼舐犢牛。',48,'全唐诗/poet.song.160000.json','["寥落求凰鳳，凄涼舐犢牛。", "有時追往事，無處著清愁。", "世故今猶古，年華春復秋。", "西風乘一舸，歸去理菟裘。"]'),
('5aa8e6a8-14c7-42af-8a33-7f8977e9b0e4','二十五日聞德瑩弟訃音越三日悲不能禁以小詩自解','王炎','宋','宋诗','song-poetry','','[]','我以官爲累，君因病得衰。',48,'全唐诗/poet.song.160000.json','["我以官爲累，君因病得衰。", "豈知成永訣，不及待歸期。", "遣至書來疾，賫回藥去遲。", "餘生來日短，終不免深悲。"]'),
('a70922c8-c5d9-43bf-b076-9fe38d40d1c9','病中書懷','王炎','宋','宋诗','song-poetry','','[]','秦望山光翠欲流，荷花落盡鑑湖秋。',32,'全唐诗/poet.song.160000.json','["秦望山光翠欲流，荷花落盡鑑湖秋。", "不堪衰病歸心切，難爲湖山更少留。"]'),
('f8930b30-df0f-4900-a3d6-84cf9190ea04','病中恕子投劾同歸','王炎','宋','宋诗','song-poetry','','[]','蕭蕭華髮更何爲，元是窮鄉一布衣。',64,'全唐诗/poet.song.160000.json','["蕭蕭華髮更何爲，元是窮鄉一布衣。", "同産弟兄誰見在，餘生父子獨相依。", "我緣多病念家切，汝爲愛親投劾歸。", "出處不齊難逆定，時來還自刺天飛。"]'),
('a512543f-2e00-453f-8463-d530594c893b','西興阻風','王炎','宋','宋诗','song-poetry','','[]','小市西興渡，年來一再行。',48,'全唐诗/poet.song.160000.json','["小市西興渡，年來一再行。", "花開方淑景，木落又寒聲。", "雲破日還晦，潮回江未平。", "壯年曾試險，遲莫敢輕生。"]'),
('5f606676-3ce2-4d08-9428-c549d9ea81da','江亭曉望','王炎','宋','宋诗','song-poetry','','[]','天在空濛外，山橫杳靄中。',48,'全唐诗/poet.song.160000.json','["天在空濛外，山橫杳靄中。", "潮翻江水白，日射海霞紅。", "旅食思鄉社，歸舟待便風。", "老懷誰共語，注目送飛鴻。"]'),
('fa570460-ef01-425c-8bfe-184362b86e2a','夜宿閔灘下','王炎','宋','宋诗','song-poetry','','[]','歙江兩岸山立壁，一水潭潭浮紺碧。',96,'全唐诗/poet.song.160000.json','["歙江兩岸山立壁，一水潭潭浮紺碧。", "嵌空老石出中流，觸碎玻璃成沸白。", "灘高水落定難行，莫雨淋浪新漲生。", "三更風怒山欲吼，催喚金烏回曉晴。", "篙工倚柂笑相語，但上閔灘無所阻。", "明日日晡過歙渚，艤船沽酒勞辛苦。"]'),
('5f5eb09c-68a2-4cb9-a4d7-d599f33361b6','將使送玉堂春花江南竹笋次韻二絕  其一','王炎','宋','宋诗','song-poetry','','[]','小白長紅盡絕塵，不將朱粉污天真。',32,'全唐诗/poet.song.160000.json','["小白長紅盡絕塵，不將朱粉污天真。", "應憐三畝荒涼地，乞與鰲扉一種春。"]'),
('6c00886b-9eb1-4ce0-a4dd-77f1b11d5fbe','將使送玉堂春花江南竹笋次韻二絕  其二','王炎','宋','宋诗','song-poetry','','[]','此君長得籜龍兒，不爲供人口腹資。',32,'全唐诗/poet.song.160000.json','["此君長得籜龍兒，不爲供人口腹資。", "養就翠梢如結實，來儀當有鳳師師。"]'),
('22f255db-79b6-464e-bb04-6de2480e5a48','題詹氏佚老堂','王炎','宋','宋诗','song-poetry','','[]','矍鑠精神鬢未斑，翛然清坐對雲山。',32,'全唐诗/poet.song.160000.json','["矍鑠精神鬢未斑，翛然清坐對雲山。", "兒孫滿眼生涯足，贏得壺中日月閒。"]'),
('e9107065-5042-4cb6-871d-22db0b2a1ed1','凶年慨然嘆久生成贅因以長句述此意','王炎','宋','宋诗','song-poetry','','[]','頻歲田家苦旱蝗，劇思小稔活丁黄。',64,'全唐诗/poet.song.160000.json','["頻歲田家苦旱蝗，劇思小稔活丁黄。", "稻粳久渴三秋雨，菽麥俄經一夜霜。", "未保溝中無殍死，已聞道上有流亡。", "白頭屏處山林下，只怕羣偷慣奪攘。"]'),
('08de072e-1d91-4274-8d95-8ecae7067a85','落花','王炎','宋','宋诗','song-poetry','','[]','小園數樹雜花開，零落無聲覆綠苔。',32,'全唐诗/poet.song.160000.json','["小園數樹雜花開，零落無聲覆綠苔。", "休恨五更風雨急，明年春色自歸來。"]'),
('dfb2c53e-3e82-42ce-8e70-23a83e32fcf7','春日苦雨','王炎','宋','宋诗','song-poetry','','[]','桃花開時苦多雨，花似啼粧悄無語。',96,'全唐诗/poet.song.160000.json','["桃花開時苦多雨，花似啼粧悄無語。", "桃花謝時雨更多，奈此輕紅委地何。", "明年花似今年好，明年人勝今年老。", "是誰留得長少年，對此不須空懊惱。", "雙飛燕子營新巢，舍後舍前穠綠交。", "長鬚但爲釀麴米，春色尚餘紅藥梢。"]'),
('e5c374e1-6a44-4f02-8f84-8e10a41d3afd','密室','王炎','宋','宋诗','song-poetry','','[]','密室可附火，小窗聊借明。',48,'全唐诗/poet.song.160000.json','["密室可附火，小窗聊借明。", "風寒皆不到，溫飽更何營。", "省事事自少，養心心亦清。", "床頭猶有易，座右不須銘。"]'),
('7035a7ba-e8e4-4a95-b73f-c4ef0dea2df7','久雨而雪','王炎','宋','宋诗','song-poetry','','[]','兩港水爭長，四山雲未歸。',48,'全唐诗/poet.song.160000.json','["兩港水爭長，四山雲未歸。", "忽聞雷虺虺，翻見雪霏霏。", "蠟屐老難出，竹爐誰共圍。", "金烏無恙否，何事隠明暉。"]'),
('d2f82889-a652-4c54-baf0-96754a2a00b3','清明日先塋掛楮錢','王炎','宋','宋诗','song-poetry','','[]','昔人最重去墳墓，絕喜歸來老一邱。',64,'全唐诗/poet.song.160000.json','["昔人最重去墳墓，絕喜歸來老一邱。", "豈是他山無笋蕨，只緣故國有松楸。", "百年暫住人間世，千古俱爲地下游。", "色境悲歡雖夢事，楮錢聊掛樹梢頭。"]'),
('7411238d-c121-41a5-9ea0-85b498431202','將使有詩許移厨雙溪次其韻  其一','王炎','宋','宋诗','song-poetry','','[]','艤舟柳岸載清尊，招我花邊一賞春。',32,'全唐诗/poet.song.160000.json','["艤舟柳岸載清尊，招我花邊一賞春。", "莫笑看花人已老，白頭曾是少年人。"]'),
('3dfc9976-e34d-428e-90f8-ece15212fb6a','將使有詩許移厨雙溪次其韻  其二','王炎','宋','宋诗','song-poetry','','[]','石上漥尊可置杯，石邊更可著浯臺。',32,'全唐诗/poet.song.160000.json','["石上漥尊可置杯，石邊更可著浯臺。", "旁人不識溪山趣，將謂尋春特地來。"]'),
('a2633f2e-fb26-476d-ae5f-50bad6a53ddf','將使有詩許移厨雙溪次其韻  其三','王炎','宋','宋诗','song-poetry','','[]','莫春天氣漸清和，枝上紅稀地上多。',32,'全唐诗/poet.song.160000.json','["莫春天氣漸清和，枝上紅稀地上多。", "惟有松筠四時好，風枝雨葉綠婆娑。"]'),
('8cf745f6-4d57-403f-a8ff-9036f71ca3b0','新晴','王炎','宋','宋诗','song-poetry','','[]','度臘殊多雨，開年亦未晴。',48,'全唐诗/poet.song.160000.json','["度臘殊多雨，開年亦未晴。", "地卑常礎潤，月墮忽霜明。", "茅舍煙猶濕，秧疇水可耕。", "幽花并細草，隨意也欣榮。"]'),
('d96c24c3-4934-4689-b088-0ad2bca017fa','和董叔重韻','王炎','宋','宋诗','song-poetry','','[]','秀色驚老眼，見此千丈松。',48,'全唐诗/poet.song.160000.json','["秀色驚老眼，見此千丈松。", "門如翟廷尉，人愧王沂公。", "驪珠損佳惠，衰遲豈宜蒙。", "三復不能已，一室生清風。"]'),
('a9ed46dc-cd99-4d74-bc2a-ce0a1d7a2467','題黄元靜廣先樓','王炎','宋','宋诗','song-poetry','','[]','聞道樓居好，翬飛百尺餘。',48,'全唐诗/poet.song.160000.json','["聞道樓居好，翬飛百尺餘。", "箕裘能襲舊，丹雘遂如初。", "生理萬鍾粟，義方千卷書。", "家聲將益大，車馬炫門閭。"]'),
('e2c6102f-fe77-4733-a66c-688d8ed743ef','社日','王炎','宋','宋诗','song-poetry','','[]','日暖泥融燕子飛，海棠深淺注臙脂。',32,'全唐诗/poet.song.160000.json','["日暖泥融燕子飛，海棠深淺注臙脂。", "一杯社日治聾酒，報答春光爛漫時。"]'),
('c1f1a994-4412-40f3-b0bb-20cee9c8843b','喜晴  其一','王炎','宋','宋诗','song-poetry','','[]','雨過千畦䆉䅉黄，趁晴刈穫可登場。',32,'全唐诗/poet.song.160000.json','["雨過千畦䆉䅉黄，趁晴刈穫可登場。", "田家子婦開眉語，白粲新炊滿屋香。"]'),
('5ad6f138-a885-4af9-83d9-abe6d3d3fb77','喜晴  其二','王炎','宋','宋诗','song-poetry','','[]','雨過兒童飽飯牛，趁晴耕墾種來牟。',32,'全唐诗/poet.song.160000.json','["雨過兒童飽飯牛，趁晴耕墾種來牟。", "田家作苦無儲蓄，待哺全須麥有秋。"]'),
('2e80c7a3-5e18-4f32-9563-858fa762dec0','舟行到滿塘','王炎','宋','宋诗','song-poetry','','[]','蘋花雙港靜，蓮葉一舟輕。',48,'全唐诗/poet.song.160000.json','["蘋花雙港靜，蓮葉一舟輕。", "白石波間走，青山路外行。", "鯈魚方自樂，鷗鳥不須驚。", "擁鼻蓬窗底，翛然午吹生。"]'),
('ecc7649f-51d9-4a0d-8af2-e94bed82ca4e','秋夜','王炎','宋','宋诗','song-poetry','','[]','索索風葉響，寒生秋夜深。',48,'全唐诗/poet.song.160000.json','["索索風葉響，寒生秋夜深。", "閒思千古事，虛費一生心。", "命薄謀多拙，年衰病易侵。", "黄粱今夢覺，高枕卧山林。"]'),
('0b1b274c-04e0-4c1d-9a86-2c5fcf80f390','壬申十二月二十八夜雷','王炎','宋','宋诗','song-poetry','','[]','殘臘方淫雨，中宵忽怒雷。',48,'全唐诗/poet.song.160000.json','["殘臘方淫雨，中宵忽怒雷。", "更長頻展轉，夢斷但驚猜。", "凍雪何時解，春風幾日來。", "龍蛇今在蟄，墐戶不宜開。"]'),
('95cf2e7e-f0e5-4b07-b167-99d538d86ff7','初春苦寒久不到雙溪成長句書懷','王炎','宋','宋诗','song-poetry','','[]','老去頗多病，苦寒摧折之。',132,'全唐诗/poet.song.160000.json','["老去頗多病，苦寒摧折之。", "袍繭非不溫，不能護清羸。", "蒲團穩附火，蓄縮如凍龜。", "西山有桃李，借問惟枯枝。", "好花何時開，仲春以爲期。", "榮悴自相代，出處亦有宜。", "天寒但深藏，日暖當游嬉。", "强健不須喜，老死何必悲。", "曉日升扶桑，莫還入崦嵫。", "置之勿復道，理達心何疑。", "及時且行樂，花邊傾一巵。"]'),
('ce48d37d-97ca-4c11-bc51-f255eac45580','和將使早雪','王炎','宋','宋诗','song-poetry','','[]','曉日藏明恐雪羞，遠山含暝更雲浮。',32,'全唐诗/poet.song.160000.json','["曉日藏明恐雪羞，遠山含暝更雲浮。", "不須苦道豐年瑞，擁衲爐邊索酒舟。"]'),
('844a2d8d-ba64-492f-9da7-23815b44988d','又和早雪韻','王炎','宋','宋诗','song-poetry','','[]','夢覺流蘇寒栗冽，曉起方知天釀雪。',64,'全唐诗/poet.song.160000.json','["夢覺流蘇寒栗冽，曉起方知天釀雪。", "松公變色失蒼髯，竹士垂頭摧直節。", "倚樓四望無紅塵，疑是身居銀漢津。", "千林一色皆玉樹，不許梅花先得春。"]'),
('7951f924-bf17-4e52-8951-08925fa3bf5d','梅花  其一','王炎','宋','宋诗','song-poetry','','[]','園林都未覺春風，蓓蕾枝頭茁小紅。',32,'全唐诗/poet.song.160000.json','["園林都未覺春風，蓓蕾枝頭茁小紅。", "要識十分清絕處，暗香疎影月明中。"]'),
('14490d85-f203-4415-b54a-8ca4dc2a0e35','梅花  其二','王炎','宋','宋诗','song-poetry','','[]','欲向花邊把一杯，喜逢臘盡又春回。',32,'全唐诗/poet.song.160000.json','["欲向花邊把一杯，喜逢臘盡又春回。", "直饒百歲爲期限，能見梅花幾度開。"]'),
('703860db-c35b-4c16-bd27-7b940956b90b','咏便坐梅花','王炎','宋','宋诗','song-poetry','','[]','去年花下立，踟躕搔白首。',72,'全唐诗/poet.song.160000.json','["去年花下立，踟躕搔白首。", "今日花邊坐，病起更衰朽。", "老與病交侵，歡悰尚何有。", "人老不再少，花謝還復開。", "對花堪酌酒，畏病不舉杯。", "寂寞重寂寞，春風何事來。"]'),
('a523a9e5-0645-4246-a8d3-8b97fc4db596','病起','王炎','宋','宋诗','song-poetry','','[]','羸軀方伏枕，凍骨倍加綿。',216,'全唐诗/poet.song.160000.json','["羸軀方伏枕，凍骨倍加綿。", "自覺脾爲約，醫言脈太玄。", "不禁腰痛楚，仍苦膝拘攣。", "搔抑方能定，扶持僅可前。", "縕袍藏被底，熾炭倚爐邊。", "衰謝誠宜爾，風寒實使然。", "迍邅雖有數，調護不無愆。", "初日憂難療，兼旬幸稍痊。", "是身無實相，何術保餘年。", "不死方成佛，長生乃是仙。", "闔棺寧再起，拔宅謾虛傳。", "力豈能加命，人終不勝天。", "災生雖或免，算盡必難延。", "只合情無滯，毋爲疾所纏。", "窮通皆任運，逆順但隨緣。", "南畝無千斛，西山有數椽。", "饑當量腹食，困則曲肱眠。", "此樂人知少，浮休永息肩。"]'),
('cbf3c42e-5de2-4baf-a879-f79dfc6235e4','雙溪種花  其一','王炎','宋','宋诗','song-poetry','','[]','雙溪漸有雜花開，每日扶筇到一回。',32,'全唐诗/poet.song.161000.json','["雙溪漸有雜花開，每日扶筇到一回。", "勝似名園空鎖閉，主人至老不歸來。"]'),
('aa96fa80-4bd5-448f-a59f-5349f8854aee','雙溪種花  其二','王炎','宋','宋诗','song-poetry','','[]','蒼頭爲我斸西山，扶病移花强自寬。',32,'全唐诗/poet.song.161000.json','["蒼頭爲我斸西山，扶病移花强自寬。", "縱不爲花長作主，何妨留與後人看。"]'),
('1ae01097-029f-4675-a1b8-d49b6e1c28bb','春日有感','王炎','宋','宋诗','song-poetry','','[]','拍岸晴波蘸柳絲，一雙鸂鶒浴紅衣。',32,'全唐诗/poet.song.161000.json','["拍岸晴波蘸柳絲，一雙鸂鶒浴紅衣。", "可憐陌上花開盡，不見魚軒緩緩歸。"]'),
('046e426e-906a-43ad-8be6-d1ed9420ce97','題汪尉立之快閤  其一','王炎','宋','宋诗','song-poetry','','[]','市廛屬耳太喧囂，林藪藏身又寂寥。',32,'全唐诗/poet.song.161000.json','["市廛屬耳太喧囂，林藪藏身又寂寥。", "負郭面溪開小閤，箇中登覽獨逍遥。"]'),
('dfe60089-fd2a-4bb3-bcbc-893cc36b6564','題汪尉立之快閤  其二','王炎','宋','宋诗','song-poetry','','[]','傍簷古木綠陰陰，下有清溪可洗心。',32,'全唐诗/poet.song.161000.json','["傍簷古木綠陰陰，下有清溪可洗心。", "燕坐紅塵飛不到，何須風過一披襟。"]'),
('852dabae-d44d-48d9-8f2d-c5e5de87e35b','將使有詩欲移具相邀到雙溪因次韻','王炎','宋','宋诗','song-poetry','','[]','緬思花下飲，歲月易侵尋。',48,'全唐诗/poet.song.161000.json','["緬思花下飲，歲月易侵尋。", "人老今華髮，春深半綠陰。", "揮毫來妙語，移具有佳音。", "草木生光彩，青藜肯下臨。"]'),
('9753ef59-0c57-45b8-83fa-20f0cbb6761e','和何元清韻九絕  其一','王炎','宋','宋诗','song-poetry','','[]','春深遶屋綠陰稠，却掃無人識冗侯。',32,'全唐诗/poet.song.161000.json','["春深遶屋綠陰稠，却掃無人識冗侯。", "獨肯敂關相勞問，不妨挾冊共藏脩。"]'),
('60f3bf05-b84f-48d7-b87d-7dbc139f458b','和何元清韻九絕  其二','王炎','宋','宋诗','song-poetry','','[]','絲竹無緣在後堂，肉羞不辨出東房。',32,'全唐诗/poet.song.161000.json','["絲竹無緣在後堂，肉羞不辨出東房。", "金徽彈罷惟清坐，共挹熏爐一穗香。"]'),
('dd321489-d015-4258-9930-b7a7f3fa4cf2','和何元清韻九絕  其三','王炎','宋','宋诗','song-poetry','','[]','屋邊花萼自離披，屋底臞儒但著書。',32,'全唐诗/poet.song.161000.json','["屋邊花萼自離披，屋底臞儒但著書。", "游冶郎君應冷笑，不能暇逸獨何歟。"]'),
('92eb508b-4cfc-46c3-ab16-88e5394336a6','和何元清韻九絕  其四','王炎','宋','宋诗','song-poetry','','[]','老來視聽稍精明，休問如何太瘦生。',32,'全唐诗/poet.song.161000.json','["老來視聽稍精明，休問如何太瘦生。", "還信閒中安樂否，龜巢蓮葉喜身輕。"]'),
('ba9baba1-983a-407b-9ed2-1e9c5bc5a5be','和何元清韻九絕  其五','王炎','宋','宋诗','song-poetry','','[]','覓官安用羨登仙，求富何須願執鞭。',32,'全唐诗/poet.song.161000.json','["覓官安用羨登仙，求富何須願執鞭。", "洙泗從游多達者，簞瓢顔子獨稱賢。"]'),
('edaa1f94-4ee1-4399-8537-59a22d257277','和何元清韻九絕  其六','王炎','宋','宋诗','song-poetry','','[]','青眼雖慚阮嗣宗，爲君解榻席相重。',32,'全唐诗/poet.song.161000.json','["青眼雖慚阮嗣宗，爲君解榻席相重。", "菜羹蔬食能甘否，自昔人言儉易容。"]'),
('886a4309-84b5-4383-8f3e-d35fea27128b','和何元清韻九絕  其七','王炎','宋','宋诗','song-poetry','','[]','莫年築室北山邊，自笑渾無塞屋錢。',32,'全唐诗/poet.song.161000.json','["莫年築室北山邊，自笑渾無塞屋錢。", "巾褐翛然窮亦樂，豈曾有夢到金蓮。"]'),
('0c380514-84bf-4bd1-b4af-05750223cc6b','和何元清韻九絕  其八','王炎','宋','宋诗','song-poetry','','[]','一洗平生箏笛耳，極知綠綺有遺音。',32,'全唐诗/poet.song.161000.json','["一洗平生箏笛耳，極知綠綺有遺音。", "君臣慶會休三弄，泉石膏肓不可鍼。"]'),
('c223027d-e801-4dc9-ae4b-28c009698eb1','和何元清韻九絕  其九','王炎','宋','宋诗','song-poetry','','[]','焦桐爲我發哀彈，但覺清風遶指寒。',32,'全唐诗/poet.song.161000.json','["焦桐爲我發哀彈，但覺清風遶指寒。", "老大雖思聞古調，莫彈別鵠感離鸞。"]'),
('313e1e4d-3f56-4925-9bd9-548c10e8f02e','雙溪即事','王炎','宋','宋诗','song-poetry','','[]','竹底開幽徑，山根結小樓。',48,'全唐诗/poet.song.161000.json','["竹底開幽徑，山根結小樓。", "誰知多病苦，自判一生休。", "舟著平沙尾，橋橫古渡頭。", "往來皆物役，却掃獨無求。"]'),
('637503fa-56b8-400d-b68f-3ee1a9eef997','清老畫雙溪壁以詩謝之','王炎','宋','宋诗','song-poetry','','[]','老夫哦詩聳兩肩，落筆不停稱腹稿。',128,'全唐诗/poet.song.161000.json','["老夫哦詩聳兩肩，落筆不停稱腹稿。", "緣詩寫出無聲句，畫史追之誰得到。", "爲予壁上留真跡，水墨纖穠任揮掃。", "石根竹樹極蕭森，中著羽蟲疑叫噪。", "雖然畫意不畫形，形意兩全方筆老。", "熟視時時自首肯，從旁見者皆稱好。", "師言此亦吾餘事，佛祖玄關須探討。", "未宜直說色是空，不著色空斯見道。"]'),
('8360282e-9448-4981-9268-b8eac98161c0','用元韻答清老  其一','王炎','宋','宋诗','song-poetry','','[]','巧匠胸中有全室，能文紙上無脫稿。',128,'全唐诗/poet.song.161000.json','["巧匠胸中有全室，能文紙上無脫稿。", "老禪善畫亦如是，毛錐未出意先到。", "解衣盤薄小經營，驀然揮灑筆如掃。", "我思詩畫本一律，衆作徒多等蟬噪。", "畫手無如王右丞，一似詩中杜陵老。", "正緣此老襟韻高，工拙奇常無不好。", "斲輪妙處不可傳，此事難從筆端討。", "由來萬法生一心，貫徹精粗無二道。"]'),
('558d2be2-9052-4c81-abba-680408c51bd8','用元韻答清老  其二','王炎','宋','宋诗','song-poetry','','[]','篆車創始自稚輪，筦簟從初但蒲稿。',128,'全唐诗/poet.song.161000.json','["篆車創始自稚輪，筦簟從初但蒲稿。", "詩到晚唐非不佳，少似國風能理到。", "嗟予耄矣棄穎泓，卧病終年長却掃。", "客無脫屨一榻懸，人不到門羣雀噪。", "敢意支郎念岑寂，時將妙語起衰老。", "若人搜句乃餘事，雖不雕鎸自精好。", "況於佛祖可呵駡，豈無魔外宜攻討。", "早辦山居一把茅，爲我長歌歌證道。"]'),
('d7d17644-afc0-4edd-ab10-711e478dbcd6','用元韻答清老  其三','王炎','宋','宋诗','song-poetry','','[]','平生言語苦不工，甲乙未能成類稿。',128,'全唐诗/poet.song.161000.json','["平生言語苦不工，甲乙未能成類稿。", "曩時陶謝以詩鳴，竭力追隨終莫到。", "上人詞鋒極痛快，睥睨千人軍可掃。", "長須驚喜見此客，無怪繞枝鳱鵲噪。", "師言能詩且工畫，筆仗須先知嫩老。", "復言能畫亦飽參，亹亹玄談聽更好。", "吾聞法海深又深，性珠可得不可討。", "若除詩畫與談禪，未審云何真悟道。"]'),
('85aeab66-7183-4d0b-9d67-7d125212f291','舟行到𦭵莪和清老韻  其一','王炎','宋','宋诗','song-poetry','','[]','沙尾維舟傍水楊，主人延我坐中堂。',32,'全唐诗/poet.song.161000.json','["沙尾維舟傍水楊，主人延我坐中堂。", "山焦石裂方亭午，借得微風一霎涼。"]'),
('34c7d76f-80d7-4cbb-9373-2cce5796280d','舟行到𦭵莪和清老韻  其二','王炎','宋','宋诗','song-poetry','','[]','詩中巧手妙穿楊，便可階陞屈宋堂。',32,'全唐诗/poet.song.161000.json','["詩中巧手妙穿楊，便可階陞屈宋堂。", "句挾冰霜堪却暑，令人心地亦清涼。"]'),
('63e331f4-25b1-4895-80b1-9c1bacb379ff','和清老韻  其一','王炎','宋','宋诗','song-poetry','','[]','不作麒麟楦，方知外物輕。',48,'全唐诗/poet.song.161000.json','["不作麒麟楦，方知外物輕。", "杜門便野處，躡屐飽山行。", "未說窮通樂，宜無寵辱驚。", "頹齡寧有幾，聊爾憇勞生。"]'),
('6a096745-b165-44d8-99e6-4fc3e6ebc956','和清老韻  其二','王炎','宋','宋诗','song-poetry','','[]','蟬蛻塵埃外，翛然世累輕。',48,'全唐诗/poet.song.161000.json','["蟬蛻塵埃外，翛然世累輕。", "開堂聊演說，杖錫遂飛行。", "畫妙人難及，詩豪我亦驚。", "筆端游戲爾，法忍貴無生。"]'),
('06712696-1578-42b1-8d1b-89cb431766de','雙溪即事','王炎','宋','宋诗','song-poetry','','[]','築室依林麓，開門向水涯。',48,'全唐诗/poet.song.161000.json','["築室依林麓，開門向水涯。", "經過無俗駕，附近少人家。", "洄洑潭成沫，嵌空石有漥。", "幽居誰是伴，鳬雁聚平沙。"]'),
('d40f4938-a90d-4b12-b3b6-ab97783d6546','舟行過白石見將使夜宿毛家林翌日到𦭵莪却回和清老','王炎','宋','宋诗','song-poetry','','[]','蒼頭倦晨炊，卯飯幾及午。',240,'全唐诗/poet.song.161000.json','["蒼頭倦晨炊，卯飯幾及午。", "泝流赤日中，舟子亦良苦。", "魚躍戀芳餌，鷗飛避鳴櫓。", "仙翁所退藏，好境自呈露。", "溪水清可鑑，山雲橫不度。", "坐斷泉石幽，不受塵土污。", "問之何所得，妙處難悉數。", "初非練玉泉，亦不鳴天鼓。", "人癯道方肥，心遠貌亦古。", "老衲同我來，得句時一吐。", "物色盡詩材，筆底隨指呼。", "行行更前之，繫纜日未莫。", "轉柂涉奔湍，支筇入幽塢。", "倦甚宿茅茨，睡熟不能寤。", "遲明又蓐食，凌風上前浦。", "重露雨點疎，晴嵐雲氣布。", "蝗蝻尚飛揚，禾稼難愛護。", "村落有狗偷，耄倪且狼顧。", "念此一悄然，回舟雙港渡。", "空羨皎然師，詩成有神助。"]'),
('5710a165-ae11-427a-9c93-bdffcbc4019d','哭吳耀遠','王炎','宋','宋诗','song-poetry','','[]','孤陋無如我，交親頼有君。',48,'全唐诗/poet.song.161000.json','["孤陋無如我，交親頼有君。", "方圖來往數，豈意死生分。", "自卜牛眠地，今歸馬鬣墳。", "不能澆斗酒，忍遽述銘文。"]'),
('b1ba2af8-7ed2-4e9f-978f-66f1227e7035','俞義夫挽詩','王炎','宋','宋诗','song-poetry','','[]','恩愛周姻族，寬和善里閭。',48,'全唐诗/poet.song.161000.json','["恩愛周姻族，寬和善里閭。", "年高無悔吝，身沒有名譽。", "願見今何及，從游舊亦疎。", "若修耆舊傳，言行可追書。"]'),
('6109dbb9-ed53-481b-8299-00b51daef10c','拒霜花','王炎','宋','宋诗','song-poetry','','[]','池上木芙蓉，曉寒摧折之。',96,'全唐诗/poet.song.161000.json','["池上木芙蓉，曉寒摧折之。", "綠葉未盡彫，紅芳已先萎。", "空得拒霜名，憔悴不自持。", "人生亦如此，榮盛須及時。", "少壯不久留，老疾仍相隨。", "騰騰當任運，慘慘徒自悲。", "萬古同有盡，華顛無再緇。", "及今幸强健，不樂將何爲。"]'),
('4ace1e95-e58f-4201-ad93-69eefd929a82','冬至日雪','王炎','宋','宋诗','song-poetry','','[]','日脚初添一線長，飛花撩亂壓微陽。',32,'全唐诗/poet.song.161000.json','["日脚初添一線長，飛花撩亂壓微陽。", "朱門滿酌羊羔酒，誰念茅茨有絕糧。"]'),
('19846f71-a3e1-4773-aefc-c23558b39943','次日快晴','王炎','宋','宋诗','song-poetry','','[]','曈曈曉日射窗明，急雪漫空快得晴。',32,'全唐诗/poet.song.161000.json','["曈曈曉日射窗明，急雪漫空快得晴。", "田父飯牛應喜甚，東臯澤澤可深耕。"]'),
('3aca34e0-d8a6-4b8a-b7af-ea11079dc586','早梅','王炎','宋','宋诗','song-poetry','','[]','似無還有暗香來，知是春風到早梅。',32,'全唐诗/poet.song.161000.json','["似無還有暗香來，知是春風到早梅。", "一歲一番花似玉，老人見得幾番開。"]'),
('9be9b801-3a76-4e30-bb58-db68a81aef3a','脚婆','王炎','宋','宋诗','song-poetry','','[]','竹奴夏日涼，脚婆冬夜燠。',168,'全唐诗/poet.song.161000.json','["竹奴夏日涼，脚婆冬夜燠。", "二物不同時，皆堪伴幽獨。", "自吾失伉儷，一紀誰與宿。", "年高氣血衰，日短天地肅。", "魚眼夜不瞑，雞膚凍生粟。", "伏枕屢展轉，挾纊但拳曲。", "脚婆當此時，貴重如金玉。", "爨釜蟹眼生，汲之滿皤腹。", "暖氣所燻蒸，羸軀任伸縮。", "粉黛工取憐，自可薦衾褥。", "豈不辟沍寒，而能動情慾。", "不如此瓠壺，但可暖吾足。", "貌醜不嫵媚，坐穩無顛覆。", "妄想何從生，黎明睡猶熟。"]'),
('df684521-89bc-4702-8dd0-08ba64d9037b','李忠甫見惠長牋以詩謝之','王炎','宋','宋诗','song-poetry','','[]','寂寂羅雀門，日見交游疎。',96,'全唐诗/poet.song.161000.json','["寂寂羅雀門，日見交游疎。", "短李不我棄，一年憩琴書。", "青衿孺子輩，共喜得範模。", "黄鵠有遠志，樊籠不可拘。", "今將舍我去，雅意何勤渠。", "駢儷出妙語，簡潔無費辭。", "捲置懷袖間，報之欠瓊琚。", "惟期在明秋，刷羽摩天衢。"]'),
('3feb28bd-9ddd-40ad-9793-d9f812465bba','病中即事三首  其一','王炎','宋','宋诗','song-poetry','','[]','附火膚革燥，遠火寒慘慘。',60,'全唐诗/poet.song.161000.json','["附火膚革燥，遠火寒慘慘。", "坐卧置湯婆，稍覺兩足暖。", "抓搔不停手，苛痒殊未減。", "飲食固多忌，所幸能强飯。", "客至不出迎，予非敢疎懶。"]'),
('864b569c-1942-4cb1-9f8c-5af33728d207','病中即事三首  其二','王炎','宋','宋诗','song-poetry','','[]','塊坐小窗下，簷牙烏鵲語。',48,'全唐诗/poet.song.161000.json','["塊坐小窗下，簷牙烏鵲語。", "飛飛去復來，遶樹鳴不已。", "料汝必不誤，顧我亦何喜。", "恐有行人來，未知誰氏子。"]'),
('9411b98d-9d25-4512-87e4-59744c2330df','病中即事三首  其三','王炎','宋','宋诗','song-poetry','','[]','浹旬不見日，凍雲塞天宇。',60,'全唐诗/poet.song.161000.json','["浹旬不見日，凍雲塞天宇。", "兒童相與言，雪意恐未已。", "一月見三白，爲瑞亦足矣。", "老夫固畏寒，貧者憂凍死。", "六出亂飛花，不如晴可喜。"]'),
('384e4bad-bea4-454b-a53e-3f73ba7eccb7','子用惠魚四軸以詩謝之  其一','王炎','宋','宋诗','song-poetry','','[]','四幅溪藤任卷舒，管城幻出化龍魚。',32,'全唐诗/poet.song.161000.json','["四幅溪藤任卷舒，管城幻出化龍魚。", "風雷定似梭飛走，莫誤呼兒覓素書。"]'),
('d313b4f9-1ac6-4813-9eef-1454885cc0ab','子用惠魚四軸以詩謝之  其二','王炎','宋','宋诗','song-poetry','','[]','掉尾揚鬐氣象閒，或潛或躍出毫端。',32,'全唐诗/poet.song.161000.json','["掉尾揚鬐氣象閒，或潛或躍出毫端。", "非魚知得魚如許，豈在濠梁子細觀。"]'),
('cf215b84-32e0-4ac5-b254-6aad0ef7f878','石倅宗卿挽詩  其一','王炎','宋','宋诗','song-poetry','','[]','潔白心如玉，寬和氣似春。',48,'全唐诗/poet.song.161000.json','["潔白心如玉，寬和氣似春。", "索居當晚歲，取友得斯人。", "婺女書難再，泉南迹已陳。", "天高不可問，反袂獨傷神。"]'),
('7c6041c5-80fa-4167-ad4e-2627bacac063','石倅宗卿挽詩  其二','王炎','宋','宋诗','song-poetry','','[]','能吏今非少，純儒古亦稀。',48,'全唐诗/poet.song.161000.json','["能吏今非少，純儒古亦稀。", "斯人胡不壽，吾道豈其非。", "才自堪時用，心難與義違。", "九原無起日，誰復可同歸。"]'),
('2d2da5b6-46e6-400b-864b-d4905418ebb2','病中書懷','王炎','宋','宋诗','song-poetry','','[]','鶴骨雞膚不耐寒，那堪癬疥更斑斕。',64,'全唐诗/poet.song.161000.json','["鶴骨雞膚不耐寒，那堪癬疥更斑斕。", "開年慘淡陰兼雨，終日抓搔寢不安。", "未可給扶親几杖，豈能見客攝衣冠。", "人言剝復相更代，頻把韋編反對觀。"]'),
('9a9ab118-d619-428d-bc21-f85f7949eda6','追念將使叔','王炎','宋','宋诗','song-poetry','','[]','青山橫白雲，野色極瀟灑。',120,'全唐诗/poet.song.161000.json','["青山橫白雲，野色極瀟灑。", "見者必屬目，寶相在其下。", "此翁强健時，門外無車馬。", "夫豈固絕交，欲與無可者。", "獨我時扣關，辭色頗相假。", "玄禪到佛祖，妙句近風雅。", "萬事已陳迹，哀思淚盈把。", "即之不復見，去之不忍捨。", "優婆塞何爲，酌水日奠斝。", "三徑草易荒，悲風遶松檟。"]'),
('c8809fcf-33a5-4012-a5f5-6db98c720acd','和汪誠之韻','王炎','宋','宋诗','song-poetry','','[]','昏昏未必晦，昭昭未必明。',204,'全唐诗/poet.song.161000.json','["昏昏未必晦，昭昭未必明。", "渾渾未必濁，漻漻未必清。", "吾道本自貴，國爵亦可并。", "所以魯素王，但欲比老彭。", "嗟予久斂退，用志難崢嶸。", "吾友暫蟠蟄，側耳春雷轟。", "韞櫝足豈刖，扛鼎肩不頳。", "鼓行當擅場，敵者誰爲勍。", "佇看慶多馬，爲彼酌兕觥。", "下視俗子陋，未識仁者榮。", "譬如黄流污，寧涴皎月晶。", "相期在遠到，所急非小成。", "頗恨會遇疎，未免鄙吝生。", "大篇何舂容，雅思真和平。", "知君培其根，許我擷其菁。", "虛靜能養心，篤實可存誠。", "此理君得之，底裏期再傾。"]'),
('990254c1-d5cd-4168-90b7-04668d2b2ab9','丙子重陽日有感','王炎','宋','宋诗','song-poetry','','[]','南山木葉赤，北山木葉黄。',216,'全唐诗/poet.song.161000.json','["南山木葉赤，北山木葉黄。", "秋色日夜變，白露將爲霜。", "玄鳥去已久，候雁方南翔。", "携壺登高侶，滿手萸菊香。", "佳節不可負，而我病在床。", "人老自多病，何爲苦悲傷。", "去年重陽日，貴孫在我旁。", "知我愛敬客，拱立傳壺觴。", "十五未冠巾，總角頎而長。", "望其有成立，門戶生輝光。", "前樓千卷書，可以識義方。", "南畝千斛穀，可以充積倉。", "一旦捨我去，冰炭交中腸。", "萬物皆有盡，死生理之常。", "修短百年間，何必論彭殤。", "豈不自開釋，念之終難忘。", "長歌意無盡，歌罷還凄凉。", "悲風扣林木，爲我號清商。"]'),
('da02f9d9-6748-4023-b511-fd81ed0fcf9a','九月二十九日到思溪莊避人事十月初四日過生朝方歸初三日早恕子遣人來送酒食并詞二闋因成唐律二首  其一','王炎','宋','宋诗','song-poetry','','[]','僻遠無來客，尪羸厭久生。',48,'全唐诗/poet.song.161000.json','["僻遠無來客，尪羸厭久生。", "擁爐便獨坐，扶杖懶徐行。", "中歲失怙恃，晚年無弟兄。", "絕知來日短，萬事可忘情。"]'),
('b724a95c-02e1-48e4-af1a-eec887e7a2f0','九月二十九日到思溪莊避人事十月初四日過生朝方歸初三日早恕子遣人來送酒食并詞二闋因成唐律二首  其二','王炎','宋','宋诗','song-poetry','','[]','人事有酬酢，山居方寂寥。',48,'全唐诗/poet.song.161000.json','["人事有酬酢，山居方寂寥。", "三時纏宿疾，十月見生朝。", "瘦骨添綿護，枯腸怯酒澆。", "爲予歌一曲，亦足慰無聊。"]'),
('18ce09f6-9ed2-49eb-9e28-d066861d326d','與滕元英','王炎','宋','宋诗','song-poetry','','[]','君尚精神健，吾真氣血衰。',48,'全唐诗/poet.song.161000.json','["君尚精神健，吾真氣血衰。", "肯來同晤語，別去即懷思。", "不厭經過數，惟憂後會遲。", "春暄宜緩步，何必以秋期。"]'),
('df2d1396-9e92-4aec-b495-b43feb684294','贈平首座','王炎','宋','宋诗','song-poetry','','[]','家在青山下，投閒歲月多。',48,'全唐诗/poet.song.161000.json','["家在青山下，投閒歲月多。", "杜門長却掃，杖錫獨經過。", "學佛非無法，哦詩恐是魔。", "願言行古路，莫遣覆藤蘿。"]'),
('0a7c41d1-4ef8-4ecc-9d54-c3915a4c42f9','再贈平首座','王炎','宋','宋诗','song-poetry','','[]','南澗誰人掃劫灰，行纏恰自冷泉回。',64,'全唐诗/poet.song.161000.json','["南澗誰人掃劫灰，行纏恰自冷泉回。", "式公昔日曾留誓，大用今生乃再來。", "應是伽藍當更造，豈關回祿故爲災。", "上頭更有華嚴界，彈指重重殿閤開。"]'),
('3e62a61a-a3c8-4c58-94fe-917fd6ca0efe','杜工部有同谷七歌其辭高古難及而音節悲壯可擬也用其體作七歌觀者不取其辭取其意可也  其一','王炎','宋','宋诗','song-poetry','','[]','有客有客字晦叔，東臯歲收可饘粥。',65,'全唐诗/poet.song.161000.json','["有客有客字晦叔，東臯歲收可饘粥。", "何爲得飽尚多憂，豈是老窮無止足。", "十日之中九日病，以杖扶行懼顛覆。", "嗚呼一歌兮歌意長，風林助我鳴悲商。"]'),
('367a646e-e532-488e-8add-efea75ab2d3b','杜工部有同谷七歌其辭高古難及而音節悲壯可擬也用其體作七歌觀者不取其辭取其意可也  其二','王炎','宋','宋诗','song-poetry','','[]','有母有母年七十，一室枵然徒壁立。',65,'全唐诗/poet.song.161000.json','["有母有母年七十，一室枵然徒壁立。", "茹蔬啜粥不怨尤，卧病在床無藥物。", "我爲舉子得一官，南陔之養嗟何及。", "嗚呼二歌兮歌轉悲，羞見慈烏隨母飛。"]'),
('9967b665-bba7-4b44-bf16-d021f7e4b83a','杜工部有同谷七歌其辭高古難及而音節悲壯可擬也用其體作七歌觀者不取其辭取其意可也  其三','王炎','宋','宋诗','song-poetry','','[]','有弟有弟手足親，與我鼎立成三人。',65,'全唐诗/poet.song.161000.json','["有弟有弟手足親，與我鼎立成三人。", "叔氏鰥居苦多病，季子宦遊依舊貧。", "吾兄既終弟亦逝，歲晚惸惸惟一身。", "嗚呼三歌兮歌意放，歌罷無言坐惆悵。"]'),
('ae91e314-9504-4b56-9e52-53e8e7e2761e','杜工部有同谷七歌其辭高古難及而音節悲壯可擬也用其體作七歌觀者不取其辭取其意可也  其四','王炎','宋','宋诗','song-poetry','','[]','有妹有妹家苦貧，補紉組織多辛勤。',65,'全唐诗/poet.song.161000.json','["有妹有妹家苦貧，補紉組織多辛勤。", "二男三女未婚嫁，已見宿草生孤墳。", "問疾弔喪俱不及，念此不置長酸辛。", "嗚呼四歌兮歌更苦，往事關心誰可語。"]'),
('0a532067-b5e1-47fc-a3a9-989daecbb6c6','杜工部有同谷七歌其辭高古難及而音節悲壯可擬也用其體作七歌觀者不取其辭取其意可也  其五','王炎','宋','宋诗','song-poetry','','[]','有子有子共七人，六子短命一子存。',65,'全唐诗/poet.song.161000.json','["有子有子共七人，六子短命一子存。", "後固無窮前萬古，浮生脩短何足論。", "天屬情鍾在我輩，歲月雖久哀如新。", "嗚呼五歌兮三嘆息，理不勝情難自釋。"]'),
('e53a4496-5431-4043-952b-7b4de630f2db','杜工部有同谷七歌其辭高古難及而音節悲壯可擬也用其體作七歌觀者不取其辭取其意可也  其六','王炎','宋','宋诗','song-poetry','','[]','有孫有孫未冠巾，頎頎狀貌如成人。',65,'全唐诗/poet.song.161000.json','["有孫有孫未冠巾，頎頎狀貌如成人。", "謂其長大習詩禮，他年可望高吾門。", "豈期一旦舍我去，白首老翁徒痛心。", "嗚呼六歌兮音調急，獨坐吞聲襟袖濕。"]'),
('a362c2be-a3df-4607-95cd-b90aecb08536','杜工部有同谷七歌其辭高古難及而音節悲壯可擬也用其體作七歌觀者不取其辭取其意可也  其七','王炎','宋','宋诗','song-poetry','','[]','有婦有婦嬪吾孫，僅能朞月問晨昏。',65,'全唐诗/poet.song.161000.json','["有婦有婦嬪吾孫，僅能朞月問晨昏。", "吉凶自古不可定，所以賀弔更在門。", "人言貧家女難嫁，豈料既嫁俄不存。", "嗚呼七歌兮意不盡，頻年多難天難問。"]'),
('f1a17508-9ebd-4519-8632-6f93b4320dd7','七夕一絕句','王炎','宋','宋诗','song-poetry','','[]','輕雲捲箔月鈎垂，正是青樓乞巧時。',32,'全唐诗/poet.song.161000.json','["輕雲捲箔月鈎垂，正是青樓乞巧時。", "牛女相望隔河漢，浪傳天上有佳期。"]'),
('af1ca611-c1c4-483b-9f19-d35dd245a313','贈劉術士','王炎','宋','宋诗','song-poetry','','[]','聞子能知算，逢予屢索詩。',48,'全唐诗/poet.song.161000.json','["聞子能知算，逢予屢索詩。", "諸公多妙語，老我更何辭。", "久客丹心苦，脩途繭足疲。", "秋深風露冷，歸去莫遲疑。"]'),
('08b73fdf-bd35-49b7-8c05-915c13136aff','與趙道人','王炎','宋','宋诗','song-poetry','','[]','欲上青雲却垂翅，歸來掃軌空山裏。',96,'全唐诗/poet.song.161000.json','["欲上青雲却垂翅，歸來掃軌空山裏。", "道人說相來敂關，酒半醺酣談亹亹。", "我今布褐終餘年，豈論燕頷并鳶肩。", "謂予形是朱頂鶴，兩眼藏神高頰顴。", "彭殤壽夭誰無死，不將動目摇湛水。", "道人去後若復來，定應難相壺邱子。"]'),
('3b63629c-f91c-4704-a9b5-f35419bab603','嘉定丁丑十二月謀葬貴孫老病不能與事但此心傷痛因成小詩以寫其哀','王炎','宋','宋诗','song-poetry','','[]','念汝方青鬢，嗟予久白鬚。',48,'全唐诗/poet.song.161000.json','["念汝方青鬢，嗟予久白鬚。", "在亡終不免，壽夭太相殊。", "有恨心如割，無言淚隕珠。", "何堪植馬鬣，玉樹閟黄壚。"]'),
('0288ac04-0cbe-49e9-a23c-ba898acc544e','與三山相士林子和三絕  其一','王炎','宋','宋诗','song-poetry','','[]','年登八十更何爲，手足支離視聽衰。',32,'全唐诗/poet.song.161000.json','["年登八十更何爲，手足支離視聽衰。", "自笑已如雞失旦，不須苦說鶴知時。"]'),
('3c547fb8-1c60-4ee0-b487-8adc2751f7a1','與三山相士林子和三絕  其二','王炎','宋','宋诗','song-poetry','','[]','鳶肩燕頷刺天飛，自顧而今已後時。',32,'全唐诗/poet.song.161000.json','["鳶肩燕頷刺天飛，自顧而今已後時。", "巾褐蕭然成野老，有何情緒更哦詩。"]'),
('bd7f809b-825e-4e59-8e13-ae314a7bd5be','與三山相士林子和三絕  其三','王炎','宋','宋诗','song-poetry','','[]','魚蝦瑣細不堪求，水澀溪寒欲斷流。',32,'全唐诗/poet.song.161000.json','["魚蝦瑣細不堪求，水澀溪寒欲斷流。", "若敂侯門逢短李，釣鰲便可月爲鈎。"]'),
('5b2c8267-9507-4892-af8b-85ca999cac49','送徐尉移簿巴陵并簡鄧器先汪兼善','王炎','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','兩鳬不到蓬萊峰，翩翩墮在葭葦叢。',272,'全唐诗/poet.song.161000.json','["兩鳬不到蓬萊峰，翩翩墮在葭葦叢。", "口談世事懶揖客，劫回老眼瞻飛鴻。", "子真何事亦來此，培塿乃生千丈松。", "揮毫古錦貯白雪，緩頰玉麈生清風。", "相知苦恨相見晚，坐席未暖行匆匆。", "離騷滿目江路冷，秋氣欲赤江頭楓。", "少留一日對歡伯，蒼顔共變桃皮紅。", "醉中出語最真實，爲君款曲論心胸。", "我嘗縱觀洞庭水，水天一色光濛濛。", "仙人帝子不可見，日月出沒滄波中。", "歸來荒縣窘朱墨，身如澤雉拘樊籠。", "君才凜凜萬夫敵，天驥一出凡馬空。", "不應拄笏棲枳棘，便合入幕依芙蓉。", "諸公得士喜推轂，從此奏賦明光宮。", "令君錦衣織青鳳，先生玉氣貫白虹。", "相逢問我令何如，爲言黑頭茁霜蓬。", "青雲事業付公等，歸去願學柴桑翁。"]'),
('b243b87b-e80f-4ddd-9cd3-db03080f1b9b','用元韻答徐尉','王炎','宋','宋诗','song-poetry','','[]','吟詩不聳肩兩峰，陸沉雁鶩文書叢。',272,'全唐诗/poet.song.161000.json','["吟詩不聳肩兩峰，陸沉雁鶩文書叢。", "銀鈎入眼光照牖，飛來白雪隨雲鴻。", "平生取友半天下，短蓬邂逅依長松。", "尉仙鯨海駕高浪，郡博鳳律鏘和風。", "詩翁巧手刻青玉，笑人擊鉢徒匆匆。", "懷歸我正念籬菊，招魂誰爲吟江楓。", "鼎來徐穉筆如掃，瞬息奇怪浮青紅。", "傾倒五色崑崙渠，洗滌萬斛塵埃胸。", "翩然舍去友三士，碧雲莫合天冥濛。", "世間英傑不易得，一朝聚會江城中。", "才華俱合上金馬，骨相元自居紗籠。", "縣齋冰合只懸榻，舉手咄咄時書空。", "把盃相屬儻相憶，更寄出水新芙蓉。", "天球固是清廟器，牛鐸或中黄鍾宮。", "當憐窘步困老驥，莫誚豪氣無雄虹。", "秋月照人光耿耿，秋風脫木聲蓬蓬。", "流年腕脫不須恨，外物乘除觀塞翁。"]'),
('3234dfea-7905-4581-aa70-3beb44975f23','次韻朱晦翁十梅 江梅','王炎','宋','宋诗','song-poetry','','[]','玉色不受垢，照影清江濱。',24,'全唐诗/poet.song.161000.json','["玉色不受垢，照影清江濱。", "江雪豈不寒，枝頭渾似春。"]'),
('16a8bcc7-b9d1-4c02-b82c-b9a572a534b1','次韻朱晦翁十梅 嶺梅','王炎','宋','宋诗','song-poetry','','[]','北枝未春風，南枝先暖雪。',24,'全唐诗/poet.song.161000.json','["北枝未春風，南枝先暖雪。", "吹香祇自憐，驛使音塵絕。"]'),
('f8104b47-7a80-4ffc-8013-2a92e7271c17','次韻朱晦翁十梅 野梅','王炎','宋','宋诗','song-poetry','','[]','迥野殊寂寥，孤芳太清絕。',24,'全唐诗/poet.song.161000.json','["迥野殊寂寥，孤芳太清絕。", "暗香疑有無，似亦畏攀折。"]'),
('4f52d8fb-ee0d-4d58-bc71-d0e8362dd0b4','次韻朱晦翁十梅 早梅','王炎','宋','宋诗','song-poetry','','[]','皎皎姑射仙，縞衣而黄裏。',24,'全唐诗/poet.song.161000.json','["皎皎姑射仙，縞衣而黄裏。", "一別如許時，見之先失喜。"]'),
('4f61a284-ff1b-435a-8974-9adde10d003e','次韻朱晦翁十梅 寒梅','王炎','宋','宋诗','song-poetry','','[]','花開有底急，迫此歲律殘。',24,'全唐诗/poet.song.161000.json','["花開有底急，迫此歲律殘。", "捷報春信來，不知冰雪寒。"]'),
('c1617a5b-ce24-4ad0-82f9-cd05d572f06b','次韻朱晦翁十梅 小梅','王炎','宋','宋诗','song-poetry','','[]','點綴鶴膝枝，無謂花萼小。',24,'全唐诗/poet.song.161000.json','["點綴鶴膝枝，無謂花萼小。", "亦有鼎實存，相期春事了。"]'),
('4e6fa9d3-a2b0-4de4-8334-541eaf06f612','次韻朱晦翁十梅 疏梅','王炎','宋','宋诗','song-poetry','','[]','詩人自情親，俗子極交淺。',24,'全唐诗/poet.song.161000.json','["詩人自情親，俗子極交淺。", "所以疏著花，即之風韻遠。"]'),
('a7807cfc-e271-4b1e-bd54-6a975b396f03','次韻朱晦翁十梅 枯梅','王炎','宋','宋诗','song-poetry','','[]','虬根蝕土石，老幹飽霜雪。',24,'全唐诗/poet.song.161000.json','["虬根蝕土石，老幹飽霜雪。", "孫枝吐春妍，靳惜那忍折。"]'),
('61881ea6-4c3a-48c0-bb4f-2d0a56eea8ed','次韻朱晦翁十梅 落梅','王炎','宋','宋诗','song-poetry','','[]','幽人自愛花，花落恨岑寂。',24,'全唐诗/poet.song.161000.json','["幽人自愛花，花落恨岑寂。", "豈悟化工意，褪花方著實。"]'),
('5a06b0c0-313b-4702-8293-34aac853cb3b','次韻朱晦翁十梅 賦梅','王炎','宋','宋诗','song-poetry','','[]','豈無和靖詩，亦有廣平賦。',24,'全唐诗/poet.song.161000.json','["豈無和靖詩，亦有廣平賦。", "多爲花寫真，終難盡佳處。"]'),
('57b05592-93cf-40c3-8043-b709add678f3','題彭城館畫屏','王炎','宋','宋诗','song-poetry','','[]','玉質青青竹弟，冰姿皎皎梅兄。',28,'全唐诗/poet.song.161000.json','["玉質青青竹弟，冰姿皎皎梅兄。", "上有大夫長鬣，歲寒誰更同盟。"]'),
('7bb0a7a0-e39a-4f06-99fa-9c2ced938f61','過涪翁墓二首  其一','王炎','宋','宋诗','song-poetry','','[]','千古詩中老斫輪，久埋玉樹去修文。',32,'全唐诗/poet.song.161000.json','["千古詩中老斫輪，久埋玉樹去修文。", "野人指點青山下，此是黄家魯直墳。"]'),
('3feab231-2b98-4b34-a276-a0ece1bd5ce4','過涪翁墓二首  其二','王炎','宋','宋诗','song-poetry','','[]','水行雙井陸沉沉，洗我胸中三斗塵。',32,'全唐诗/poet.song.161000.json','["水行雙井陸沉沉，洗我胸中三斗塵。", "人物只今雖寂寞，溪山依舊自清新。"]'),
('97440fdd-9834-4f0b-bd09-cf5427cfd350','送術士胡果','王炎','宋','宋诗','song-poetry','','[]','羊腸世路隻輪車，未老先衰半白鬚。',32,'全唐诗/poet.song.161000.json','["羊腸世路隻輪車，未老先衰半白鬚。", "欲買青山早歸去，煩君算我有錢無。"]'),
('86f5f221-1519-4d69-bbdd-9867b865616e','題謝艮齋桂山','王炎','宋','宋诗','song-poetry','','[]','懶曳星辰履，歸休背郭堂。',48,'全唐诗/poet.song.161000.json','["懶曳星辰履，歸休背郭堂。", "詩成時走筆，客至即行觴。", "百本山椒樹，三秋月窟秋。", "即之清可掬，人亦似幽芳。"]'),
('03e56295-6ce1-4afe-ae26-67696b0d8661','解官到郡諸丈置酒岳陽樓招炎爲客鄧巴陵索詩','王炎','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','重上危樓覽洞庭，故人一笑對飛觥。',64,'全唐诗/poet.song.161000.json','["重上危樓覽洞庭，故人一笑對飛觥。", "君山只似艑山綠，江水不如湘水清。", "一日勝遊成樂事，三年俗狀奪詩情。", "天涯邂逅還離別，莫惜樽前底裏傾。"]'),
('5754b429-6e20-4aae-bb84-e7b050af4e2e','浮碧亭','王炎','宋','宋诗','song-poetry','','[]','鳬舄飛來空翠間，萬家聯絡擁風煙。',64,'全唐诗/poet.song.161000.json','["鳬舄飛來空翠間，萬家聯絡擁風煙。", "箇中杖屨宜頻到，此外樓臺總浪傳。", "山似蓬萊差可近，水疑渤澥欲無邊。", "湘妃度曲馮夷舞，招我騎鯨意亦仙。"]'),
('385b363e-ff45-4f18-91b2-c9b36d09765b','贈地理游曉山','王炎','宋','宋诗','song-poetry','','[]','仙人白鶴渺煙霞，野日昏昏噪暮鴉。',64,'全唐诗/poet.song.161000.json','["仙人白鶴渺煙霞，野日昏昏噪暮鴉。", "城外土饅同此味，牆頭濁酒且須賒。", "堪輿信有玄通理，造物能私富貴家。", "宜爾何公微意在，石盤流水映桃花。"]'),
('1313aa69-9d15-40dd-a6d8-cd39abd984e7','寄德瑩弟二首  其一','王炎','宋','宋诗','song-poetry','','[]','牢落羈旅隔楚東，青山夢入往來中。',64,'全唐诗/poet.song.161000.json','["牢落羈旅隔楚東，青山夢入往來中。", "離心落雁驚秋雨，醉眼開花昨夜風。", "一壑若爲甘小隠，三江何日掛歸篷。", "謀生向坐文窮計，識破誵訛慮已空。"]'),
('654516cc-6362-4ab9-942f-9e0ceb885447','寄德瑩弟二首  其二','王炎','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭秋水望中天，側目飛鴻斷復連。',64,'全唐诗/poet.song.161000.json','["洞庭秋水望中天，側目飛鴻斷復連。", "得句信知神入夢，澆愁不慣酒中仙。", "秋風白髮欺來日，夜雨青燈憶往年。", "用拙不妨消息好，關山明月兩茫然。"]'),
('89273946-9309-40f7-b99e-e5c4112dae8c','秋日山所見野花','王炎','宋','宋诗','song-poetry','','[]','風流渾似內家粧，也想春風不分香。',32,'全唐诗/poet.song.161000.json','["風流渾似內家粧，也想春風不分香。", "從得傾城與傾國，牡丹人道是花王。"]'),
('3dd12f09-e321-41c0-a8b4-a6441bac2b01','臨湘縣崇惠廟詞','王炎','宋','宋诗','song-poetry','','[]','仙伯兮逍遥，共騎鶴兮雲霄。',151,'全唐诗/poet.song.161000.json','["仙伯兮逍遥，共騎鶴兮雲霄。", "西弱水兮東瀛洲，超然變化兮不可以留。", "農之田兮瘠田，仙弭節兮憫此民而勿去。", "白雲橫兮翠微，石室幽幽兮宜而燕娛。", "一竇之泉兮不溢不枯，仙顧而樂兮黄鵠翩其來歸。", "有龍蟄兮於寒泉，潜而飛兮遥天。", "仙吹簫兮擊鼓，老農酌醑兮互起舞。", "仙馭飛龍兮四郊甘雨，旱不爲災兮年穀屢豐，我民敬恭兮蒙仙之澤無窮。"]'),
